#translator_gui.py
if __name__ == '__main__':
    import multiprocessing
    import sys as _early_sys

    try:
        multiprocessing.freeze_support()
    except OSError:
        # [WinError 87] "The parameter is incorrect" — happens when a
        # multiprocessing child process tries to connect to a parent pipe
        # that is already closed (parent exited, path has special chars,
        # or antivirus interfered with the spawn).  The child has no parent
        # to talk to, so exit silently instead of showing an error dialog.
        _early_sys.exit(0)

    # PyInstaller-safe AuthND token helper entrypoint.  authnd_auth.py cannot
    # run itself via ``sys.executable script.py`` once bundled because
    # sys.executable is the Glossarion app exe.  Handle this tiny helper command
    # before importing the full GUI so the child process returns JSON and exits.
    import sys as _authnd_sys
    if "--authnd-mint-token" in _authnd_sys.argv:
        _idx = _authnd_sys.argv.index("--authnd-mint-token")
        _page_url = _authnd_sys.argv[_idx + 1] if len(_authnd_sys.argv) > _idx + 1 else ""
        _remaining = _authnd_sys.argv[_idx + 2:]
        _authnd_sys.argv = [_authnd_sys.argv[0], "--mint-token", _page_url, *_remaining]
        try:
            from authnd_auth import _main as _authnd_main
            raise SystemExit(_authnd_main())
        except ImportError:
            print('{"token":"","error":"AuthND is not available in this build."}', flush=True)
            raise SystemExit(1)
        except Exception as _authnd_exc:
            import json as _authnd_json
            print(_authnd_json.dumps({
                "token": "",
                "error": f"AuthND is not available in this build: {_authnd_exc}",
            }, separators=(",", ":")), flush=True)
            raise SystemExit(1)

    # PyInstaller-safe Gemini Free helper entrypoint.  gemini_free.py is normally
    # run as a subprocess so Qt WebEngine stays out of translation worker threads.
    if "--gemini-free-search" in _authnd_sys.argv:
        _idx = _authnd_sys.argv.index("--gemini-free-search")
        _remaining = _authnd_sys.argv[_idx + 1:]
        _authnd_sys.argv = [_authnd_sys.argv[0], "--search-helper", *_remaining]
        try:
            from gemini_free import _main as _gemini_free_main
            raise SystemExit(_gemini_free_main())
        except ImportError:
            print('{"content":"","finish_reason":"error","error":"Gemini Free is not available in this build."}', flush=True)
            raise SystemExit(1)
        except Exception as _gemini_free_exc:
            import json as _gemini_free_json
            print(_gemini_free_json.dumps({
                "content": "",
                "finish_reason": "error",
                "error": f"Gemini Free is not available in this build: {_gemini_free_exc}",
            }, separators=(",", ":")), flush=True)
            raise SystemExit(1)

