    _STREAM_END_LOG_PHRASES = (
        'stream finished',
        'stream complete',
        'sdk call finished',
        'received translation from api',
        'received chapter ',
        'received section ',
        'received merged response',
    )
    _HIDDEN_STREAM_START_LOG_PHRASES = (
        '] streaming on (env=',
        '] stream start (model=',
        '] sse stream start (model=',
        '] sdk stream start (model=',
        '] sdk stream opened in ',
    )
    _DIRECT_RESPONSE_PAYLOAD_PREFIX = '[DIRECT_TEXT_RESPONSE_PAYLOAD] '
    # QTextDocument comments/empty anchors are not searchable, so the active
    # streaming section uses tiny sentinel text.  Stream repaints replace only
    # the text between these sentinels instead of rebuilding every saved chat
    # message on the GUI thread.
    _ACTIVE_STREAM_START_MARKER = "DIRECT_TEXT_ACTIVE_STREAM_START_7F31"
    _ACTIVE_STREAM_END_MARKER = "DIRECT_TEXT_ACTIVE_STREAM_END_7F31"
    def __init__(self, translator):
        super().__init__(translator)
        from collections import deque
        from PySide6.QtWidgets import (
            QPlainTextEdit,
            QTextBrowser,
            QListWidget,
            QRadioButton,
            QButtonGroup,
        )

        self.translator = translator
        self._log_queue = deque()
        self._active = False
        self._in_thinking = False
        self._thinking_token_count = 0
        self._generation_token_count = 0
        self._processing_token_count = 0
        self._token_encoder = None
        self._token_encoder_initialized = False
        self._streaming_text = False
        self._streamed_content = ""
        self._temp_root = ""
        self._temp_input = ""
        self._expected_output = ""
        self._saved_selected_files = []
        self._saved_force_stream_all = False
        self._saved_env = {}
        self._saved_full_env = {}
        self._saved_gui_attrs = {}
        self._saved_browse_enabled = True
        self._listener_attached = False
        self._context_saved = False
        self._last_output_folder = ""
        self._preserve_temp_root = False
        self._direct_graceful_stop_pending = False
        self._direct_graceful_stop_ts = 0.0
        self._chat_history_path = self._resolve_chat_history_path()
        self._chat_sessions, current_chat_id = self._load_chat_history()
        self._chat_session_counter = max(
            (int(session.get("id", 0)) for session in self._chat_sessions),
            default=0,
        )
        if not self._chat_sessions:
            self._chat_session_counter = 1
            self._chat_sessions = [self._new_chat_session(self._chat_session_counter)]
        self._current_chat_index = next(
            (
                index
                for index, session in enumerate(self._chat_sessions)
                if session.get("id") == current_chat_id
            ),
            0,
        )
        self._switching_chat = False
        self._chat_messages = self._chat_sessions[self._current_chat_index]["messages"]
        self._chat_history_save_timer = QTimer(self)
        self._chat_history_save_timer.setSingleShot(True)
        self._chat_history_save_timer.setInterval(450)
        self._chat_history_save_timer.timeout.connect(self._save_chat_history)
        self._inline_response_resize_timer = QTimer(self)
        self._inline_response_resize_timer.setSingleShot(True)
        self._inline_response_resize_timer.setInterval(140)
        self._inline_response_resize_timer.timeout.connect(
            self._resize_inline_response_editor_to_content
        )
        self._chat_sidebar_hidden = False
        self._assistant_message_active = False
        self._pending_glossary_approval = None
        self._active_request_segments = []
        self._request_segment_by_thread = {}
        self._stream_phase_by_thread = {}
        self._listener_stream_phase_by_thread = {}
        self._pending_attachment = None
        try:
            parent_output_mode = translator._get_output_mode()
        except Exception:
            parent_output_mode = translator.config.get('output_mode', 'text')
        configured_direct_mode = str(
            translator.config.get('direct_text_output_mode', parent_output_mode)
            or parent_output_mode
            or 'text'
        ).strip().lower()
        if configured_direct_mode == 'refine':
            configured_direct_mode = 'refinement'
        valid_direct_modes = {choice[0] for choice in self._OUTPUT_MODE_CHOICES}
        self._direct_output_mode = (
            configured_direct_mode
            if configured_direct_mode in valid_direct_modes
            else 'text'
        )
        self._run_output_mode = self._direct_output_mode
        self._mode_before_image_attachment = None
        self._direct_mode_buttons = {}
        self._run_source_path = ""
        self._run_source_extension = ".txt"
        self._run_source_is_attachment = False
        self._run_manual_glossary_path = ""
        self._run_started_at = 0.0
        self._render_pending = False
        self._rendered_message_cache = {}
        self._message_text_cache = {}
        self._drop_hover_active = False
        self._history_visible_start = 0
        self._history_page_size = 10
        self._history_character_budget = 120000
        # Follow newly streamed text by default. Users can opt into a fixed
        # viewport from Settings or the transcript context menu.
        self._output_auto_scroll_disabled = bool(
            translator.config.get('direct_text_disable_auto_scroll', False)
        )
        self._chat_zoom_level = 0
        self._chat_zoom_percent = 100
        self._processing_text = ""
        self._thinking_stream_text = ""
        self._processing_label_text = "Processing"
        self._processing_spinner_active = False
        self._expanded_processing_messages = set()
        self._copied_message_key = None
        self._inline_response_editor_frame = None
        self._inline_response_editor_box = None
        self._inline_response_edit_index = -1
        self._inline_response_edit_session_id = None
        self._inline_response_original_source = ""
        self._inline_response_source_kind = "plain"
        self._inline_response_reserved_height = 0
        self._assistant_avatar_data_uri = ""
        self._assistant_avatar_width = 28
        self._assistant_avatar_height = 36
        self._user_bubble_corner_data = {}
        self._assistant_bubble_corner_data = {}

        self.setWindowTitle("Direct Text Translation")
        self.setObjectName("directTextDialog")
        self.setModal(False)
        self.setWindowFlags(
            self.windowFlags()
            | Qt.WindowSystemMenuHint
            | Qt.WindowMinMaxButtonsHint
            | Qt.WindowCloseButtonHint
        )
        self.resize(1040, 840)
        self.setMinimumSize(720, 560)
        self._restore_maximized_after_fullscreen = False

        root = QVBoxLayout(self)
