            "QFrame#directComposerCard[dropActive=\"true\"] "
            "QPushButton#directAttachmentButton { background: #344f6b; "
            "border-color: #65a9ff; color: white; }"
            "QPlainTextEdit#directComposer { background: transparent; color: white; "
