    def changeEvent(self, event):
        """Remove always-on-top when window loses focus.
        
        Child dialogs with WindowStaysOnTopHint can cause the parent to
        inherit TOPMOST on Windows. This forces it off when deactivated.
        """
        super().changeEvent(event)
        if event.type() == event.Type.ActivationChange and not self.isActiveWindow():
            # Win32-only: clear TOPMOST flag via SetWindowPos
            if platform.system() == 'Windows':
                try:
                    import ctypes
                    hwnd = int(self.winId())
                    HWND_NOTOPMOST = -2
                    SWP_NOMOVE = 0x0002
                    SWP_NOSIZE = 0x0001
                    SWP_NOACTIVATE = 0x0010
                    ctypes.windll.user32.SetWindowPos(
                        hwnd, HWND_NOTOPMOST, 0, 0, 0, 0,
                        SWP_NOMOVE | SWP_NOSIZE | SWP_NOACTIVATE
                    )
                except Exception:
                    pass

    def closeEvent(self, event):
        """Handle window close event properly"""
        try:
            print("[CLOSE] Window closing...")

            self._request_hard_stop_for_shutdown()
            
            # Save all settings before shutdown so they persist across restarts
            try:
                self.save_config(show_message=False)
                print("[CLOSE] Config saved successfully")
            except Exception as e:
                print(f"[CLOSE] Warning: Could not save config on close: {e}")
            
            # Stop any background operations first
            self.stop_all_operations(kill_child_processes=False, fast=True)
            self._restore_in_progress_rows_for_shutdown()

            # Aggressively free PyInstaller temp dir to avoid warning message box
            try:
                _preempt_temp_dir_warning()
            except Exception:
                pass
            
            print("[CLOSE] Background operations stopped, accepting close event...")
            
            # Accept the close event - this will naturally end the Qt event loop
            event.accept()
            # Propagate global stop to UnifiedClient so in-flight calls exit cleanly
            try:
                from unified_api_client import UnifiedClient
                UnifiedClient.set_global_cancellation(True)
                try:
                    import logging
                    logging.getLogger("unified_api_client").info("⏹️ Global stop requested from translator GUI close")
                except Exception:
                    pass
            except Exception:
                pass
            
            # Quit the application - this will cause app.exec() to return
            from PySide6.QtWidgets import QApplication
            app = QApplication.instance()
            if app:
                print("[CLOSE] Calling app.quit()...")
                app.quit()
            
            print("[CLOSE] Close event handling completed")
            
        except Exception as e:
            print(f"[CLOSE] Error during close: {e}")
            # Even on error, just accept the event and let main function handle exit
            try:
                event.accept()
                from PySide6.QtWidgets import QApplication
                app = QApplication.instance()
                if app:
                    app.quit()
            except:
                pass
    
    def _request_hard_stop_for_shutdown(self):
        """Set stop flags synchronously before close-time cleanup starts."""
        try:
            from shutdown_utils import request_hard_stop_for_shutdown
            request_hard_stop_for_shutdown(
                owner=self,
                translation_stop_flag=globals().get('translation_stop_flag'),
                glossary_stop_flag=globals().get('glossary_stop_flag'),
            )
        except Exception:
            pass

    def _selected_input_files_for_shutdown(self):
        files = list(getattr(self, 'selected_files', []) or [])
        try:
            entry_value = self.entry_epub.text().strip() if hasattr(self, 'entry_epub') else ""
            if entry_value and os.path.isfile(entry_value):
                files.append(entry_value)
        except Exception:
            pass
        return [
            file_path for file_path in files
            if file_path and file_path != "__generative_mode__"
        ]

    def _restore_in_progress_rows_for_shutdown(self):
        """Best-effort parallel cleanup for progress rows before force exit."""
        entry_file = ""
        try:
            entry_file = self.entry_epub.text().strip() if hasattr(self, 'entry_epub') else ""
        except Exception as e:
            entry_file = ""
        try:
            from shutdown_utils import restore_in_progress_rows_for_shutdown
            restore_in_progress_rows_for_shutdown(
                input_files=self._selected_input_files_for_shutdown(),
                entry_file=entry_file,
                output_dir_resolver=self._resolve_translation_output_dir,
                config=getattr(self, 'config', {}),
                app_dir=_get_app_dir(),
                image_progress_managers=[
                    ("image_progress_manager", getattr(self, 'image_progress_manager', None)),
                    ("glossary_progress_manager", getattr(self, 'glossary_progress_manager', None)),
                ],
            )
        except Exception as e:
            print(f"[CLOSE] Warning: shutdown progress cleanup failed: {e}")

    def stop_all_operations(self, kill_child_processes=True, fast=False):
        """Stop all background operations and threads"""
        if getattr(self, '_stop_all_operations_done', False):
            print("[CLEANUP] Background operations already stopped")
            return
        if getattr(self, '_stop_all_operations_running', False):
            print("[CLEANUP] Background operations shutdown already in progress")
            return
        self._stop_all_operations_running = True
        try:
            print("[CLEANUP] Stopping all background operations...")
            self._request_hard_stop_for_shutdown()
            thread_timeout_ms = 250 if fast else 1500
            shutdown_task_timeout = 0.15 if fast else 0.45

            try:
                import concurrent.futures as _shutdown_cf
                import time as _shutdown_time
            except Exception:
                _shutdown_cf = None
                _shutdown_time = None
            shutdown_pool = None
            shutdown_futures = []

            def _submit_shutdown_task(label, fn):
                nonlocal shutdown_pool
                try:
                    if _shutdown_cf is None:
                        fn()
                        return
                    if shutdown_pool is None:
                        shutdown_pool = _shutdown_cf.ThreadPoolExecutor(
                            max_workers=4,
                            thread_name_prefix="gui-shutdown",
                        )
                    shutdown_futures.append((label, shutdown_pool.submit(fn)))
                except Exception:
                    try:
                        fn()
                    except Exception:
                        pass

            def _drain_shutdown_tasks(timeout=shutdown_task_timeout):
                try:
                    if not shutdown_futures or _shutdown_time is None:
                        return
                    deadline = _shutdown_time.monotonic() + max(0.0, float(timeout))
                    for label, future in list(shutdown_futures):
                        remaining = deadline - _shutdown_time.monotonic()
                        if remaining <= 0:
                            if not future.done():
                                print(f"[CLEANUP] {label} still shutting down in background")
                            continue
                        try:
                            future.result(timeout=remaining)
                        except TimeoutError:
                            print(f"[CLEANUP] {label} still shutting down in background")
                        except Exception:
                            pass
                finally:
                    try:
                        if shutdown_pool is not None:
                            shutdown_pool.shutdown(wait=False, cancel_futures=True)
                    except Exception:
                        pass

            def _stop_extraction_daemon():
                try:
                    from chapter_extraction_manager import shutdown_daemon
                    shutdown_daemon()
                    print("[CLEANUP] Extraction daemon shut down")
                except Exception:
                    pass

            def _stop_qa_scanner():
                try:
                    from scan_html_folder import stop_scan
                    stop_scan()
                    print("[CLEANUP] QA scanner stop signal sent")
                except Exception:
                    pass

            _submit_shutdown_task("extraction daemon", _stop_extraction_daemon)

            # Stop QA scanner if running (including truncation detection)
            _submit_shutdown_task("QA scanner", _stop_qa_scanner)

            # Helper: force-close dialogs that override closeEvent to hide instead of close
            def _force_close_dialog(dlg):
                try:
                    if dlg is None:
                        return
                    dlg.closeEvent = lambda event: event.accept()
                    dlg.setAttribute(Qt.WidgetAttribute.WA_DeleteOnClose, True)
                    if hasattr(dlg, "accept"):
                        dlg.accept()
                    dlg.close()
                    dlg.deleteLater()
                except Exception:
                    pass

            def _stop_thread_like(label, thread_obj, timeout_ms=thread_timeout_ms):
                try:
                    if not thread_obj:
                        return
                    print(f"[CLEANUP] Stopping {label}...")
                    if hasattr(thread_obj, 'requestInterruption'):
                        try:
                            thread_obj.requestInterruption()
                        except Exception:
                            pass
                    if hasattr(thread_obj, 'quit'):
                        try:
                            thread_obj.quit()
                        except Exception:
                            pass
                    if hasattr(thread_obj, 'wait'):
                        try:
                            if thread_obj.wait(timeout_ms) is False:
                                print(f"[CLEANUP] {label} did not stop before shutdown")
                        except TypeError:
                            thread_obj.wait()
                        return
                    if hasattr(thread_obj, 'join'):
                        thread_obj.join(timeout=timeout_ms / 1000.0)
                except Exception:
                    pass

            def _fast_cancel_manga_translator(translator):
                """Cancel manga worker resources without expensive model unloads."""
                try:
                    if translator is None:
                        return
                    try:
                        translator.cancel_requested = True
                    except Exception:
                        pass
                    try:
                        if hasattr(translator, '_mem_stop_event') and translator._mem_stop_event:
                            translator._mem_stop_event.set()
                    except Exception:
                        pass
                    try:
                        if hasattr(translator, '_clear_checkout_references'):
                            translator._clear_checkout_references()
                    except Exception:
                        pass
                    try:
                        from manga_translator import MangaTranslator
                        MangaTranslator.set_global_cancellation(True)
                        MangaTranslator.force_release_all_pool_checkouts(restart_workers=False)
                    except Exception:
                        pass
                    for attr in ('_inpainting_future', '_inpainting_executor'):
                        try:
                            obj = getattr(translator, attr, None)
                            if attr.endswith('executor') and obj is not None:
                                try:
                                    obj.shutdown(wait=False, cancel_futures=True)
                                except TypeError:
                                    obj.shutdown(wait=False)
                            setattr(translator, attr, None)
                        except Exception:
                            pass
                except Exception:
                    pass
            
            # Stop any translation operations
            if hasattr(self, '_translation_thread') and self._translation_thread:
                try:
                    print("[CLEANUP] Stopping translation thread...")
                    if hasattr(self._translation_thread, 'wait'):
                        # QThread path
                        _stop_thread_like("translation thread", self._translation_thread)
                    elif hasattr(self._translation_thread, 'join'):
                        # threading.Thread path — cannot force-terminate, just wait briefly
                        self._translation_thread.join(timeout=thread_timeout_ms / 1000.0)
                except:
                    pass
            
            # Stop glossary operations
            if hasattr(self, '_glossary_thread') and self._glossary_thread:
                try:
                    print("[CLEANUP] Stopping glossary thread...")
                    if hasattr(self._glossary_thread, 'wait'):
                        # QThread path
                        _stop_thread_like("glossary thread", self._glossary_thread)
                    elif hasattr(self._glossary_thread, 'join'):
                        # threading.Thread path — cannot force-terminate, just wait briefly
                        self._glossary_thread.join(timeout=thread_timeout_ms / 1000.0)
                except:
                    pass
            
            # Stop executor if it exists
            if hasattr(self, 'executor') and self.executor:
                try:
                    print("[CLEANUP] Shutting down thread pool executor...")
                    executor = self.executor
                    self.executor = None
                    _submit_shutdown_task(
                        "thread pool executor",
                        lambda executor=executor: executor.shutdown(wait=False)
                    )
                except:
                    pass
            
            # Stop PDF worker subprocess if running
            if hasattr(self, 'epub_converter') and hasattr(self.epub_converter, '_active_pdf_mgr'):
                def _stop_pdf_worker():
                    try:
                        pdf_mgr = self.epub_converter._active_pdf_mgr
                        if pdf_mgr and pdf_mgr.is_running:
                            print("[CLEANUP] Stopping PDF worker subprocess...")
                            pdf_mgr.stop()
                            # Force kill the process if still alive
                            if pdf_mgr.process and pdf_mgr.process.poll() is None:
                                pdf_mgr.process.kill()
                    except Exception:
                        pass
                _submit_shutdown_task("PDF worker", _stop_pdf_worker)

            # Stop compression worker subprocesses if running
            if hasattr(self, 'epub_converter') and hasattr(self.epub_converter, '_active_compress_workers'):
                def _stop_compression_workers():
                    try:
                        for p in (self.epub_converter._active_compress_workers or []):
                            if p and p.poll() is None:
                                try:
                                    p.kill()
                                except Exception:
                                    pass
                        print("[CLEANUP] Compression workers killed")
                    except Exception:
                        pass
                _submit_shutdown_task("compression workers", _stop_compression_workers)
            
            # Set any stop flags that might exist
            if hasattr(self, 'stop_flag'):
                self.stop_flag.set()
            
            # Close any open dialogs
            if hasattr(self, '_manga_dialog') and self._manga_dialog:
                try:
                    print("[CLEANUP] Closing manga dialog...")
                    # Flush manga state before closing
                    if hasattr(self, 'manga_translator') and hasattr(self.manga_translator, 'image_state_manager'):
                        try:
                            print("[CLEANUP] Flushing manga image state...")
                            self.manga_translator.image_state_manager.flush()
                            print("[CLEANUP] Manga state flushed successfully")
                        except Exception as e:
                            print(f"[CLEANUP] Failed to flush manga state: {e}")
                    
                    # Shut down the MangaTranslator instance (frees models, HF cache, torch memory)
                    if hasattr(self, 'manga_translator') and self.manga_translator:
                        try:
                            # Call MangaTranslationTab.cleanup() for timer/worker/state cleanup
                            if hasattr(self.manga_translator, 'cleanup'):
                                print("[CLEANUP] Running MangaTranslationTab.cleanup(fast=True)...")
                                try:
                                    self.manga_translator.cleanup(fast=True)
                                except TypeError:
                                    self.manga_translator.cleanup()
                            
                            # App shutdown exits the process shortly after this. Full torch/HF
                            # unloads can add seconds and are unnecessary unless explicitly requested.
                            translator = getattr(self.manga_translator, 'translator', None)
                            if (
                                translator
                                and hasattr(translator, 'shutdown')
                                and os.environ.get('GLOSSARION_FULL_MANGA_SHUTDOWN', '0') == '1'
                            ):
                                print("[CLEANUP] Running full MangaTranslator.shutdown()...")
                                translator.shutdown()
                                print("[CLEANUP] MangaTranslator shutdown complete")
                            elif translator:
                                print("[CLEANUP] Fast-canceling MangaTranslator resources...")
                                _submit_shutdown_task(
                                    "manga translator fast cancel",
                                    lambda translator=translator: _fast_cancel_manga_translator(translator)
                                )
                            
                            # Null out the translator to release memory
                            self.manga_translator.translator = None
                        except Exception as e:
                            print(f"[CLEANUP] Manga translator shutdown error: {e}")
                    
                    self._manga_dialog.close()
                except:
                    pass

            # Close review dialog and stop its background review generator thread
            if hasattr(self, '_review_dialog') and self._review_dialog:
                try:
                    print("[CLEANUP] Closing review dialog & stopping review generator...")
                    dlg = self._review_dialog
                    # Signal the review generator thread to stop
                    if hasattr(dlg, '_stop_requested'):
                        dlg._stop_requested = True
                        dlg._force_stop = True
                    # Cancel any in-flight API calls from review_generator
                    try:
                        from unified_api_client import UnifiedClient
                        UnifiedClient.set_global_cancellation(True)
                        UnifiedClient.hard_cancel_all()
                    except Exception:
                        pass
                    # Stop poll timer
                    if hasattr(dlg, '_review_poll_timer'):
                        try:
                            dlg._review_poll_timer.stop()
                        except Exception:
                            pass
                    # Stop spinner timer
                    if hasattr(dlg, '_stop_spinner_timer'):
                        try:
                            dlg._stop_spinner_timer.stop()
                        except Exception:
                            pass
                    _force_close_dialog(dlg)
                    self._review_dialog = None
                    print("[CLEANUP] Review dialog & generator closed")
                except Exception:
                    pass

            # Close EPUB Library/details/reader stack through its own
            # shutdown hook so reader QThreads are drained before Qt
            # destroys the dialogs.
            if hasattr(self, '_epub_library_dialog') and self._epub_library_dialog:
                try:
                    print("[CLEANUP] Closing EPUB library dialog...")
                    dlg = self._epub_library_dialog
                    if hasattr(dlg, "shutdown"):
                        dlg.shutdown()
                    try:
                        dlg.setAttribute(Qt.WidgetAttribute.WA_DeleteOnClose, True)
                    except Exception:
                        pass
                    dlg.close()
                    try:
                        QApplication.processEvents()
                    except Exception:
                        pass
                    dlg.deleteLater()
                    self._epub_library_dialog = None
                    print("[CLEANUP] EPUB library dialog closed")
                except Exception:
                    pass

            if kill_child_processes:
                # Kill stray QtWebEngine child processes that can lock the PyInstaller _MEI temp dir.
                # Normal GUI close leaves this to shutdown_utils.force_shutdown() after Qt has had
                # a chance to drain WebEngine teardown events.
                try:
                    import psutil, sys
                    meipass = getattr(sys, "_MEIPASS", "").lower()
                    victims = []
                    for proc in psutil.process_iter(["name", "exe"]):
                        name = (proc.info.get("name") or "").lower()
                        exe = (proc.info.get("exe") or "").lower()
                        if "qtwebengineprocess" in name or "qtwebengineprocess" in exe:
                            if not meipass or meipass in exe:
                                victims.append(proc)
                    for p in victims:
                        try:
                            p.terminate()
                        except Exception:
                            pass
                    if victims:
                        psutil.wait_procs(victims, timeout=1)
                except Exception:
                    # Fallback to taskkill if psutil unavailable (Windows only)
                    if os.name == 'nt':
                        try:
                            import subprocess
                            try:
                                from shutdown_utils import run_no_window
                            except Exception:
                                run_no_window = subprocess.run
                            run_no_window(["taskkill", "/F", "/IM", "QtWebEngineProcess.exe"],
                                          stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
                        except Exception:
                            pass

                # Sweep any remaining children (helper workers, Qt subprocesses)
                # so their handles to DLLs under _MEIPASS drop before we exit.
                try:
                    _kill_child_process_tree()
                except Exception:
                    pass
            # Remove temporary CBZ extraction folder if it exists
            try:
                temp_root = getattr(self, 'cbz_temp_root', None)
                if temp_root and os.path.isdir(temp_root):
                    _submit_shutdown_task(
                        "temporary CBZ cleanup",
                        lambda temp_root=temp_root: shutil.rmtree(temp_root, ignore_errors=True)
                    )
            except Exception:
                pass

            # Best-effort release of _MEIPASS locks to avoid temp-dir warning
            try:
                _preempt_temp_dir_warning()
            except Exception:
                pass

            # Close auxiliary dialogs that may remain hidden
            try:
                _force_close_dialog(getattr(self, '_other_settings_dialog', None))
            except Exception:
                pass
            try:
                _force_close_dialog(getattr(self, '_multi_file_retranslation_dialog', None))
            except Exception:
                pass
            try:
                for dlg in getattr(self, '_image_retranslation_dialog_cache', {}).values():
                    _force_close_dialog(dlg)
            except Exception:
                pass
            try:
                _force_close_dialog(getattr(self, '_qa_settings_dialog', None))
            except Exception:
                pass
            
            _drain_shutdown_tasks()
            print("[CLEANUP] Background operations stopped")
            if not fast:
                self._stop_all_operations_done = True
            
        except Exception as e:
            print(f"[CLEANUP] Error stopping operations: {e}")
            if not fast:
                self._stop_all_operations_done = True
        finally:
            try:
                if 'shutdown_pool' in locals() and shutdown_pool is not None:
                    shutdown_pool.shutdown(wait=False, cancel_futures=True)
            except Exception:
                pass
            self._stop_all_operations_running = False
        
