    # Logging handler to forward client logs into the GUI
    class GuiLogHandler(logging.Handler):
        def __init__(self, outer, level=logging.INFO):
            super().__init__(level)
            self.outer = outer
            self.outer_id = id(outer)  # Store ID to identify handlers from same instance
        def emit(self, record):
            try:
                # Use the raw message without logger name/level prefixes
                msg = record.getMessage()
                self.outer.append_log(msg)
            except Exception:
                # Never raise from logging path
                pass

    def _attach_gui_logging_handlers(self):
        """Attach logging handlers so library/client logs appear in the GUI log.
        Safe to call multiple times (won't duplicate handlers).
        """
        try:
            # Build handler
            handler = TranslatorGUI.GuiLogHandler(self, level=logging.INFO)
            fmt = logging.Formatter('%(message)s')
            handler.setFormatter(fmt)
            
            gui_id = id(self)
            
            # Target relevant loggers
            target_loggers = [
                'unified_api_client',
                'httpx',
                'requests.packages.urllib3',
                'openai'
            ]
            for name in target_loggers:
                lg = logging.getLogger(name)
                # Remove any existing handlers from THIS SAME gui instance (any GuiLogHandler type)
                lg.handlers = [h for h in lg.handlers 
                              if not (hasattr(h, 'outer_id') and h.outer_id == gui_id)]
                # Now add the new handler
                lg.addHandler(handler)
                # Ensure at least INFO level to see retry/backoff notices
                if lg.level > logging.INFO or lg.level == logging.NOTSET:
                    lg.setLevel(logging.INFO)
        except Exception as e:
            try:
                self.append_log(f"⚠️ Failed to attach GUI log handlers: {e}")
            except Exception:
                pass

    def create_glossary_backup(self, operation_name="manual"):
        """Create a backup of the current glossary if auto-backup is enabled"""
        # For manual backups, always proceed. For automatic backups, check the setting.
        if operation_name != "manual" and not self.config.get('glossary_auto_backup', True):
            return True
        
        if not self.current_glossary_data or not hasattr(self, 'editor_file_entry') or not self.editor_file_entry.text():
            return True
        
        try:
            # Get the original glossary file path
            original_path = self.editor_file_entry.text()
            original_dir = os.path.dirname(original_path)
            original_name = os.path.basename(original_path)
            
            # Create backup directory
            backup_dir = os.path.join(original_dir, "Backups")
            
            # Create directory if it doesn't exist
            try:
                os.makedirs(backup_dir, exist_ok=True)
            except Exception as e:
                self.append_log(f"⚠️ Failed to create backup directory: {str(e)}")
                return False
            
            # Generate timestamp-based backup filename
            timestamp = time.strftime("%Y%m%d_%H%M%S")
            backup_name = f"{os.path.splitext(original_name)[0]}_{operation_name}_{timestamp}.json"
            backup_path = os.path.join(backup_dir, backup_name)
            
            # Try to save backup
            with open(backup_path, 'w', encoding='utf-8') as f:
                json.dump(self.current_glossary_data, f, ensure_ascii=False, indent=2)
            
            self.append_log(f"💾 Backup created: {backup_name}")
            
            # Optional: Clean old backups if more than limit
            max_backups = self.config.get('glossary_max_backups', 50)
            if max_backups > 0:
                self._clean_old_backups(backup_dir, original_name, max_backups)
            
            return True
            
        except Exception as e:
            # Log the actual error
            self.append_log(f"⚠️ Backup failed: {str(e)}")
            # Ask user if they want to continue anyway
            reply = QMessageBox.question(self, "Backup Failed", 
                                      f"Failed to create backup: {str(e)}\n\nContinue anyway?",
                                      QMessageBox.Yes | QMessageBox.No)
            return reply == QMessageBox.Yes

    def get_current_epub_path(self):
        """Get the currently selected EPUB path from various sources"""
        epub_path = None
        
        # Try different sources in order of preference
        sources = [
            # Direct selection
            lambda: getattr(self, 'selected_epub_path', None),
            # From config
            lambda: self.config.get('last_epub_path', None) if hasattr(self, 'config') else None,
            # From file path variable (if it exists)
            lambda: self.epub_file_path if hasattr(self, 'epub_file_path') and self.epub_file_path else None,
            # From current translation
            lambda: getattr(self, 'current_epub_path', None),
        ]
        
        for source in sources:
            try:
                path = source()
                if path and os.path.exists(path):
                    epub_path = path
                    break
            except Exception as e:
                # Keep debug for unexpected source-check failures
                try:
                    print(f"[DEBUG] Error checking source: {e}")
                except Exception:
                    pass
                continue

        if not epub_path:
            try:
                pass
            except Exception:
                pass

        return epub_path
    
    def _clean_old_backups(self, backup_dir, original_name, max_backups):
        """Remove old backups exceeding the limit"""
        try:
            # Find all backups for this glossary
            prefix = os.path.splitext(original_name)[0]
            backups = []
            
            for file in os.listdir(backup_dir):
                if file.startswith(prefix) and file.endswith('.json'):
                    file_path = os.path.join(backup_dir, file)
                    backups.append((file_path, os.path.getmtime(file_path)))
            
            # Sort by modification time (oldest first)
            backups.sort(key=lambda x: x[1])
            
            # Remove oldest backups if exceeding limit
            while len(backups) > max_backups:
                old_backup = backups.pop(0)
                os.remove(old_backup[0])
                self.append_log(f"🗑️ Removed old backup: {os.path.basename(old_backup[0])}")
                
        except Exception as e:
            self.append_log(f"⚠️ Error cleaning old backups: {str(e)}")
        
    def open_manga_translator(self):
        """Open manga translator in a new window"""
        try:
            if MANGA_IMPORT_FUTURE is not None:
                _consume_manga_import_future()
        except Exception:
            pass
        if MANGA_IMPORT_LOADING:
            QMessageBox.information(self, "Manga Translator", "Manga imports are still loading.")
            return
        if not MANGA_SUPPORT:
            QMessageBox.warning(self, "Not Available", "Manga translation modules not found.")
            return

        try:
            enabled = bool(getattr(self, 'use_custom_image_edit_endpoint_var', False))
            endpoint = str(getattr(self, 'custom_image_edit_endpoint_var', '') or self.config.get('custom_image_edit_endpoint', '') or '').strip()
            self.config['custom_image_edit_endpoint'] = endpoint
            self.config['use_custom_image_edit_endpoint'] = enabled
            if self.config.get('manga_local_inpaint_model') == 'custom-image-edit' and endpoint:
                self.config['manga_custom-image-edit_model_path'] = endpoint
                self.config['manga_custom_image_edit_model_path'] = endpoint
            elif self.config.get('manga_local_inpaint_model') == 'custom-image-edit' and not endpoint:
                self.config['manga_custom-image-edit_model_path'] = ''
                self.config['manga_custom_image_edit_model_path'] = ''
            os.environ['USE_CUSTOM_IMAGE_EDIT_ENDPOINT'] = '1' if enabled else '0'
            os.environ['CUSTOM_IMAGE_EDIT_BASE_URL'] = endpoint if enabled else ''
            os.environ['OPENAI_IMAGE_EDIT_BASE_URL'] = endpoint if enabled else ''
        except Exception:
            pass
        
        # Always open directly - model preloading will be handled inside the manga tab
        self._open_manga_translator_direct()
    
    def _open_manga_translator_direct(self):
        """Open manga translator directly without loading screen"""
        # Import PySide6 components for the manga translator
        try:
            from PySide6.QtWidgets import QApplication, QDialog, QWidget, QVBoxLayout, QScrollArea
            from PySide6.QtCore import Qt
        except ImportError:
            QMessageBox.critical(self, "Missing Dependency", 
                               "PySide6 is required for manga translation. Please install it:\npip install PySide6")
            return

        # If dialog already exists, just show and focus it to preserve exact state
        try:
            if hasattr(self, "_manga_dialog") and self._manga_dialog is not None:
                # Show with fade-in animation
                try:
                    from dialog_animations import show_dialog_with_fade
                    show_dialog_with_fade(self._manga_dialog, duration=250)
                except Exception:
                    self._manga_dialog.show()
                # Bring to front and focus
                try:
                    self._manga_dialog.raise_()
                    self._manga_dialog.activateWindow()
                except Exception:
                    pass
                return
        except Exception:
            # If the old reference is invalid, recreate below
            self._manga_dialog = None
        
        # Create or get QApplication instance
        app = QApplication.instance()
        if not app:
            # DPI awareness is handled globally by dpi_setup.configure()
            app = QApplication(sys.argv)
        try:
            import dpi_setup
            dpi_setup.apply_font_scale(app)
        except Exception:
            pass
        
        # Create PySide6 dialog with standard window controls
        dialog = QDialog()
        dialog.setWindowTitle("🎌 Manga Panel Translator")
        
        # Enable maximize button and standard window controls (minimize, maximize, close)
        dialog.setWindowFlags(
            Qt.Window |
            Qt.WindowMinimizeButtonHint |
            Qt.WindowMaximizeButtonHint |
            Qt.WindowCloseButtonHint
        )
        # Do not delete widgets on close; we'll hide instead to retain exact state
        dialog.setAttribute(Qt.WA_DeleteOnClose, False)
        
        # Set icon if available
        try:
            icon_path = os.path.join(self.base_dir, 'Halgakos.ico')
            if os.path.exists(icon_path):
                from PySide6.QtGui import QIcon
                dialog.setWindowIcon(QIcon(icon_path))
        except Exception:
            pass
        
        # Size and position the dialog
        # Use availableGeometry to exclude taskbar and other system UI
        screen = app.primaryScreen().availableGeometry()
        dialog_width = min(1400, int(screen.width() * 0.95))  # Increased from 900 to 1400 for 2-column layout
        dialog_height = int(screen.height() * 0.90)  # Use 90% of available screen height for safety margin
        dialog.resize(dialog_width, dialog_height)
        
        # Center the dialog within available screen space
        dialog_x = screen.x() + (screen.width() - dialog_width) // 2
        dialog_y = screen.y() + (screen.height() - dialog_height) // 2
        dialog.move(dialog_x, dialog_y)
        
        # Set dialog layout
        dialog_layout = QVBoxLayout(dialog)
        dialog_layout.setContentsMargins(0, 0, 0, 0)

        # --- Instant feedback: show a lightweight loading placeholder first.
        # Building MangaTranslationTab takes seconds, so it is deferred until
        # after the dialog is visible and painted.
        from PySide6.QtWidgets import QLabel, QProgressBar
        from PySide6.QtCore import QTimer
        loading_widget = QWidget()
        loading_layout = QVBoxLayout(loading_widget)
        loading_layout.setSpacing(14)
        loading_layout.addStretch(1)
        loading_spin_timer = None
        try:
            from spinning import create_icon_label
            loading_icon = create_icon_label(64, self.base_dir)
            loading_icon.setFixedSize(64, 64)
            loading_layout.addWidget(loading_icon, 0, Qt.AlignCenter)
            # Continuously spin the icon (spinning.py's animate_icon is a
            # one-shot 500ms spin, so drive the rotation with our own timer,
            # same as the SDLXLIFF review loading page).
            original_pixmap = loading_icon.pixmap()
            if original_pixmap is not None and not original_pixmap.isNull():
                original_pixmap = original_pixmap.copy()
                from PySide6.QtGui import QTransform
                spin_state = {"angle": 0}

                def _spin_manga_loading_icon():
                    try:
                        spin_state["angle"] = (spin_state["angle"] + 24) % 360
                        transform = QTransform().rotate(spin_state["angle"])
                        rotated = original_pixmap.transformed(transform, Qt.SmoothTransformation)
                        if rotated.isNull():
                            return
                        loading_icon.setPixmap(rotated.scaled(
                            loading_icon.size().width(),
                            loading_icon.size().height(),
                            Qt.KeepAspectRatio,
                            Qt.SmoothTransformation,
                        ))
                        loading_icon.update()
                    except RuntimeError:
                        try:
                            loading_spin_timer.stop()
                        except Exception:
                            pass
                    except Exception:
                        pass

                from PySide6.QtCore import QTimer as _QTimer
                loading_spin_timer = _QTimer(dialog)
                loading_spin_timer.timeout.connect(_spin_manga_loading_icon)
                # IMPORTANT: don't start spinning yet. The dialog fades in via
                # a QGraphicsOpacityEffect, and updating a transparent label's
                # pixmap while that effect is active smears ghost copies of the
                # icon into the effect's cached buffer (multiple overlaid
                # Halgakos icons until the fade ends). The spin is started
                # after the fade completes, in _build_manga_content's
                # scheduling below.
        except Exception:
            loading_spin_timer = None
        loading_label = QLabel("Loading Manga Translator...")
        loading_label.setAlignment(Qt.AlignCenter)
        loading_label.setStyleSheet("font-size: 13pt; font-weight: bold; color: #94a3b8; padding: 8px;")
        loading_layout.addWidget(loading_label)
        loading_progress = QProgressBar()
        loading_progress.setRange(0, 0)  # indeterminate
        loading_progress.setTextVisible(False)
        loading_progress.setFixedHeight(14)
        loading_progress.setFixedWidth(340)
        loading_layout.addWidget(loading_progress, 0, Qt.AlignCenter)
        loading_layout.addStretch(1)
        dialog_layout.addWidget(loading_widget)

        # Intercept window close: hide instead of destroy to preserve state
        def _handle_close(event):
            try:
                # Persist current image rectangles/state before flushing
                if hasattr(self, 'manga_translator'):
                    try:
                        if hasattr(self.manga_translator, '_current_image_path') and self.manga_translator._current_image_path:
                            import ImageRenderer
                            ImageRenderer._persist_current_image_state(self.manga_translator)
                            print("[MANGA_CLOSE] Persisted current image state")
                    except Exception as e:
                        print(f"[MANGA_CLOSE] Failed to persist state: {e}")
                
                # Flush image state to disk to persist OCR data
                if hasattr(self, 'manga_translator') and hasattr(self.manga_translator, 'image_state_manager'):
                    try:
                        print("[MANGA_CLOSE] Flushing image state...")
                        self.manga_translator.image_state_manager.flush()
                        print("[MANGA_CLOSE] State flushed successfully")
                    except Exception as e:
                        print(f"[MANGA_CLOSE] Failed to flush state: {e}")
                
                event.ignore()
                dialog.hide()
            except Exception:
                # Best-effort: still hide on any error
                try:
                    event.ignore()
                except Exception:
                    pass
                dialog.hide()
        dialog.closeEvent = _handle_close

        # Keep reference to prevent garbage collection and allow reuse
        self._manga_dialog = dialog

        # Show the dialog with smooth fade-in animation BEFORE building the
        # heavy manga UI, so the user gets instant feedback on click.
        try:
            from dialog_animations import show_dialog_with_fade
            show_dialog_with_fade(dialog, duration=250)
        except Exception:
            # Fallback to normal show if animation fails
            dialog.show()

        def _build_manga_content():
            # Dialog may have been replaced/discarded while the timer was pending
            if getattr(self, '_manga_dialog', None) is not dialog:
                return
            try:
                # Create scrollable content area
                scroll_area = QScrollArea()
                scroll_area.setWidgetResizable(True)
                scroll_area.setHorizontalScrollBarPolicy(Qt.ScrollBarAsNeeded)
                scroll_area.setVerticalScrollBarPolicy(Qt.ScrollBarAsNeeded)

                # Create main content widget
                content_widget = QWidget()
                scroll_area.setWidget(content_widget)

                # Initialize the manga translator interface (the heavy part)
                self.manga_translator = MangaTranslationTab(content_widget, self, dialog, scroll_area)

                dialog_layout.addWidget(scroll_area)
            except Exception as exc:
                # Surface the failure inside the dialog and allow a clean retry
                try:
                    if loading_spin_timer is not None:
                        loading_spin_timer.stop()
                    loading_progress.hide()
                    loading_label.setText(f"Failed to load Manga Translator:\n{exc}")
                    loading_label.setStyleSheet("font-size: 11pt; color: #e74c3c; padding: 8px;")
                except Exception:
                    pass
                self._manga_dialog = None
                return
            # Swap the placeholder out. Hide FIRST and keep the timer cleanup
            # separate, so no failure can leave the placeholder visible on top
            # of the real UI (which would show two Halgakos icons).
            try:
                loading_widget.hide()
            except Exception:
                pass
            try:
                if loading_spin_timer is not None:
                    loading_spin_timer.stop()
                    loading_spin_timer.deleteLater()
            except Exception:
                pass
            try:
                dialog_layout.removeWidget(loading_widget)
                loading_widget.setParent(None)
                loading_widget.deleteLater()
            except Exception:
                pass

        def _start_loading_phase():
            # Runs after the fade-in has fully completed and the opacity
            # effect has been removed from the dialog. Only now is it safe to
            # animate the icon (no ghost smearing) and to pump events during
            # the heavy build.
            try:
                if loading_spin_timer is not None:
                    loading_spin_timer.start(45)
            except Exception:
                pass
            # Let the first clean spin frames paint, then start the build
            QTimer.singleShot(90, _build_manga_content)

        # Defer past the 250ms fade so the QGraphicsOpacityEffect is gone
        QTimer.singleShot(320, _start_loading_phase)

        
