    def _update_assistant_prompt_button_style(self):
        """Update the assistant prompt button style based on whether a prompt is set"""
        if hasattr(self, 'assistant_prompt') and self.assistant_prompt and self.assistant_prompt.strip():
            # Prompt is set - use active style (green)
            self.assistant_prompt_button.setStyleSheet("background-color: #28a745; color: white; font-weight: bold;")
            self.assistant_prompt_button.setToolTip(f"Assistant prompt is active ({len(self.assistant_prompt)} chars)")
        else:
            # No prompt set - use neutral style
            self.assistant_prompt_button.setStyleSheet("background-color: #6c757d; color: white; font-weight: bold;")
            self.assistant_prompt_button.setToolTip("Optional: Set an assistant prefill prompt")

    def _update_refinement_prompt_button_style(self):
        """Update the refinement prompt button style based on custom prompt fields."""
        if not hasattr(self, 'refinement_prompt_button'):
            return
        prompt_pairs = [
            ('refinement_system_prompt', 'default_refinement_system_prompt'),
            ('refinement_user_prompt', 'default_refinement_user_prompt'),
            ('refinement_full_with_raw_system_prompt', 'default_refinement_full_with_raw_system_prompt'),
            ('refinement_full_with_raw_user_prompt', 'default_refinement_full_with_raw_user_prompt'),
            ('refinement_failed_system_prompt', 'default_refinement_failed_system_prompt'),
            ('refinement_failed_user_prompt', 'default_refinement_failed_user_prompt'),
            ('refinement_partial_system_prompt', 'default_refinement_partial_system_prompt'),
            ('refinement_partial_user_prompt', 'default_refinement_partial_user_prompt'),
            ('refinement_partial_b_system_prompt', 'default_refinement_partial_b_system_prompt'),
            ('refinement_partial_b_user_prompt', 'default_refinement_partial_b_user_prompt'),
            ('refinement_partial_b2_system_prompt', 'default_refinement_partial_b2_system_prompt'),
            ('refinement_partial_b2_user_prompt', 'default_refinement_partial_b2_user_prompt'),
        ]
        is_custom = any(
            str(getattr(self, attr, '') or '').strip() != str(getattr(self, default_attr, '') or '').strip()
            for attr, default_attr in prompt_pairs
        )
        is_custom = is_custom or any(
            str(getattr(self, attr, '') or '') != str(getattr(self, default_attr, '') or '')
            for attr, default_attr in (
                ('refinement_full_with_raw_raw_header', 'default_refinement_full_with_raw_raw_header'),
                ('refinement_full_with_raw_raw_footer', 'default_refinement_full_with_raw_raw_footer'),
            )
        )
        raw_role = str(
            getattr(
                self,
                'refinement_full_with_raw_raw_role_var',
                self.config.get('refinement_full_with_raw_raw_role', 'assistant'),
            ) or 'assistant'
        ).strip().lower()
        is_custom = is_custom or raw_role != 'assistant'
        if is_custom:
            self.refinement_prompt_button.setStyleSheet("background-color: #28a745; color: white; font-weight: bold;")
            self.refinement_prompt_button.setToolTip("Refinement prompt override is active")
        else:
            self.refinement_prompt_button.setStyleSheet("background-color: #6c757d; color: white; font-weight: bold;")
            self.refinement_prompt_button.setToolTip("Edit the prompts used by refinement output mode and multipass refinement")

    def _get_multipass_refinement_mode(self):
        """Return the live multipass refinement mode from the combobox/config."""
        mode = None
        can_read_widgets = True
        try:
            app = QApplication.instance()
            can_read_widgets = app is None or QThread.currentThread() == app.thread()
        except Exception:
            can_read_widgets = True

        combo = getattr(self, 'multipass_refinement_mode_combo', None) if can_read_widgets else None
        if combo is not None:
            try:
                mode = combo.currentData()
            except Exception:
                mode = None
            if not mode:
                try:
                    mode = combo.currentText()
                except Exception:
                    mode = None
        if not mode:
            mode = getattr(self, 'multipass_refinement_mode_var', None)
        if not mode:
            mode = self.config.get('multipass_refinement_mode', 'full')
        mode = str(mode or 'full').strip().lower()
        return mode if mode in MULTIPASS_REFINEMENT_MODES else 'full'

    def _sync_multipass_refinement_mode_from_combo(self, _idx=None):
        mode = self._get_multipass_refinement_mode()
        self.multipass_refinement_mode_var = mode
        self.config['multipass_refinement_mode'] = mode

    def _export_multipass_runtime_env(self):
        """Capture the live multipass controls and export them for the worker."""
        if (
            getattr(self, '_input_output_run_active', False)
            and getattr(self, '_direct_text_force_multipass_off', True)
        ):
            mode = self._get_multipass_refinement_mode()
            os.environ['MULTIPASS_MODE'] = '0'
            os.environ['MULTIPASS_REFINEMENT_MODE'] = mode
            return False, mode

        can_read_widgets = True
        try:
            app = QApplication.instance()
            can_read_widgets = app is None or QThread.currentThread() == app.thread()
        except Exception:
            can_read_widgets = True

        if can_read_widgets:
            checkbox = getattr(self, 'multipass_checkbox', None)
            if checkbox is not None:
                try:
                    self.multipass_mode_var = bool(checkbox.isChecked())
                except Exception:
                    pass
            self._sync_multipass_refinement_mode_from_combo()

        enabled = bool(getattr(self, 'multipass_mode_var', self.config.get('multipass_mode', False)))
        mode = self._get_multipass_refinement_mode()

        self.multipass_mode_var = enabled
        self.multipass_refinement_mode_var = mode
        self.config['multipass_mode'] = enabled
        self.config['multipass_refinement_mode'] = mode

        os.environ['MULTIPASS_MODE'] = '1' if enabled else '0'
        os.environ['MULTIPASS_REFINEMENT_MODE'] = mode
        try:
            os.environ['SCAN_PHASE_MODE'] = self._get_scan_phase_mode()
            os.environ['QA_SCANNER_SETTINGS_JSON'] = self._get_qa_scanner_settings_json()
        except Exception:
            pass
        return enabled, mode

    def _get_scan_phase_mode(self):
        """Return the live QA scan mode used by post-translation scanning."""
        mode = getattr(self, 'scan_phase_mode_var', None) or self.config.get('scan_phase_mode', 'quick-scan')
        mode = str(mode or 'quick-scan').strip().lower()
        if mode not in ('quick-scan', 'aggressive', 'ai-hunter', 'custom'):
            mode = 'quick-scan'
        return mode

    def _get_qa_scanner_settings_json(self):
        """Serialize QA scanner settings so worker-side scans match GUI scans."""
        settings = self.config.get('qa_scanner_settings', {})
        if not isinstance(settings, dict):
            settings = {}
        settings = dict(settings)
        try:
            main_lang = self.config.get('output_language') or getattr(self, 'target_lang_var', '') or os.getenv('OUTPUT_LANGUAGE', '')
            if main_lang:
                settings['target_language'] = str(main_lang).strip().lower()
        except Exception:
            pass
        try:
            return json.dumps(settings, ensure_ascii=False)
        except Exception:
            return "{}"

    def _available_width_for_multipass_refinement_row(self, row):
        """Return the grid cell width available to the compact multipass controls."""
        available_width = row.width()
        try:
            layout = getattr(self, 'frame', None)
            index = layout.indexOf(row) if layout is not None else -1
            if index >= 0:
                grid_row, grid_col, row_span, col_span = layout.getItemPosition(index)
                rect = layout.cellRect(grid_row, grid_col)
                if row_span > 1 or col_span > 1:
                    for r in range(grid_row, grid_row + row_span):
                        for c in range(grid_col, grid_col + col_span):
                            rect = rect.united(layout.cellRect(r, c))
                if rect.isValid() and rect.width() > 0:
                    available_width = max(available_width, rect.width())
        except Exception:
            pass
        return available_width

    def _update_multipass_refinement_layout(self):
        """Move the refine prompt button to the temperature row when the batch row is tight."""
        controls_layout = getattr(self, 'multipass_refinement_controls_layout', None)
        controls_widget = getattr(self, 'multipass_refinement_controls', None)
        combo = getattr(self, 'multipass_refinement_mode_combo', None)
        button = getattr(self, 'refinement_prompt_button', None)
        row = getattr(self, 'batch_right_container', None)
        batch_size = getattr(self, 'batch_size_entry', None)
        checkbox = getattr(self, 'multipass_checkbox', None)
        temp_layout = getattr(self, 'temp_layout', None)
        temp_container = getattr(self, 'temp_container', None)
        temp_entry = getattr(self, 'trans_temp', None)
        disable_temp_checkbox = getattr(self, 'disable_temperature_checkbox', None)
        compact_spacer = getattr(self, '_refinement_prompt_compact_spacer', None)
        if not all((controls_layout, controls_widget, combo, button, row, batch_size, checkbox, temp_layout, temp_container)):
            return

        try:
            spacing = 6
            row_margins = row.layout().contentsMargins() if row.layout() else None
            margin_width = (row_margins.left() + row_margins.right()) if row_margins else 0
            batch_size_max = batch_size.maximumWidth()
            batch_size_width = batch_size.sizeHint().width()
            if batch_size_max and batch_size_max < 16777215:
                batch_size_width = min(batch_size_width, batch_size_max)
            combo_width = combo.minimumWidth() or combo.sizeHint().width()
            button_width = max(
                int(getattr(self, '_refinement_prompt_button_width', 0) or 0),
                button.minimumWidth(),
                button.sizeHint().width(),
                button.minimumSizeHint().width(),
            )
            self._refinement_prompt_button_width = button_width
            button.setFixedWidth(button_width)
            button.setSizePolicy(QSizePolicy.Fixed, QSizePolicy.Fixed)

            desired_width = (
                margin_width
                + batch_size_width
                + checkbox.sizeHint().width()
                + combo_width
                + button_width
                + (spacing * 3)
            )
            available_width = self._available_width_for_multipass_refinement_row(row)
            currently_compact = bool(getattr(self, '_multipass_refinement_compact', False))
            compact = available_width > 0 and (
                available_width < desired_width if not currently_compact else available_width < desired_width + 8
            )
            target_parent = temp_container if compact else controls_widget
            if compact == currently_compact and button.parentWidget() is target_parent:
                if not compact or (compact_spacer is not None and temp_layout.indexOf(compact_spacer) >= 0):
                    return

            controls_layout.setDirection(QBoxLayout.LeftToRight)
            controls_layout.setSpacing(spacing)
            if controls_layout.indexOf(combo) < 0:
                controls_layout.insertWidget(0, combo)
            combo.setParent(controls_widget)

            controls_layout.removeWidget(button)
            temp_layout.removeWidget(button)
            if compact_spacer is not None:
                temp_layout.removeWidget(compact_spacer)
                controls_layout.removeWidget(compact_spacer)
                compact_spacer.hide()
                compact_spacer.setParent(None)
            if compact:
                if compact_spacer is None:
                    compact_spacer = QWidget()
                    compact_spacer.setObjectName("refinementPromptCompactSpacer")
                    compact_spacer.setSizePolicy(QSizePolicy.Fixed, QSizePolicy.Fixed)
                    self._refinement_prompt_compact_spacer = compact_spacer
                compact_spacer.setFixedWidth(50)
                insert_at = 2
                for temperature_widget in (temp_entry, disable_temp_checkbox):
                    if temperature_widget is not None:
                        temp_index = temp_layout.indexOf(temperature_widget)
                        if temp_index >= 0:
                            insert_at = max(insert_at, temp_index + 1)
                temp_layout.insertWidget(insert_at, compact_spacer)
                compact_spacer.show()
                temp_layout.insertWidget(insert_at + 1, button)
            else:
                controls_layout.addWidget(button)

            self._multipass_refinement_compact = compact
            controls_widget.updateGeometry()
            temp_container.updateGeometry()
            row.updateGeometry()
        except Exception:
            pass

    def show_refinement_prompt_dialog(self):
        """Open dialog to edit prompts used by refinement output mode and multipass."""
        if hasattr(self, '_refinement_prompt_dialog') and self._refinement_prompt_dialog is not None:
            try:
                self._refinement_prompt_dialog.show()
                self._refinement_prompt_dialog.raise_()
                self._refinement_prompt_dialog.activateWindow()
                return
            except RuntimeError:
                self._refinement_prompt_dialog = None

        dialog = QDialog(self)
        dialog.setWindowTitle("Refinement Prompt")
        dialog.setModal(False)
        dialog.setWindowModality(Qt.NonModal)
        dialog.setWindowFlags(dialog.windowFlags() | Qt.WindowStaysOnTopHint)
        self._refinement_prompt_dialog = dialog
        dialog.finished.connect(lambda _result: setattr(self, '_refinement_prompt_dialog', None))

        screen = QApplication.primaryScreen().geometry()
        dialog.setMinimumSize(int(screen.width() * 0.42), int(screen.height() * 0.55))

        layout = QVBoxLayout(dialog)
        instructions = QLabel(
            "Edit prompts sent only to refinement requests. "
            "Use {target_lang} for the selected target language. "
            "In the user prompt, {html} or {content} can mark where the translated HTML should be inserted. "
            "In Full, Full + raw, Failed, Partial, Partial.b, and Partial.b2 prompts, {QA_Issues} is replaced with current character-found QA issues when available. "
            "Full + raw sends the matching raw source HTML as a separate prompt using the role selected on that tab. "
            "The existing Assistant Prompt button is used for optional assistant prefill."
        )
        instructions.setWordWrap(True)
        layout.addWidget(instructions)

        tabs = QTabWidget()
        tabs.setStyleSheet("""
            QTabWidget::pane {
                border: 1px solid #4b5565;
                border-radius: 6px;
                top: -1px;
                background: #1f1f1f;
            }
            QTabBar::tab {
                background: #2a2d32;
                color: #d7dde8;
                border: 1px solid #4b5565;
                border-bottom: 0;
                min-width: 78px;
                padding: 8px 16px;
                margin-right: 4px;
                font-weight: 600;
            }
            QTabBar::tab:selected {
                background: #2f80d0;
                color: #ffffff;
                border-color: #6eb6ff;
            }
            QTabBar::tab:hover:!selected {
                background: #39414d;
                color: #ffffff;
                border-color: #718096;
            }
            QTabBar::tab:first {
                border-top-left-radius: 6px;
            }
            QTabBar::tab:last {
                background: #0d6efd;
                color: #ffffff;
                border: 1px solid #64a5ff;
                border-radius: 3px;
                margin-left: 18px;
                margin-right: 0px;
                min-width: 116px;
            }
            QTabBar::tab:last:hover {
                background: #2f80ff;
                border-color: #8fc2ff;
            }
            QTabBar::tab:last:selected {
                background: #0d6efd;
                color: #ffffff;
                border: 1px solid #64a5ff;
            }
        """)
        editors = {}
        tab_mode_by_index = {}

        def _prompt_value(attr, config_key, default_attr, allow_default=True):
            value = getattr(self, attr, None)
            if value is None:
                value = self.config.get(config_key, None)
            if value is None or (allow_default and not str(value).strip()):
                value = getattr(self, default_attr, '')
            return str(value or '')

        def _add_prompt_tab(mode_key, label, system_attr, user_attr, system_config_key, user_config_key, default_system_attr, default_user_attr, *, system_allow_default=True):
            tab = QWidget()
            tab_layout = QVBoxLayout(tab)
            tab_layout.addWidget(QLabel("System Prompt:"))
            system_editor = QTextEdit()
            system_editor.setPlainText(_prompt_value(system_attr, system_config_key, default_system_attr, allow_default=system_allow_default))
            tab_layout.addWidget(system_editor)

            tab_layout.addWidget(QLabel("User Prompt (optional):"))
            user_editor = QTextEdit()
            if mode_key == "all":
                user_editor.setPlaceholderText("Optional extra instruction for this refinement request")
            else:
                user_editor.setPlaceholderText("Optional extra instruction for this refinement mode")
            user_editor.setPlainText(_prompt_value(user_attr, user_config_key, default_user_attr, allow_default=False))
            tab_layout.addWidget(user_editor)
            editors[mode_key] = (system_editor, user_editor)
            tab_index = tabs.addTab(tab, label)
            tab_mode_by_index[tab_index] = mode_key
            return tab, tab_layout, system_editor, user_editor

        _add_prompt_tab(
            "all", "Full",
            "refinement_system_prompt", "refinement_user_prompt",
            "refinement_system_prompt", "refinement_user_prompt",
            "default_refinement_system_prompt", "default_refinement_user_prompt",
        )
        _full_with_raw_tab, full_with_raw_layout, _, _ = _add_prompt_tab(
            "full_with_raw", "Full + raw",
            "refinement_full_with_raw_system_prompt", "refinement_full_with_raw_user_prompt",
            "refinement_full_with_raw_system_prompt", "refinement_full_with_raw_user_prompt",
            "default_refinement_full_with_raw_system_prompt", "default_refinement_full_with_raw_user_prompt",
        )
        full_with_raw_options = QWidget()
        full_with_raw_options_layout = QHBoxLayout(full_with_raw_options)
        full_with_raw_options_layout.setContentsMargins(0, 0, 0, 0)
        full_with_raw_options_layout.setSpacing(8)
        raw_role_label = QLabel("Raw prompt role:")
        raw_role_label.setToolTip(
            "Choose the API message role used for the matching raw source HTML. "
            "Assistant is the default; System and User are also available."
        )
        full_with_raw_options_layout.addWidget(raw_role_label)
        self.refinement_full_with_raw_raw_role_combo = QComboBox()
        self.refinement_full_with_raw_raw_role_combo.addItem("Assistant", "assistant")
        self.refinement_full_with_raw_raw_role_combo.addItem("System", "system")
        self.refinement_full_with_raw_raw_role_combo.addItem("User", "user")
        raw_role = str(
            getattr(
                self,
                'refinement_full_with_raw_raw_role_var',
                self.config.get('refinement_full_with_raw_raw_role', 'assistant'),
            ) or 'assistant'
        ).strip().lower()
        if raw_role not in REFINEMENT_RAW_PROMPT_ROLES:
            raw_role = 'assistant'
