    # ==================================================================
    # Auth Account Arrow Switcher for numbered account slots
    # ==================================================================

    def _collect_auth_account_ids_from_pools(self):
        """Scan enabled key pools and return sets of account IDs per provider.

        Returns dict: {'authgpt': {0, 2}, 'authcd': {1}, 'authgem': {0, 3}}.
        """
        import re as _re
        result = {'authgpt': set(), 'authcd': set(), 'authgem': set()}
        patterns = {
            'authgpt': _re.compile(r'^authgpt(\d{0,4})/'),
            'authcd':  _re.compile(r'^authcd(\d{0,4})/'),
            'authgem': _re.compile(r'^authgem(?:-vertex)?(\d{0,4})/'),
        }
        try:
            pool_map = {
                'multi_api_keys': 'use_multi_api_keys',
                'fallback_keys': 'use_fallback_keys',
                'glossary_keys': 'use_glossary_keys',
                'glossary_refinement_keys': 'use_glossary_refinement_keys',
                'rolling_summary_keys': 'use_rolling_summary_keys',
                'truncation_retry_keys': 'use_truncation_retry_keys',
            }
            for pool_key, toggle_key in pool_map.items():
                if self.config.get(toggle_key, False):
                    for key_data in self.config.get(pool_key, []):
                        if isinstance(key_data, dict):
                            if not key_data.get('enabled', True):
                                continue
                            m = key_data.get('model', '')
                        else:
                            m = getattr(key_data, 'model', '')
                        m = str(m or '').strip().lower()
                        for provider, pat in patterns.items():
                            match = pat.match(m)
                            if match:
                                acct_id = int(match.group(1)) if match.group(1) else 0
                                result[provider].add(acct_id)
        except Exception:
            pass
        return result

    def _refresh_auth_account_arrows(self):
        """Update account-slot dropdown visibility and items for each auth provider.

        Collects all account IDs (from the primary model + key pools),
        stores them in ``_auth_account_ids``, and populates/shows the
        dropdown only when 2+ distinct account slots exist for a provider.
        """
        import re as _re

        pool_ids = self._collect_auth_account_ids_from_pools()

        # Also include the primary model's account ID
        model = str(getattr(self, 'model_var', '') or self.config.get('model', '') or '').strip().lower()
        _prov_patterns = {
            'authgpt': _re.compile(r'^authgpt(\d{0,4})/'),
            'authcd':  _re.compile(r'^authcd(\d{0,4})/'),
            'authgem': _re.compile(r'^authgem(?:-vertex)?(\d{0,4})/'),
        }
        for provider, pat in _prov_patterns.items():
            m = pat.match(model)
            if m:
                acct_id = int(m.group(1)) if m.group(1) else 0
                pool_ids[provider].add(acct_id)

        combo_map = {
            'authgpt': 'authgpt_acct_combo',
            'authcd':  'authcd_acct_combo',
            'authgem': 'authgem_acct_combo',
        }

        if not hasattr(self, '_auth_account_ids'):
            self._auth_account_ids = {'authgpt': [0], 'authcd': [0], 'authgem': [0]}
        if not hasattr(self, '_auth_account_idx'):
            self._auth_account_idx = {'authgpt': 0, 'authcd': 0, 'authgem': 0}

        for provider, acct_set in pool_ids.items():
            sorted_ids = sorted(acct_set) if acct_set else [0]
            self._auth_account_ids[provider] = sorted_ids

            # Clamp current index if accounts were removed
            cur_idx = self._auth_account_idx.get(provider, 0)
            if cur_idx >= len(sorted_ids):
                cur_idx = 0
            self._auth_account_idx[provider] = cur_idx

            # Show/hide and populate account dropdown
            combo_name = combo_map.get(provider)
            if combo_name and hasattr(self, combo_name):
                combo = getattr(self, combo_name)
                # Determine whether this provider is configured.  Do not key this
                # off QWidget.isVisible(): startup/login status refreshes can run
                # while the parent row is hidden or before the button has been
                # reshown, which made the account-slot dropdown disappear after a
                # successful login even though authgemN/ pool entries still exist.
                main_btn_name = f"{provider}_login_btn"
                provider_configured = bool(acct_set) and hasattr(self, main_btn_name)
                show_combo = len(sorted_ids) > 1 and provider_configured
                if show_combo:
                    # Repopulate items (block signals to avoid triggering change handler)
                    combo.blockSignals(True)
                    combo.clear()
                    for aid in sorted_ids:
                        combo.addItem(f"#{aid}", aid)
                    combo.setCurrentIndex(cur_idx)
                    combo.blockSignals(False)
                    combo.show()
                else:
                    combo.hide()

        # Update all visible main button labels to reflect current selection
        for provider in ('authgpt', 'authcd', 'authgem'):
            main_btn_name = f"{provider}_login_btn"
            if hasattr(self, main_btn_name) and getattr(self, main_btn_name).isVisible():
                update_fn = getattr(self, f'_update_{provider}_login_status', None)
                if update_fn:
                    if provider == 'authgem':
                        update_fn()  # authgem auto-detects needs_vertex
                    else:
                        update_fn()

    def _on_auth_acct_combo_changed(self, provider, index):
        """Handle account-slot dropdown selection change for *provider*.

        Updates the internal index, then refreshes the main login button.
        """
        if index < 0:
            return
        ids_list = self._auth_account_ids.get(provider, [0])
        if index >= len(ids_list):
            return
        self._auth_account_idx[provider] = index

        # Refresh the main button appearance
        update_fn = getattr(self, f'_update_{provider}_login_status', None)
        if update_fn:
            if provider == 'authgem':
                update_fn()  # auto-detects needs_vertex
            else:
                update_fn()

    # ==================================================================
    # AuthCD (Claude Login) – mirrors the AuthGPT pattern
    # ==================================================================


    def _get_authcd_account_id(self):
        """Return the numeric account ID for the AuthCD provider.

        If the arrow switcher is active (multiple account slots), returns
        the currently-selected slot.  Otherwise falls back to parsing the
        model prefix string.
        """
        # Arrow switcher override
        ids_list = getattr(self, '_auth_account_ids', {}).get('authcd', [])
        idx = getattr(self, '_auth_account_idx', {}).get('authcd', 0)
        if len(ids_list) > 1 and 0 <= idx < len(ids_list):
            return ids_list[idx]
        # Fallback: parse model string
        model = getattr(self, 'model_var', '') or self.config.get('model', '')
        import re as _re
        m = _re.match(r'^authcd(\d{1,4})/', model)
        if m:
            return int(m.group(1))
        return 0

    def _get_authcd_store_for_current_model(self):
        """Return the AuthCDTokenStore for the currently selected model's account slot."""
        from authcd_auth import get_store
        return get_store(self._get_authcd_account_id())

    def _update_authcd_login_status(self):
        """Update the AuthCD login button text based on current token state."""
        try:
            store = self._get_authcd_store_for_current_model()
            acct_id = self._get_authcd_account_id()
            acct_suffix = f" #{acct_id}" if acct_id else ""
            if store.has_tokens:
                info = store.account_info
                source = info.get('source', '')
                self.authcd_login_btn.setText(f"\u2705 Claude{acct_suffix}")
                tip = "Logged in"
                if source == 'claude_code':
                    tip = "Using Claude Code credentials"
                tip += "<br>Click to log out"
                self.authcd_login_btn.setToolTip(
                    "<qt><p style='white-space: normal; max-width: 36em; margin: 0;'>" +
                    tip + "</p></qt>"
                )
                self.authcd_login_btn.setStyleSheet(
                    "background-color: #28a745; color: white; font-weight: bold; "
                    "font-size: 10pt; padding: 4px 12px; border-radius: 4px;"
                )
            else:
                self.authcd_login_btn.setText(f"\ud83d\udd10 Claude{acct_suffix} Login")
                self.authcd_login_btn.setToolTip(
                    "<qt><p style='white-space: normal; max-width: 36em; margin: 0;'>"
                    "Log in with your Claude Pro/Max subscription via browser. "
                    "No API key needed.</p></qt>"
                )
                self.authcd_login_btn.setStyleSheet(
                    "background-color: #d97706; color: white; font-weight: bold; "
                    "font-size: 10pt; padding: 4px 12px; border-radius: 4px;"
                )
        except ImportError:
            self.authcd_login_btn.setText("\ud83d\udd10 Claude Login (unavailable)")
            self.authcd_login_btn.setEnabled(False)

    def _authcd_login_clicked(self):
        """Handle Claude Login – uses Claude Code CLI credentials."""
        try:
            store = self._get_authcd_store_for_current_model()
        except ImportError:
            QMessageBox.critical(
                self, "AuthCD Unavailable",
                "The authcd module is not installed. Please check your installation."
            )
            return

        acct_id = self._get_authcd_account_id()
        acct_suffix = f" #{acct_id}" if acct_id else ""

        if store.has_tokens:
            reply = QMessageBox.question(
                self, "Claude Account",
                f"Currently logged in{acct_suffix}.\n\nDo you want to log out?",
                QMessageBox.Yes | QMessageBox.No
            )
            if reply == QMessageBox.Yes:
                store.clear_tokens()
                store._tokens = None
                # Also logout from Claude Code CLI
                import shutil as _shutil, subprocess as _sp
                _claude = _shutil.which("claude")
                if _claude:
                    try:
                        _sp.run(
                            [_claude, "auth", "logout"],
                            timeout=10, capture_output=True,
                            creationflags=getattr(_sp, "CREATE_NO_WINDOW", 0),
                        )
                    except Exception:
                        pass
                # Fallback: also remove credentials file directly
                import os as _os
                _cc_creds = _os.path.join(_os.path.expanduser("~"), ".claude", ".credentials.json")
                if _os.path.isfile(_cc_creds):
                    try:
                        _os.remove(_cc_creds)
                    except OSError:
                        pass
                self._refresh_auth_account_arrows()
                self.append_log(f"\ud83d\udd13 Claude{acct_suffix}: Logged out")
            return

        # --- Strategy 1: Try loading existing Claude Code credentials ---
        from authcd_auth import _load_claude_code_credentials
        if not getattr(store, '_cleared', False):
            creds = _load_claude_code_credentials()
            if creds:
                store.save_tokens(creds)
                self._refresh_auth_account_arrows()
                self.append_log(f"\u2705 Claude{acct_suffix}: Loaded credentials from Claude Code")
                return

        # --- Strategy 2: Run 'claude auth login' via CLI in a visible terminal ---
        import shutil
        claude_bin = shutil.which("claude")
        if not claude_bin:
            dlg = QDialog(self)
            dlg.setWindowTitle("Claude Code Required")
            dlg.setMinimumWidth(430)
            lay = QVBoxLayout(dlg)
            lay.addWidget(QLabel("Claude Code CLI is required for login.\nInstall it with:"))
            cmd_edit = QLineEdit("npm install -g @anthropic-ai/claude-code")
            cmd_edit.setReadOnly(True)
            cmd_edit.selectAll()
            lay.addWidget(cmd_edit)
            lay.addWidget(QLabel("After installing, click this button again."))
            btn_row = QHBoxLayout()
            copy_btn = QPushButton("Copy Command")
            copy_btn.clicked.connect(lambda: (
                QApplication.clipboard().setText(cmd_edit.text()),
                copy_btn.setText("\u2705 Copied!"),
            ))
            ok_btn = QPushButton("OK")
            ok_btn.clicked.connect(dlg.accept)
            btn_row.addWidget(copy_btn)
            btn_row.addWidget(ok_btn)
            lay.addLayout(btn_row)
            dlg.exec()
            return

        self.authcd_login_btn.setText("\u23f3 Logging in\u2026")
        self.authcd_login_btn.setEnabled(False)
        self.append_log(f"\ud83d\udd10 Claude{acct_suffix}: Opening browser for Claude login\u2026")

        def _do_claude_login():
            import subprocess, time as _time, os
            try:
                # Run 'claude auth login' in a VISIBLE console window
                if os.name == 'nt':
                    proc = subprocess.Popen(
                        [claude_bin, "auth", "login"],
                        creationflags=subprocess.CREATE_NEW_CONSOLE,
                    )
                else:
                    proc = subprocess.Popen(
                        [claude_bin, "auth", "login"],
                    )
                proc.wait(timeout=180)

                # Poll for credentials file
                cred_path = os.path.join(os.path.expanduser("~"), ".claude", ".credentials.json")
                for _ in range(10):
                    _time.sleep(1)
                    if os.path.isfile(cred_path):
                        break

                creds = _load_claude_code_credentials()
                if creds:
                    store.save_tokens(creds)
                    QMetaObject.invokeMethod(
                        self, "_authcd_login_finished",
                        Qt.QueuedConnection
                    )
                else:
                    self._authcd_login_error = (
                        "Claude login completed but no credentials found.\n"
                        "Try running 'claude auth login' manually in a terminal."
                    )
                    QMetaObject.invokeMethod(
                        self, "_authcd_login_failed",
                        Qt.QueuedConnection
                    )
            except subprocess.TimeoutExpired:
                proc.kill()
                self._authcd_login_error = "Login timed out (3 min). Try 'claude auth login' in a terminal."
                QMetaObject.invokeMethod(
                    self, "_authcd_login_failed",
                    Qt.QueuedConnection
                )
            except Exception as exc:
                self._authcd_login_error = str(exc)
                QMetaObject.invokeMethod(
                    self, "_authcd_login_failed",
                    Qt.QueuedConnection
                )

        t = threading.Thread(target=_do_claude_login, daemon=True)
        t.start()


    @Slot()
    def _authcd_login_status_changed(self):
        """Called (thread-safe) whenever AuthCD tokens are saved or cleared."""
        self._refresh_auth_account_arrows()

    @Slot()
    def _authcd_login_finished(self):
        """Called on GUI thread after successful AuthCD login."""
        self.authcd_login_btn.setEnabled(True)
        self._refresh_auth_account_arrows()
        acct_id = self._get_authcd_account_id()
        acct_suffix = f" #{acct_id}" if acct_id else ""
        self.append_log(f"\u2705 Claude{acct_suffix}: Logged in")

    @Slot()
    def _authcd_login_failed(self):
        """Called on GUI thread after AuthCD login failure."""
        self.authcd_login_btn.setEnabled(True)
        self._refresh_auth_account_arrows()
        err = getattr(self, '_authcd_login_error', 'Unknown error')
        self.append_log(f"\u274c Claude login failed: {err}")
        QMessageBox.warning(self, "Login Failed", f"Claude login failed:\n{err}")

    def _get_authgpt_account_id(self):
        """Return the numeric account ID for the AuthGPT provider.

        If the arrow switcher is active (multiple account slots), returns
        the currently-selected slot.  Otherwise falls back to parsing the
        model prefix string (``authgpt/`` → 0, ``authgpt2/`` → 2).
        """
        # Arrow switcher override
        ids_list = getattr(self, '_auth_account_ids', {}).get('authgpt', [])
        idx = getattr(self, '_auth_account_idx', {}).get('authgpt', 0)
        if len(ids_list) > 1 and 0 <= idx < len(ids_list):
            return ids_list[idx]
        # Fallback: parse model string
        model = getattr(self, 'model_var', '') or self.config.get('model', '')
        import re as _re
        m = _re.match(r'^authgpt(\d{1,4})/', model)
        if m:
            return int(m.group(1))
        return 0

    def _get_authgpt_store_for_current_model(self):
        """Return the AuthGPTTokenStore for the currently selected model's account slot."""
        from authgpt_auth import get_store
        return get_store(self._get_authgpt_account_id())

