    # ==================================================================
    # AuthGem (Gemini Login) – mirrors the AuthGPT pattern
    # ==================================================================

    def _get_authgem_account_id(self) -> int:
        """Return the numeric account ID for the AuthGem provider.

        If the arrow switcher is active (multiple account slots), returns
        the currently-selected slot.  Otherwise falls back to parsing the
        model prefix string.
        """
        # Arrow switcher override
        ids_list = getattr(self, '_auth_account_ids', {}).get('authgem', [])
        idx = getattr(self, '_auth_account_idx', {}).get('authgem', 0)
        if len(ids_list) > 1 and 0 <= idx < len(ids_list):
            return ids_list[idx]
        # Fallback: parse model string
        import re
        m = re.match(r'^authgem(?:-vertex)?(\d{1,4})/', self.model_var)
        return int(m.group(1)) if m else 0

    def _get_authgem_store_for_current_model(self):
        """Return the AuthGemTokenStore for the current model's account slot."""
        from authgem_auth import get_store
        return get_store(self._get_authgem_account_id())

    def _update_authgem_login_status(self, needs_vertex=None):
        """Update the AuthGem login button text based on current token state.
        
        Args:
            needs_vertex: If True, show GCP project dropdown (only for authgem-vertex/).
                          If None, auto-detect from current model.
        """
        import re as _re
        # Auto-detect if not explicitly provided
        if needs_vertex is None:
            needs_vertex = bool(_re.match(r'^authgem-vertex\d{0,4}/', self.model_var)) or self._has_authgem_vertex_in_key_pools()
        
        account_id = self._get_authgem_account_id()
        acct_suffix = f" #{account_id}" if account_id else ""
        
        try:
            store = self._get_authgem_store_for_current_model()
            if store.has_tokens:
                info = store.account_info
                email = info.get('email', '')
                name = info.get('name', '')
                self.authgem_login_btn.setText(f"✅ Gemini{acct_suffix}")
                # Put email/name in tooltip instead of button text
                tip_parts = []
                if email:
                    tip_parts.append(f"Account: {email}")
                if name:
                    tip_parts.append(f"Name: {name}")
                tip_parts.append("Click to log out")
                self.authgem_login_btn.setToolTip(
                    "<qt><p style='white-space: normal; max-width: 36em; margin: 0;'>" +
                    "<br>".join(tip_parts) + "</p></qt>"
                )
                self.authgem_login_btn.setStyleSheet(
                    "background-color: #28a745; color: white; font-weight: bold; "
                    "font-size: 10pt; padding: 4px 12px; border-radius: 4px;"
                )
                # Populate projects ONLY for authgem-vertex/ (Vertex AI needs GCP project)
                # authgem/ uses AI Studio which doesn't require a GCP project
                if hasattr(self, 'authgem_project_combo'):
                    if needs_vertex:
                        if self.authgem_project_combo.count() == 0:
                            self._fetch_authgem_projects()
                            # Don't hide — _authgem_projects_loaded will show it
                        elif self.authgem_login_btn.isVisible():
                            self.authgem_project_combo.show()
                            self._reposition_authgem_project_combo()
                    else:
                        self.authgem_project_combo.hide()
            else:
                self.authgem_login_btn.setText(f"🔐 Gemini{acct_suffix} Login")
                self.authgem_login_btn.setToolTip(
                    "<qt><p style='white-space: normal; max-width: 36em; margin: 0;'>"
                    "Log in with your Google account via browser. "
                    "No API key needed.</p></qt>"
                )
                self.authgem_login_btn.setStyleSheet(
                    "background-color: #4385f4; color: white; font-weight: bold; "
                    "font-size: 10pt; padding: 4px 12px; border-radius: 4px;"
                )
                if hasattr(self, 'authgem_project_combo'):
                    self.authgem_project_combo.hide()
        except ImportError:
            self.authgem_login_btn.setText(f"🔐 Gemini{acct_suffix} Login (unavailable)")
            self.authgem_login_btn.setEnabled(False)

    def _fetch_authgem_projects(self):
        """Fetch GCP projects in a background thread, check billing, populate dropdown."""
        # Guard against duplicate concurrent fetches (e.g. on_model_change called twice)
        if getattr(self, '_authgem_fetching_projects', False):
            return
        self._authgem_fetching_projects = True
        import threading
        def _worker():
            try:
                import requests as _req
                store = self._get_authgem_store_for_current_model()
                token = store.get_valid_access_token(auto_login=False)
                headers = {"Authorization": f"Bearer {token}"}
                
                # 1. List active projects (fast)
                resp = _req.get(
                    "https://cloudresourcemanager.googleapis.com/v1/projects",
                    headers=headers,
                    params={"filter": "lifecycleState:ACTIVE", "pageSize": 50},
                    timeout=15,
                )
                if not resp.ok:
                    return
                projects = resp.json().get("projects", [])
                if not projects:
                    return
                
                all_pids = [p.get("projectId", "") for p in projects if p.get("projectId")]
                
                # Phase 1: Show all projects immediately as unknown (❔)
                # This ensures the dropdown appears fast
                self._authgem_billed_projects = []
                self._authgem_unbilled_projects = []
                self._authgem_unknown_projects = list(all_pids)
                QMetaObject.invokeMethod(
                    self, "_authgem_projects_loaded",
                    Qt.QueuedConnection,
                )
                
                # Phase 2: Check billing in parallel, then update
                from concurrent.futures import ThreadPoolExecutor, as_completed
                
                def _check_billing(pid):
                    """Return (pid, 'billed'|'unbilled'|'unknown')."""
                    try:
                        # Try Cloud Billing API first (fast, works with ADC client)
                        br = _req.get(
                            f"https://cloudbilling.googleapis.com/v1/projects/{pid}/billingInfo",
                            headers=headers, timeout=8,
                        )
                        if br.ok:
                            if br.json().get("billingEnabled", False):
                                return (pid, "billed")
                            return (pid, "unbilled")
                        # Billing API returned 403 — probe Vertex AI directly
                        vr = _req.get(
                            f"https://us-central1-aiplatform.googleapis.com/v1/projects/{pid}/locations/us-central1",
                            headers=headers, timeout=8,
                        )
                        if vr.ok:
                            return (pid, "billed")
                        return (pid, "unbilled")
                    except Exception:
                        return (pid, "unknown")
                
                billed = []
                unbilled = []
                unknown = []
                with ThreadPoolExecutor(max_workers=min(6, len(all_pids))) as pool:
                    futures = {pool.submit(_check_billing, pid): pid for pid in all_pids}
                    for future in as_completed(futures):
                        pid, status = future.result()
                        if status == "billed":
                            billed.append(pid)
                        elif status == "unbilled":
                            unbilled.append(pid)
                        else:
                            unknown.append(pid)
                
                # Phase 2 complete: Update dropdown with billing info
                self._authgem_billed_projects = billed
                self._authgem_unbilled_projects = unbilled
                self._authgem_unknown_projects = unknown
                QMetaObject.invokeMethod(
                    self, "_authgem_projects_loaded",
                    Qt.QueuedConnection,
                )
            except Exception as exc:
                import logging
                logging.getLogger(__name__).debug("Failed to fetch GCP projects: %s", exc)
            finally:
                self._authgem_fetching_projects = False  # always clear guard
        threading.Thread(target=_worker, daemon=True).start()

    @Slot()
    def _authgem_projects_loaded(self):
        """Populate the project dropdown (called on GUI thread)."""
        if not hasattr(self, 'authgem_project_combo'):
            return
        billed = getattr(self, '_authgem_billed_projects', [])
        unbilled = getattr(self, '_authgem_unbilled_projects', [])
        unknown = getattr(self, '_authgem_unknown_projects', [])
        if not billed and not unbilled and not unknown:
            return
        combo = self.authgem_project_combo
        combo.blockSignals(True)
        combo.clear()
        # Add billed projects first (confirmed usable)
        for pid in billed:
            combo.addItem(f"✅ {pid}", pid)
        # Add unknown projects (billing API inaccessible — still selectable)
        for pid in unknown:
            combo.addItem(f"❔ {pid}", pid)
        # Add unbilled projects last (confirmed no billing)
        for pid in unbilled:
            combo.addItem(f"⚠️ {pid} (no billing)", pid)
        
        # Try to restore previously selected project
        saved = self.config.get('authgem_project', '')
        selected_idx = -1
        if saved:
            # Only restore saved project if it's NOT known-unbilled;
            # prefer a billed project over a previously-saved unbilled one.
            if saved not in unbilled:
                selected_idx = combo.findData(saved)
        # If no saved or saved not found/unbilled, pick first billed; if none, first unknown
        if selected_idx < 0 and billed:
            selected_idx = 0
        elif selected_idx < 0 and unknown:
            selected_idx = len(billed)  # first unknown item
        if selected_idx >= 0:
            combo.setCurrentIndex(selected_idx)
        combo.blockSignals(False)
        # Apply the selection
        if combo.count() > 0:
            self._authgem_project_changed(combo.currentIndex())
            combo.show()
            self._reposition_authgem_project_combo()
        else:
            combo.hide()
        # Log billing results only when billing detection is complete
        # (skip phase 1 where everything is unknown — that's just the fast preview)
        has_billing_results = bool(billed or unbilled)
        if has_billing_results:
            if billed:
                self.append_log(f"📁 Found {len(billed)} GCP project(s) with billing enabled")
            if not billed:
                self.append_log("⚠️ No GCP projects with billing found — Vertex AI won't work")

    def _authgem_project_changed(self, index):
        """Called when user picks a different GCP project."""
        if not hasattr(self, 'authgem_project_combo'):
            return
        combo = self.authgem_project_combo
        project_id = combo.itemData(index)
        if not project_id:
            return
        # Save to config + persist
        self.config['authgem_project'] = project_id
        try:
            self._save_config()
        except Exception:
            pass
        # Push to authgem module so API calls use this project
        try:
            import authgem_auth
            _acct = self._get_authgem_account_id()
            authgem_auth._cached_project_id[_acct] = project_id
            authgem_auth._project_set_by_gui[_acct] = True
            import os
            os.environ['GOOGLE_CLOUD_PROJECT'] = project_id
        except Exception:
            pass
        self.append_log(f"📁 AuthGem project set: {project_id}")

    def _reposition_authgem_project_combo(self):
        """Move project dropdown to its own grid row if the button row is crowded.

        When both the AuthGPT *and* AuthGem login buttons are visible the
        horizontal space is tight, so the project combo moves to a dedicated
        row below the model row.  Otherwise it stays inline with the buttons.
        """
        if not hasattr(self, 'authgem_project_combo'):
            return
        combo = self.authgem_project_combo

        # Don't touch hidden combos
        if combo.isHidden() or combo.count() == 0:
            return

        both_visible = (
            hasattr(self, 'authgpt_login_btn') and self.authgpt_login_btn.isVisible()
            and hasattr(self, 'authgem_login_btn') and self.authgem_login_btn.isVisible()
        )

        already_own_row = getattr(self, '_authgem_combo_in_own_row', False)

        if both_visible and not already_own_row:
            # Remove from the HBox button row
            parent_layout = combo.parentWidget().layout() if combo.parentWidget() else None
            if parent_layout:
                parent_layout.removeWidget(combo)
            # Insert into the profile-buttons row (right of Delete Profile, before stretch)
            if hasattr(self, '_profile_buttons_layout'):
                # Insert before the stretch (last item)
                idx = self._profile_buttons_layout.count() - 1  # before addStretch
                if idx < 0:
                    idx = 0
                self._profile_buttons_layout.insertWidget(idx, combo)
            self._authgem_combo_in_own_row = True
        elif not both_visible and already_own_row:
            # Move back into the HBox button row
            if hasattr(self, '_profile_buttons_layout'):
                self._profile_buttons_layout.removeWidget(combo)
            # Find the button container layout
            if hasattr(self, 'authgem_login_btn'):
                parent_layout = self.authgem_login_btn.parentWidget().layout()
                if parent_layout:
                    parent_layout.addWidget(combo)
            self._authgem_combo_in_own_row = False

    def _authgem_login_clicked(self):
        """Handle Gemini Login button click – run OAuth flow in background thread."""
        try:
            store = self._get_authgem_store_for_current_model()
        except ImportError:
            QMessageBox.critical(
                self, "AuthGem Unavailable",
                "The authgem module is not installed. Please check your installation."
            )
            return

        account_id = self._get_authgem_account_id()
        acct_suffix = f" #{account_id}" if account_id else ""

        # If already logged in, offer to log out
        if store.has_tokens:
            info = store.account_info
            email = info.get('email', 'unknown')
            reply = QMessageBox.question(
                self, f"Gemini Account{acct_suffix}",
                f"Account{acct_suffix} logged in as: {email}\n\nDo you want to log out?",
                QMessageBox.Yes | QMessageBox.No
            )
            if reply == QMessageBox.Yes:
                store.clear_tokens()
                # Clear the project dropdown so it re-fetches for the next account
                if hasattr(self, 'authgem_project_combo'):
                    self.authgem_project_combo.clear()
                    self.authgem_project_combo.hide()
                self._refresh_auth_account_arrows()
                self.append_log(f"🔓 Gemini{acct_suffix}: Logged out")
            return

        # Start login in background thread
        self.authgem_login_btn.setText(f"⏳ Logging in{acct_suffix}…")
        self.authgem_login_btn.setEnabled(False)
        self.append_log(f"🔐 Gemini{acct_suffix}: Opening browser for login…")

        def _do_login():
            try:
                from authgem_auth import run_oauth_flow
                tokens = run_oauth_flow()
                store.save_tokens(tokens)
                QMetaObject.invokeMethod(
                    self, "_authgem_login_finished",
                    Qt.QueuedConnection
                )
            except Exception as exc:
                self._authgem_login_error = str(exc)
                QMetaObject.invokeMethod(
                    self, "_authgem_login_failed",
                    Qt.QueuedConnection
                )

        t = threading.Thread(target=_do_login, daemon=True)
        t.start()

    @Slot()
    def _authgem_login_status_changed(self):
        """Called (thread-safe) whenever AuthGem tokens are saved or cleared."""
