    def _show_profile_context_menu(self, position):
        """Show context menu for profile management."""
        from PySide6.QtWidgets import QMenu, QApplication

        menu = QMenu(self.profile_menu)

        # Resolve the combo's internal line edit for copy/paste operations
        line_edit = self.profile_menu.lineEdit()
        clipboard = QApplication.clipboard()

        # Cut
        cut_action = menu.addAction("✂️ Cut")
        cut_action.setShortcut("Ctrl+X")
        if line_edit is None or line_edit.isReadOnly() or not line_edit.hasSelectedText():
            cut_action.setEnabled(False)

        # Copy
        copy_action = menu.addAction("📋 Copy")
        copy_action.setShortcut("Ctrl+C")
        if line_edit is None or not line_edit.hasSelectedText():
            # Fall back to copying the full current text if nothing is selected
            if not self.profile_menu.currentText():
                copy_action.setEnabled(False)

        # Paste
        paste_action = menu.addAction("📥 Paste")
        paste_action.setShortcut("Ctrl+V")
        if line_edit is None or line_edit.isReadOnly() or not clipboard.text():
            paste_action.setEnabled(False)

        menu.addSeparator()
        manage_action = menu.addAction("⚙️ Manage Profiles...")

        # Show menu at cursor position
        action = menu.exec(self.profile_menu.mapToGlobal(position))

        if action == manage_action:
            self._open_profile_manager()
        elif action == cut_action and line_edit is not None:
            line_edit.cut()
        elif action == copy_action:
            if line_edit is not None and line_edit.hasSelectedText():
                line_edit.copy()
            else:
                clipboard.setText(self.profile_menu.currentText())
        elif action == paste_action and line_edit is not None:
            line_edit.paste()
    
    def _quick_new_profile(self):
        """Create a new empty profile with auto-incrementing name."""
        existing = set(self.prompt_profiles.keys())
        if hasattr(self, 'profile_menu'):
            for i in range(self.profile_menu.count()):
                existing.add(self.profile_menu.itemText(i))
        
        n = 1
        while f"New Profile #{n}" in existing:
            n += 1
        name = f"New Profile #{n}"
        
        self.prompt_profiles[name] = ""
        self.config['prompt_profiles'] = self.prompt_profiles
        self.config['active_profile'] = name
        
        if hasattr(self, 'profile_menu'):
            self.profile_menu.addItem(name)
            self.profile_menu.setCurrentText(name)
        
        if hasattr(self, 'prompt_text'):
            self.prompt_text.setPlainText("")
        
        self.profile_var = name
        if not hasattr(self, '_original_profile_content'):
            self._original_profile_content = {}
        self._original_profile_content[name] = ""
        self._active_profile_for_autosave = name
        
        if hasattr(self, 'save_profiles'):
            self.save_profiles()
        
        if hasattr(self, 'append_log'):
            self.append_log(f"✅ Created new profile: '{name}'")
        self._update_profile_delete_button_label(name)
    
    def _open_profile_manager(self):
        """Open a dialog for managing profile order with drag-and-drop."""
        from PySide6.QtWidgets import QDialog, QVBoxLayout, QHBoxLayout, QListWidget, QPushButton, QLabel, QApplication
        from PySide6.QtCore import Qt
        from PySide6.QtGui import QIcon

        # Reuse existing window if it's already open
        try:
            existing = getattr(self, '_profile_manager_dialog', None)
            if existing is not None and existing.isVisible():
                existing.raise_()
                existing.activateWindow()
                return
        except Exception:
            pass
        
        dialog = QDialog(self)
        dialog.setWindowTitle("Manage Profiles")
        dialog.setModal(False)
        dialog.setWindowFlags(dialog.windowFlags() | Qt.WindowStaysOnTopHint)
        dialog.setAttribute(Qt.WA_DeleteOnClose, True)
        self._profile_manager_dialog = dialog
        dialog.finished.connect(lambda *_: setattr(self, '_profile_manager_dialog', None))
        
        # Use screen ratios for sizing
        screen = QApplication.primaryScreen().availableGeometry()
        dialog_width = int(screen.width() * 0.22)  # 22% of screen width
        dialog_height = int(screen.height() * 0.40)  # 40% of screen height
        dialog.setMinimumWidth(dialog_width)
        dialog.setMinimumHeight(dialog_height)
        dialog.resize(dialog_width, dialog_height)
        
        # Set icon
        try:
            icon_path = os.path.join(self.base_dir, 'Halgakos.ico')
            if os.path.exists(icon_path):
                dialog.setWindowIcon(QIcon(icon_path))
        except:
            pass
        
        layout = QVBoxLayout(dialog)
        
        # Instructions
        instructions = QLabel("Drag and drop profiles to reorder them (Ctrl+Click for multiple):")
        instructions.setStyleSheet("font-weight: bold; margin-bottom: 6px;")
        layout.addWidget(instructions)

        # Info / naming conventions
        info = QLabel(
            "<span style='font-weight:600;'>Profile name tags</span> <span style='color:#94a3b8;'>(case-insensitive)</span>:<br>"
            "• <span style='font-family: Consolas, \"Courier New\", monospace; font-weight:700; color:#e2e8f0;'>_beautifulsoup</span>: BeautifulSoup extraction<br>"
            "• <span style='font-family: Consolas, \"Courier New\", monospace; font-weight:700; color:#e2e8f0;'>_html2text</span>: html2text extraction<br><br>"
            "Built-in profiles are protected <span style='color:#94a3b8;'>(can’t be deleted)</span> and will restore themselves on restart."
        )
        info.setWordWrap(True)
        # Make text selectable so tags can be copy/pasted
        info.setTextInteractionFlags(Qt.TextSelectableByMouse | Qt.TextSelectableByKeyboard)
        info.setCursor(Qt.IBeamCursor)
        info.setStyleSheet("color: #cbd5e1; font-size: 9pt; margin-bottom: 10px;")
        layout.addWidget(info)
        
        # Horizontal layout for list and buttons
        content_layout = QHBoxLayout()
        
        # List widget with drag-and-drop and multi-selection
        list_widget = QListWidget()
        list_widget.setDragDropMode(QListWidget.InternalMove)
        list_widget.setSelectionMode(QListWidget.ExtendedSelection)  # Enable multi-selection
        list_widget.addItems(list(self.prompt_profiles.keys()))
        
        # Select current profile
        current_profile = self.profile_menu.currentText()
        for i in range(list_widget.count()):
            if list_widget.item(i).text() == current_profile:
                list_widget.setCurrentRow(i)
                break
        
        # History for undo/redo
        history_stack = [self._get_list_order(list_widget)]
        history_index = [0]  # Use list to make it mutable in nested functions
        
        def save_state():
            # Remove any redo states
            history_stack[history_index[0] + 1:] = []
            # Add current state
            current_order = self._get_list_order(list_widget)
            # Only save if order actually changed
            if history_stack[history_index[0]] != current_order:
                history_stack.append(current_order)
                history_index[0] = len(history_stack) - 1
                update_undo_redo_buttons()
        
        def update_undo_redo_buttons():
            undo_btn.setEnabled(history_index[0] > 0)
            redo_btn.setEnabled(history_index[0] < len(history_stack) - 1)
        
        # Connect model changed signal to track drag-and-drop reordering
        list_widget.model().rowsMoved.connect(lambda: save_state())
        
        content_layout.addWidget(list_widget)
        
        # Vertical layout for reorder buttons
        button_column = QVBoxLayout()
        
        # Undo button
        undo_btn = QPushButton("↶ Undo")
        undo_btn.setToolTip("Undo last change")
        undo_btn.setEnabled(False)
        def do_undo():
            if history_index[0] > 0:
                history_index[0] -= 1
                self._restore_list_order(list_widget, history_stack[history_index[0]])
                update_undo_redo_buttons()
        undo_btn.clicked.connect(do_undo)
        button_column.addWidget(undo_btn)
        
        # Redo button
        redo_btn = QPushButton("↷ Redo")
        redo_btn.setToolTip("Redo last undone change")
        redo_btn.setEnabled(False)
        def do_redo():
            if history_index[0] < len(history_stack) - 1:
                history_index[0] += 1
                self._restore_list_order(list_widget, history_stack[history_index[0]])
                update_undo_redo_buttons()
        redo_btn.clicked.connect(do_redo)
        button_column.addWidget(redo_btn)
        
        button_column.addSpacing(10)
        
        # Move to Top button
        move_top_btn = QPushButton("⇈ Top")
        move_top_btn.setToolTip("Move selected profile(s) to top")
        def move_top():
            self._move_profile_in_list(list_widget, 'top')
            save_state()
        move_top_btn.clicked.connect(move_top)
        button_column.addWidget(move_top_btn)
        
        # Move Up button
        move_up_btn = QPushButton("↑ Up")
        move_up_btn.setToolTip("Move selected profile(s) up")
        def move_up():
            self._move_profile_in_list(list_widget, 'up')
            save_state()
        move_up_btn.clicked.connect(move_up)
        button_column.addWidget(move_up_btn)
        
        # Move Down button
        move_down_btn = QPushButton("↓ Down")
        move_down_btn.setToolTip("Move selected profile(s) down")
        def move_down():
            self._move_profile_in_list(list_widget, 'down')
            save_state()
        move_down_btn.clicked.connect(move_down)
        button_column.addWidget(move_down_btn)
        
        # Move to Bottom button
        move_bottom_btn = QPushButton("⇊ Bottom")
        move_bottom_btn.setToolTip("Move selected profile(s) to bottom")
        def move_bottom():
            self._move_profile_in_list(list_widget, 'bottom')
            save_state()
        move_bottom_btn.clicked.connect(move_bottom)
        button_column.addWidget(move_bottom_btn)
        
        button_column.addSpacing(10)
        
        # Delete button
        delete_btn = QPushButton("❌ Delete")
        delete_btn.setToolTip("Delete selected profile(s)")
        delete_btn.setStyleSheet("background-color: #dc3545; color: white; font-weight: bold;")
        def delete_profiles():
            selected_items = list_widget.selectedItems()
            if not selected_items:
                return

            from PySide6.QtWidgets import QMessageBox

            try:
                protected_profiles = set(self._get_protected_prompt_profiles())
            except Exception:
                protected_profiles = {
                    "Universal",
                    "Refinement",
                    "Korean_BeautifulSoup",
                    "Japanese_BeautifulSoup",
                    "Chinese_BeautifulSoup",
                    "Korean_html2text",
                    "Japanese_html2text",
                    "Chinese_html2text",
                }

            profile_names = [item.text() for item in selected_items]
            protected_selected = [n for n in profile_names if n in protected_profiles]
            deletable_selected = [n for n in profile_names if n not in protected_profiles]

            # Protected profiles: treat "Delete" as "Reset to defaults".
            if protected_selected:
                msg = (
                    "Reset the selected built-in profile(s) to the latest default prompts?\n\n"
                    + "\n".join(protected_selected)
                )
                reply = QMessageBox.question(dialog, "Reset Built-in Profiles", msg, QMessageBox.Yes | QMessageBox.No)
                if reply == QMessageBox.Yes:
                    for n in protected_selected:
                        try:
                            self._reset_prompt_profile_to_default(n)
                        except Exception:
                            pass
                    # Persist immediately so reset survives restart
                    try:
                        self.save_profiles()
                    except Exception:
                        pass

            # Custom profiles: still deletable from the list/order editor.
            if not deletable_selected:
                return

            msg = f"Delete {len(deletable_selected)} profile(s)?\n\n" + "\n".join(deletable_selected)
            reply = QMessageBox.question(dialog, "Confirm Delete", msg, QMessageBox.Yes | QMessageBox.No)
            if reply == QMessageBox.Yes:
                for item in selected_items:
                    if item.text() in protected_profiles:
                        continue
                    list_widget.takeItem(list_widget.row(item))
                save_state()
        delete_btn.clicked.connect(delete_profiles)
        button_column.addWidget(delete_btn)
        
        button_column.addStretch()
        
        content_layout.addLayout(button_column)
        layout.addLayout(content_layout)
        
        # Button layout
        button_layout = QHBoxLayout()
        button_layout.addStretch()
        
        # Cancel button
        cancel_btn = QPushButton("Cancel")
        cancel_btn.clicked.connect(dialog.reject)
        button_layout.addWidget(cancel_btn)
        
        # Save button
        save_btn = QPushButton("Save Order")
        save_btn.setStyleSheet("background-color: #28a745; color: white; font-weight: bold;")
        save_btn.clicked.connect(lambda: self._save_profile_order(list_widget, dialog))
        button_layout.addWidget(save_btn)
        
        layout.addLayout(button_layout)

        dialog.show()
        dialog.raise_()
        dialog.activateWindow()
    
    def _get_list_order(self, list_widget):
        """Get the current order of items in the list."""
        return [list_widget.item(i).text() for i in range(list_widget.count())]
    
    def _restore_list_order(self, list_widget, order):
        """Restore a specific order to the list."""
        list_widget.clear()
        list_widget.addItems(order)
    
    def _move_profile_in_list(self, list_widget, direction):
        """Move the selected profile(s) in the list."""
        selected_items = list_widget.selectedItems()
        if not selected_items:
            return
        
        # Get selected rows and sort them
        selected_rows = sorted([list_widget.row(item) for item in selected_items])
        
        if direction == 'up':
            if selected_rows[0] == 0:
                return  # Already at top
            for row in selected_rows:
                item = list_widget.takeItem(row)
                list_widget.insertItem(row - 1, item)
                item.setSelected(True)
        
        elif direction == 'down':
            if selected_rows[-1] == list_widget.count() - 1:
                return  # Already at bottom
            for row in reversed(selected_rows):
                item = list_widget.takeItem(row)
                list_widget.insertItem(row + 1, item)
                item.setSelected(True)
        
        elif direction == 'top':
            if selected_rows[0] == 0:
                return  # Already at top
            items = [list_widget.takeItem(row) for row in reversed(selected_rows)]
            for i, item in enumerate(reversed(items)):
                list_widget.insertItem(i, item)
                item.setSelected(True)
        
        elif direction == 'bottom':
            if selected_rows[-1] == list_widget.count() - 1:
                return  # Already at bottom
            items = [list_widget.takeItem(row) for row in reversed(selected_rows)]
            for item in reversed(items):
                list_widget.addItem(item)
                item.setSelected(True)
    
    def _save_profile_order(self, list_widget, dialog):
        """Save the new profile order from the list widget."""
        # Get new order from list widget
        new_order = []
        for i in range(list_widget.count()):
            new_order.append(list_widget.item(i).text())
        
        # Reorder profiles dictionary
        new_profiles = {}
        for name in new_order:
            new_profiles[name] = self.prompt_profiles[name]
        
        # Update profiles
        self.prompt_profiles = new_profiles
        self.config['prompt_profiles'] = new_profiles
        
        # Get currently selected profile before refresh
        current_profile = self.profile_menu.currentText()
        
        # Refresh combobox
        self.profile_menu.blockSignals(True)
        self.profile_menu.clear()
        self.profile_menu.addItems(list(new_profiles.keys()))
        self.profile_menu.setCurrentText(current_profile)
        self.profile_menu.blockSignals(False)
        
        # Save changes
        self.save_profiles()
        
        self.append_log("✓ Profile order updated")
        dialog.accept()
    
    def _show_model_context_menu(self, position):
        """Show context menu for model management."""
        from PySide6.QtWidgets import QMenu, QApplication

        menu = QMenu(self.model_combo)

        # Resolve the combo's internal line edit for copy/paste operations
        line_edit = self.model_combo.lineEdit()
        clipboard = QApplication.clipboard()

        # Cut
        cut_action = menu.addAction("✂️ Cut")
        cut_action.setShortcut("Ctrl+X")
        if line_edit is None or line_edit.isReadOnly() or not line_edit.hasSelectedText():
            cut_action.setEnabled(False)

        # Copy
        copy_action = menu.addAction("📋 Copy")
        copy_action.setShortcut("Ctrl+C")
        if line_edit is None or not line_edit.hasSelectedText():
            # Fall back to copying the full current text if nothing is selected
            if not self.model_combo.currentText():
                copy_action.setEnabled(False)

        # Paste
        paste_action = menu.addAction("📥 Paste")
        paste_action.setShortcut("Ctrl+V")
        if line_edit is None or line_edit.isReadOnly() or not clipboard.text():
            paste_action.setEnabled(False)

        menu.addSeparator()
        manage_action = menu.addAction("⚙️ Manage Models...")

        action = menu.exec(self.model_combo.mapToGlobal(position))

        if action == manage_action:
            self._open_model_manager()
        elif action == cut_action and line_edit is not None:
            line_edit.cut()
        elif action == copy_action:
            if line_edit is not None and line_edit.hasSelectedText():
                line_edit.copy()
            else:
                clipboard.setText(self.model_combo.currentText())
        elif action == paste_action and line_edit is not None:
            line_edit.paste()

    def _open_model_manager(self, *args, show=True):
        """Open a dialog for managing the model dropdown list."""
        from PySide6.QtWidgets import (QDialog, QVBoxLayout, QHBoxLayout,
                                        QListWidget, QPushButton, QLabel,
                                        QApplication, QLineEdit, QMessageBox,
                                        QTabWidget, QWidget, QTableWidget,
                                        QTableWidgetItem, QHeaderView, QComboBox)
        from PySide6.QtCore import Qt, QObject, QEvent, QEventLoop
        from PySide6.QtGui import QIcon

        def _center_dialog(dialog):
            try:
                screen = dialog.screen() or QApplication.primaryScreen()
                if screen is None:
                    return
                geo = screen.availableGeometry()
                dialog.move(
                    geo.x() + max(0, (geo.width() - dialog.width()) // 2),
                    geo.y() + max(0, (geo.height() - dialog.height()) // 2),
                )
            except Exception:
                pass

        def _prewarm_dialog_offscreen(dialog):
            app = QApplication.instance()
            was_visible = dialog.isVisible()
            old_opacity = dialog.windowOpacity()
            try:
                dialog.setAttribute(Qt.WA_DontShowOnScreen, False)
                if not was_visible:
                    dialog.setWindowOpacity(0.0)
                    dialog.move(-20000, -20000)
                    dialog.show()
                    dialog._fade_native_window_seen = True
                    dialog.raise_()
                try:
                    dialog.ensurePolished()
                    layout = dialog.layout()
                    if layout is not None:
                        layout.activate()
                except Exception:
                    pass
                if app is not None:
                    app.processEvents(QEventLoop.ExcludeUserInputEvents)
                if not was_visible:
                    dialog.hide()
                    _center_dialog(dialog)
                    dialog.setWindowOpacity(old_opacity)
            except Exception:
                try:
                    if not was_visible:
                        dialog.hide()
                        _center_dialog(dialog)
                        dialog.setWindowOpacity(old_opacity)
                except Exception:
                    pass

        # Reuse existing window if it has already been built.
        try:
            existing = getattr(self, '_model_manager_dialog', None)
            if existing is not None:
                if not show:
                    _prewarm_dialog_offscreen(existing)
                    return existing
                existing.setAttribute(Qt.WA_DontShowOnScreen, False)
                _center_dialog(existing)
                try:
                    existing.setWindowOpacity(1.0)
                except Exception:
                    pass
                existing.show()
                existing.raise_()
                existing.activateWindow()
                return existing
        except Exception:
            pass

        dialog = QDialog(self)
        dialog.setWindowTitle("Manage Models")
        dialog.setModal(False)
        dialog.setWindowFlags(dialog.windowFlags() | Qt.WindowStaysOnTopHint)
        dialog.setAttribute(Qt.WA_DeleteOnClose, True)
        self._model_manager_dialog = dialog
        dialog.finished.connect(lambda *_: setattr(self, '_model_manager_dialog', None))

        # Use screen ratios for sizing
        screen = QApplication.primaryScreen().availableGeometry()
        dialog_width = int(screen.width() * 0.28)
        dialog_height = int(screen.height() * 0.50)
        dialog.setMinimumWidth(dialog_width)
        dialog.setMinimumHeight(dialog_height)
        dialog.resize(dialog_width, dialog_height)

        # Set icon
        try:
            icon_path = os.path.join(self.base_dir, 'Halgakos.ico')
            if os.path.exists(icon_path):
                dialog.setWindowIcon(QIcon(icon_path))
        except Exception:
            pass

        layout = QVBoxLayout(dialog)
        tabs = QTabWidget()
        tabs.setStyleSheet("""
            QTabWidget::pane {
                border: 1px solid #3f4d5d;
                background: #181818;
                top: -1px;
            }
            QTabBar::tab {
                background: #202020;
                color: #d7e2f0;
                border: 1px solid #3a4652;
                border-bottom: none;
                padding: 7px 14px;
                margin-right: 2px;
                border-top-left-radius: 4px;
                border-top-right-radius: 4px;
            }
            QTabBar::tab:selected {
                background: #35516d;
                color: #ffffff;
                border-color: #6f8faf;
                font-weight: bold;
            }
            QTabBar::tab:!selected:hover {
                background: #2a3440;
                color: #ffffff;
                border-color: #526b84;
            }
        """)
        models_tab = QWidget()
        model_layout = QVBoxLayout(models_tab)

        # Instructions
        instructions = QLabel(
            "Drag and drop models to reorder. Add custom entries or remove unused ones (Ctrl+Click for multiple):"
        )
        instructions.setWordWrap(True)
        instructions.setStyleSheet("font-weight: bold; margin-bottom: 10px;")
        model_layout.addWidget(instructions)

        # --- Add-model row ---
        add_row = QHBoxLayout()
        add_entry = QLineEdit()
        add_entry.setPlaceholderText("Type a model ID to add…")
        add_row.addWidget(add_entry)
        add_btn = QPushButton("➕ Add")
        add_btn.setToolTip("Add the entered model to the list")
        add_btn.setStyleSheet("background-color: #17a2b8; color: white; font-weight: bold;")

        def _add_model():
            text = add_entry.text().strip()
            if not text:
                return
            # Check for duplicates
            for i in range(list_widget.count()):
                if list_widget.item(i).text() == text:
                    QMessageBox.information(dialog, "Duplicate",
                                            f"'{text}' is already in the list.")
                    return
            list_widget.insertItem(0, text)
            list_widget.setCurrentRow(0)
            add_entry.clear()
            save_state()

        add_btn.clicked.connect(_add_model)
        add_entry.returnPressed.connect(_add_model)
        add_row.addWidget(add_btn)
