        _mode_idx = {'off': 0, 'off_fuzzy_automap': 1, 'off_no_automap': 2, 'no_glossary': 3, 'minimal': 4, 'balanced': 5, 'full': 6, 'single_pass': 7}.get(_auto_mode.lower(), 0)
        self.auto_glossary_shortcut_combo.setCurrentIndex(_mode_idx)
