        self._gloss_status_row.setMaximumWidth(340)
        _gloss_row_layout = QHBoxLayout(self._gloss_status_row)
        _gloss_row_layout.setContentsMargins(0, 0, 8, 8)
        _gloss_row_layout.setSpacing(6)

