    def _context_mode_from_flags(self):
        """Return the UI context mode represented by legacy config flags."""
        if bool(getattr(self, 'rolling_summary_var', False)):
            mode = str(getattr(self, 'rolling_summary_mode_var', 'replace') or 'replace').strip().lower()
            return 'rolling_summary_append' if mode == 'append' else 'rolling_summary_replace'
        if bool(getattr(self, 'contextual_var', False)):
            return 'contextual_history'
        return 'off'

    def _on_contextual_toggle(self, state=None):
        """Compatibility shim for older callers; the combo is now authoritative."""
        self._on_context_mode_changed()

    def _set_batching_mode(self, mode):
        """Update batching mode state and any visible radio controls."""
        mode = str(mode or 'direct').strip().lower()
        if mode not in ('direct', 'conservative', 'aggressive'):
            mode = 'direct'
        self.batch_mode_var = mode
        self.config['batching_mode'] = mode
        if mode in ('direct', 'conservative'):
            self._context_last_batched_mode = mode

        radio_map = (
            ('batch_conservative_radio', mode == 'conservative'),
            ('batch_direct_radio', mode == 'direct'),
            ('batch_no_batching_radio', mode == 'aggressive'),
        )
        for attr, checked in radio_map:
            if not hasattr(self, attr):
                continue
            radio = getattr(self, attr)
            try:
                radio.blockSignals(True)
                radio.setChecked(checked)
                radio.blockSignals(False)
            except Exception:
                pass

    def _refresh_context_batching_controls(self):
        """Reflect context-mode batching constraints in the Other Settings radios."""
        controls = (
            ('batch_conservative_radio', 'Conservative batching'),
            ('batch_direct_radio', 'Direct batching'),
            ('batch_no_batching_radio', 'No batching'),
        )
        if not any(hasattr(self, attr) for attr, _label in controls):
            return

        mode = getattr(self, 'context_mode_var', None) or self._context_mode_from_flags()
        purple = "#b388ff"
        muted = "#777"
        normal = "#ddd"

        def apply_radio(attr, label, enabled, locked=False):
            radio = getattr(self, attr, None)
            if radio is None:
                return
            try:
                base_label = getattr(radio, '_context_base_text', None)
                if not base_label:
                    radio._context_base_text = label
                    base_label = label
                radio.setText(f"🔒  {base_label}" if locked else base_label)
                radio.setEnabled(enabled)
                if locked:
                    radio.setStyleSheet(
                        f"QRadioButton {{ color: {purple}; }}"
                        f"QRadioButton:disabled {{ color: {purple}; }}"
                    )
                elif enabled:
                    radio.setStyleSheet(f"QRadioButton {{ color: {normal}; }}")
                else:
                    radio.setStyleSheet(f"QRadioButton {{ color: {muted}; }}")
            except Exception:
                pass

        if mode == 'off':
            apply_radio('batch_conservative_radio', 'Conservative batching', False, False)
            apply_radio('batch_direct_radio', 'Direct batching', False, False)
            apply_radio('batch_no_batching_radio', 'No batching', True, True)
            status = "ℹ️ Context Mode Off uses No batching for translation.\n   Glossary extraction also uses No batching."
        else:
            apply_radio('batch_conservative_radio', 'Conservative batching', True, True)
            apply_radio('batch_direct_radio', 'Direct batching', True, True)
            apply_radio('batch_no_batching_radio', 'No batching', False, False)
            if mode == 'contextual_history':
                status = "ℹ️ Contextual History requires Direct or Conservative batching.\n   Glossary extraction uses the selected batching mode so history order stays aligned."
            else:
                status = "ℹ️ Rolling Summary requires Direct or Conservative batching for translation.\n   Glossary extraction stays on No batching and does not use the selected batching mode."

        label = getattr(self, 'batch_context_lock_label', None)
        if label is not None:
            try:
                label.setText(status)
                label.setStyleSheet("color: #17a2b8; font-size: 10pt;")
                label.setVisible(True)
            except Exception:
                pass

    def _enforce_context_batching_mode(self):
        """Apply context-mode batching constraints and keep the visible controls in sync."""
        mode = getattr(self, 'context_mode_var', None) or self._context_mode_from_flags()
        current = str(getattr(self, 'batch_mode_var', 'aggressive') or 'aggressive').strip().lower()

        if mode == 'off':
            if current in ('direct', 'conservative'):
                self._context_last_batched_mode = current
            self._set_batching_mode('aggressive')
        else:
            if current not in ('direct', 'conservative'):
                self._set_batching_mode(getattr(self, '_context_last_batched_mode', 'direct'))

        self._refresh_context_batching_controls()

    def _translation_batching_mode_for_env(self):
        """Return the effective batching mode for main translation subprocesses."""
        context_mode = getattr(self, 'context_mode_var', None) or self._context_mode_from_flags()
        if context_mode == 'off':
            return 'aggressive'
        mode = str(getattr(self, 'batch_mode_var', 'aggressive') or 'aggressive').strip().lower()
        if mode not in ('direct', 'conservative', 'aggressive'):
            mode = 'direct'
        if mode == 'aggressive':
            return 'direct'
        return mode

    def _glossary_batching_mode_for_env(self):
        """Glossary extraction uses no batching except when Contextual History is active."""
        context_mode = getattr(self, 'context_mode_var', None) or self._context_mode_from_flags()
        if context_mode != 'contextual_history':
            return 'aggressive'
        mode = str(getattr(self, 'batch_mode_var', 'direct') or 'direct').strip().lower()
        if mode not in ('direct', 'conservative', 'aggressive'):
            mode = 'direct'
        return 'direct' if mode == 'aggressive' else mode

    def _coerce_live_bool(self, value, default=False):
        if value is None:
            return bool(default)
        if hasattr(value, 'isChecked'):
            try:
                return bool(value.isChecked())
            except Exception:
                return bool(default)
        if hasattr(value, 'get'):
            try:
                return self._coerce_live_bool(value.get(), default)
            except Exception:
                return bool(default)
        if isinstance(value, str):
            normalized = value.strip().lower()
            if normalized in ('1', 'true', 'yes', 'on', 'checked'):
                return True
            if normalized in ('0', 'false', 'no', 'off', 'unchecked', ''):
                return False
        return bool(value)

    def _live_bool_setting(self, checkbox_attr, var_attr, config_key, default=False):
        widget = getattr(self, checkbox_attr, None)
        if widget is not None and hasattr(widget, 'isChecked'):
            try:
                return bool(widget.isChecked())
            except Exception:
                pass
        if hasattr(self, var_attr):
            return self._coerce_live_bool(getattr(self, var_attr), default)
        return self._coerce_live_bool(self.config.get(config_key, default), default)

    def _live_text_setting(self, widget_attr, var_attr, config_key, default=''):
        widget = getattr(self, widget_attr, None)
        if widget is not None and hasattr(widget, 'text'):
            try:
                value = str(widget.text()).strip()
                if value:
                    return value
            except Exception:
                pass
        if hasattr(self, var_attr):
            value = getattr(self, var_attr)
            if value is not None:
                value = str(value).strip()
                if value:
                    return value
        value = self.config.get(config_key, default)
        return str(value if value is not None else default).strip()

    def _on_disable_temperature_toggle(self, state=None):
        """Keep the live request flag and temperature field in sync."""
        checkbox = getattr(self, 'disable_temperature_checkbox', None)
        if checkbox is not None:
            disabled = bool(checkbox.isChecked())
        else:
            disabled = self._coerce_live_bool(
                getattr(self, 'disable_temperature_var', self.config.get('disable_temperature', False)),
                False,
            )
        self.disable_temperature_var = disabled
        self.config['disable_temperature'] = disabled
        os.environ['DISABLE_TEMPERATURE'] = '1' if disabled else '0'
        temperature_entry = getattr(self, 'trans_temp', None)
        if temperature_entry is not None:
            temperature_entry.setEnabled(not disabled)

    def _current_auto_glossary_mode(self):
        if (
            getattr(self, '_input_output_run_active', False)
            and getattr(self, '_direct_text_use_manual_glossary', False)
        ):
            return 'off_no_automap'
        if (
            getattr(self, '_input_output_run_active', False)
            and getattr(self, '_direct_text_force_no_glossary', True)
        ):
            return 'no_glossary'

        combo = getattr(self, 'auto_glossary_mode_combo', None)
        if combo is not None and hasattr(combo, 'currentText'):
            try:
                mode_raw = str(combo.currentText() or '').strip()
            except Exception:
                mode_raw = ''
        else:
            mode_raw = str(
                getattr(self, 'auto_glossary_mode_var', None)
                or self.config.get('auto_glossary_mode')
                or ''
            ).strip()
        if not mode_raw:
            return 'minimal' if self.config.get('enable_auto_glossary', False) else 'off'
        display_to_mode = {
            'Off': 'off',
            'Off (Fuzzy Mapping)': 'off_fuzzy_automap',
            'Manual Glossary Only': 'off_no_automap',
            'Off (No Auto-Mapping)': 'off_no_automap',
            'No Glossary': 'no_glossary',
            'Minimal': 'minimal',
            'Balanced': 'balanced',
            'Full': 'full',
            'Single Pass': 'single_pass',
        }
        return display_to_mode.get(mode_raw, mode_raw.lower().replace(' ', '_'))

    def _current_glossary_request_env(self, force_balanced_request_merging=False):
        merging_enabled = self._live_bool_setting(
            'glossary_request_merging_checkbox',
            'glossary_request_merging_enabled_var',
            'glossary_request_merging_enabled',
            False,
        )
        merge_count = self._live_text_setting(
            'glossary_request_merge_count_entry',
            'glossary_request_merge_count_var',
            'glossary_request_merge_count',
            '10',
        ) or '10'
        chapter_split = self._live_bool_setting(
            'glossary_enable_chapter_split_checkbox',
            'glossary_enable_chapter_split_var',
            'glossary_enable_chapter_split',
            False,
        )
        if force_balanced_request_merging:
            return '1', '99', '1' if chapter_split else '0'
        return '1' if merging_enabled else '0', str(merge_count), '1' if chapter_split else '0'

    def _glossary_contextual_env_value(self):
        disable_history = self._live_bool_setting(
            'disable_glossary_history_checkbox',
            'disable_glossary_history_var',
            'disable_glossary_history',
            True,
        )
        if disable_history:
            return '0'
        return '1' if getattr(self, 'contextual_var', False) else '0'

    def _on_context_mode_changed(self, index=None):
        """Map the Context Mode combo onto the existing runtime config flags."""
        mode = 'off'
        if hasattr(self, 'context_mode_combo'):
            mode = self.context_mode_combo.currentData() or 'off'
        self.context_mode_var = mode

        is_contextual = mode == 'contextual_history'
        is_summary = mode in ('rolling_summary_replace', 'rolling_summary_append')
        is_summary_append = mode == 'rolling_summary_append'
        has_context_options = is_contextual or is_summary

        self.contextual_var = is_contextual
        self.rolling_summary_var = is_summary
        if is_summary:
            self.rolling_summary_mode_var = 'append' if mode == 'rolling_summary_append' else 'replace'

        self.config['contextual'] = self.contextual_var
        self.config['use_rolling_summary'] = self.rolling_summary_var
        self.config['rolling_summary_mode'] = self.rolling_summary_mode_var
        self._enforce_context_batching_mode()

        if hasattr(self, 'contextual_warning_label'):
            self.contextual_warning_label.setVisible(is_contextual)
        if hasattr(self, 'context_options_container'):
            self.context_options_container.setVisible(has_context_options)
        if hasattr(self, 'rolling_summary_keys_btn'):
            self.rolling_summary_keys_btn.setVisible(is_summary)
        if hasattr(self, 'trans_history_label'):
            self.trans_history_label.setVisible(is_contextual)
        if hasattr(self, 'trans_history'):
            self.trans_history.setVisible(is_contextual)
            self.trans_history.setEnabled(is_contextual)
        for attr in (
            'rolling_summary_exchanges_label',
            'rolling_summary_exchanges_edit',
        ):
            if hasattr(self, attr):
                getattr(self, attr).setVisible(is_summary)
        for attr in (
            'rolling_summary_retain_label',
            'rolling_summary_retain_edit',
        ):
            if hasattr(self, attr):
                getattr(self, attr).setVisible(is_summary_append)

        if hasattr(self, 'frame'):
            row_shift = 0 if has_context_options else -1
            placements = (
                ('auto_glossary_row_container', 5 + row_shift, 2, 1, 2, Qt.AlignLeft),
                ('temp_container', 6 + row_shift, 2, 1, 2, Qt.AlignLeft),
                ('batch_container', 7 + row_shift, 2, 1, 1, Qt.AlignLeft),
                ('batch_right_container', 7 + row_shift, 3, 1, 1, Qt.AlignLeft),
            )
            for attr, row, col, row_span, col_span, alignment in placements:
                if hasattr(self, attr):
                    self.frame.addWidget(getattr(self, attr), row, col, row_span, col_span, alignment)
            if hasattr(self, '_gloss_status_row'):
                self.frame.addWidget(self._gloss_status_row, 5, 4, Qt.AlignRight)

        self.translation_history_rolling_var = True
    
    def _on_batch_toggle(self, state=None):
        """Handle batch translation toggle - enable/disable batch size entry"""
        # If called with a state (Qt.CheckState), update the var
        if state is not None:
            self.batch_translation_var = (state == Qt.Checked)
        
        # Always get the current checkbox state to be sure
        if hasattr(self, 'batch_checkbox'):
            is_batch = self.batch_checkbox.isChecked()
            self.batch_translation_var = is_batch
        else:
            is_batch = self.batch_translation_var
        
        # Enable/disable batch size entry based on checkbox state
        if hasattr(self, 'batch_size_entry'):
            self.batch_size_entry.setEnabled(is_batch)
    
    def _on_remove_artifacts_toggle(self, index=None):
        """Handle Remove AI Artifacts dropdown change"""
        if hasattr(self, 'remove_artifacts_combo'):
            self.REMOVE_AI_ARTIFACTS_var = self.remove_artifacts_combo.currentData() or "off"
    
    def _auto_save_system_prompt(self):
        """Auto-save system prompt to current profile as user types (in-memory only)"""
        try:
            # Get current profile name
            if not hasattr(self, 'profile_menu'):
                return
            
            name = self.profile_menu.currentText().strip()
            if not name:
                return
            
            # Don't auto-save if user is currently editing the profile name
            # Only save to profiles that already exist
            if name not in self.prompt_profiles:
                return
            
            # CRITICAL: Only auto-save if this profile is the one we're actively editing
            # This prevents accidentally saving to a previously selected profile
            if not hasattr(self, '_active_profile_for_autosave'):
                self._active_profile_for_autosave = None
            
            if self._active_profile_for_autosave != name:
                # Profile has changed but we haven't confirmed it yet
                # Don't auto-save until on_profile_select confirms the switch
                return
            
            # Get current text from prompt_text
            content = self.prompt_text.toPlainText().strip()
            
            # Update the profile in memory (staging area)
            self.prompt_profiles[name] = content
            
            # Update config in memory
            self.config['prompt_profiles'] = self.prompt_profiles
            self.config['active_profile'] = name
            
            # Note: We don't call save_profiles() here to avoid constant disk I/O
            # The profile will only be persisted when Save Profile is clicked
        except Exception as e:
            # Silently fail to avoid disrupting user's typing
            pass
    
    def _toggle_system_prompt_mode(self):
        """Toggle between system message and user message mode for system prompt"""
        self.system_prompt_to_user_var = not self.system_prompt_to_user_var
        os.environ['SYSTEM_PROMPT_TO_USER'] = '1' if self.system_prompt_to_user_var else '0'
        
        # Update label text
        self.prompt_label.setText("User Prompt:" if self.system_prompt_to_user_var else "System Prompt:")
        
        # Update switch emoji and tooltip
        self.system_prompt_switch.setText("🔀" if self.system_prompt_to_user_var else "↕️")
        self.system_prompt_switch.setToolTip(
            "<qt><p style='white-space: normal; max-width: 36em; margin: 0; font-size: 9pt;'>" +
            ("System prompt content will be sent as part of user message (🔀 mode)" if self.system_prompt_to_user_var 
             else "System prompt content will be sent as system message (↕️ mode)") +
            "<br><br>Click to toggle.</p></qt>"
        )
        
        # Save to config
        self.config['system_prompt_to_user'] = self.system_prompt_to_user_var
        try:
            _atomic_json_write(CONFIG_FILE, encrypt_config(self.config))
        except Exception as e:
            print(f"Warning: Could not save config: {e}")
        
        # Log the change
        mode_name = "user message" if self.system_prompt_to_user_var else "system message"
        self.append_log(f"🔀 System prompt will be sent as {mode_name}")
    
    def _get_output_base_dir(self, input_file: str = "") -> str:
        """Return the base directory where translation output folders are created.

        On Windows the translation engine writes output relative to the
        script / exe directory, NOT the input file's location.  On macOS
        CWD can be '/' due to App Translocation so we prefer the input
        file's parent there, with the script dir as fallback.
        """
        # Candidate 1: the script / exe directory (where the engine outputs)
        if getattr(sys, 'frozen', False):
            script_dir = os.path.dirname(sys.executable)
        else:
            script_dir = os.path.dirname(os.path.abspath(__file__))

        if platform.system() == 'Windows':
            return script_dir

        # macOS / Linux — prefer input file dir, fall back to script dir
        if input_file:
            input_dir = os.path.dirname(os.path.abspath(input_file))
            if input_dir and input_dir != '/':
                return input_dir
        return script_dir

    def _resolve_translation_output_dir(self, input_file: str) -> str:
        """Return the expected translation output directory for one input file."""
        base_name = os.path.splitext(os.path.basename(input_file))[0]
        override_dir = os.environ.get('OUTPUT_DIRECTORY') or self.config.get('output_directory')
        if override_dir:
            return os.path.join(os.path.abspath(override_dir), base_name)
        relative_output = base_name
        helper_output = os.path.join(self._get_output_base_dir(input_file), base_name)
        if os.path.exists(relative_output) or not os.path.exists(helper_output):
            return relative_output
        return helper_output

    def _resolve_open_output_folder_for_file(self, file_path: str) -> str:
        """Return the output folder path used by the Open Output Folder button."""
        ext = os.path.splitext(file_path)[1].lower()
        if ext == '.exe':
            return os.path.join(os.path.dirname(os.path.abspath(file_path)), 'GTool_Translation')
        return self._resolve_translation_output_dir(file_path)

    def _open_folder_in_file_manager(self, folder_path: str):
        """Open an existing folder in the platform file manager."""
        import subprocess

        if not folder_path:
            raise ValueError("No folder path was provided.")

        folder_path = os.path.abspath(folder_path)
        system_name = platform.system()
        if system_name == 'Windows':
            os.startfile(folder_path)
            return
        if system_name == 'Darwin':
            subprocess.Popen(['open', folder_path])
            return

        desktop_openers = [
            ('xdg-open', folder_path),
            ('gio', 'open', folder_path),
            ('kioclient6', 'exec', folder_path),
            ('kioclient5', 'exec', folder_path),
            ('kioclient', 'exec', folder_path),
        ]
        last_error = None
        for command in desktop_openers:
            if not shutil.which(command[0]):
                continue
            try:
                completed = subprocess.run(
                    list(command),
                    stdout=subprocess.DEVNULL,
                    stderr=subprocess.PIPE,
                    text=True,
                    timeout=5,
                )
                if completed.returncode == 0:
                    return
                last_error = completed.stderr.strip() or f"{command[0]} exited with {completed.returncode}"
            except Exception as exc:
                last_error = str(exc)

        for manager in ('dolphin', 'thunar', 'nemo', 'nautilus', 'pcmanfm', 'caja'):
            if not shutil.which(manager):
                continue
            subprocess.Popen([manager, folder_path], stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
            return

        raise RuntimeError(last_error or "No Linux file manager opener was found. Install xdg-utils or a file manager.")

    def _flatten_translation_qa_issue_text(self, value) -> str:
        if value is None:
            return ""
        if isinstance(value, dict):
            parts = []
            for key, item in value.items():
                parts.append(self._flatten_translation_qa_issue_text(key))
                parts.append(self._flatten_translation_qa_issue_text(item))
            return " ".join(part for part in parts if part)
        if isinstance(value, (list, tuple, set)):
            return " ".join(
                part
                for part in (self._flatten_translation_qa_issue_text(item) for item in value)
                if part
            )
        return str(value)

    def _is_foreign_character_translation_qa_issue(self, issue) -> bool:
        text = self._flatten_translation_qa_issue_text(issue).strip()
        if not text:
            return False
        normalized = text.lower().replace("-", "_").replace(" ", "_")
        return "_text_found_" in normalized and "_chars_" in normalized

    def _entry_has_foreign_character_qa_failure(self, entry) -> bool:
        seen = set()
        current = entry
        while isinstance(current, dict) and id(current) not in seen:
            seen.add(id(current))
            status = str(current.get("status", "") or "").strip().lower()
            issues = []
            for key in ("qa_issues_found", "qa_issues", "failure_reason", "error_message"):
                value = current.get(key)
                if isinstance(value, (list, tuple, set)):
                    issues.extend(value)
                elif value is not None:
                    issues.append(value)
            if status == "qa_failed" and any(
                self._is_foreign_character_translation_qa_issue(issue) for issue in issues
            ):
                return True
            current = current.get("previous_progress_entry")
        return False

    def _collect_translation_qa_failures(self, files=None, *, foreign_character_only=False):
        """Collect qa_failed chapters from translation_progress.json files."""
        files = files or getattr(self, 'selected_files', []) or []
        failures = []
        seen = set()

        for file_path in files:
            if not file_path or file_path == "__generative_mode__":
                continue
            try:
                progress_path = os.path.join(
                    self._resolve_translation_output_dir(file_path),
                    "translation_progress.json",
                )
                if not os.path.exists(progress_path):
                    continue
                with open(progress_path, "r", encoding="utf-8") as pf:
                    progress = json.load(pf)
            except Exception:
                continue

            chapters = progress.get("chapters", {})
            if not isinstance(chapters, dict):
                continue

            for chapter_key, chapter_info in chapters.items():
                if not isinstance(chapter_info, dict):
                    continue
                status = str(chapter_info.get("status", "")).lower()
                if foreign_character_only and not self._entry_has_foreign_character_qa_failure(chapter_info):
                    continue
                issues = chapter_info.get("qa_issues_found") or []
                if (
                    not foreign_character_only
                    and status not in {"qa_failed", "failed"}
                    and not chapter_info.get("qa_issues")
                ):
                    continue
                if isinstance(issues, str):
                    issues = [issues]
                elif not isinstance(issues, list):
                    issues = []

                chapter_num = (
                    chapter_info.get("actual_num")
                    or chapter_info.get("chapter_num")
                    or chapter_info.get("raw_chapter_num")
                    or chapter_key
                )
                output_file = chapter_info.get("output_file") or chapter_info.get("chapter_file") or ""
                dedupe_key = (os.path.abspath(progress_path), str(chapter_num), output_file)
                if dedupe_key in seen:
                    continue
                seen.add(dedupe_key)
                failures.append({
                    "source": os.path.basename(file_path),
                    "chapter": chapter_num,
                    "output_file": output_file,
                    "issues": [str(issue).strip() for issue in issues if str(issue).strip()] or ["UNKNOWN"],
                })

        return failures

    def _active_translation_output_mode(self) -> str:
        override = getattr(self, '_translation_run_output_mode_override', None)
        if override:
            return str(override).lower().strip()
        if getattr(self, '_input_output_run_active', False):
            direct_mode = getattr(self, '_direct_text_output_mode', None)
            if direct_mode:
                return str(direct_mode).lower().strip()
        return self._get_output_mode()

    def _translation_qa_failure_key(self, failure):
        return (
            str(failure.get("source", "")),
            str(failure.get("chapter", "")),
            str(failure.get("output_file", "")),
        )

    def _prepare_multipass_qa_refinement_run(self, multipass_enabled, multipass_refinement_mode):
        self._translation_run_output_mode_override = None
        self._translation_run_is_multipass_qa_refinement = False
        self._translation_run_qa_refinement_mode = ""
        self._translation_run_targeted_qa_failures = []
        self._translation_run_skipped_qa_failures = []
        self._translation_run_followup_translation_after_refinement = False

        if not multipass_enabled or multipass_refinement_mode not in ("failed", "partial", "partial.b", "partial.b2"):
            return []
        if self._get_output_mode() in ("refinement", "audio", "image", "video"):
            return []

        all_failures = self._collect_translation_qa_failures()
        targeted_failures = self._collect_translation_qa_failures(foreign_character_only=True)
        if not targeted_failures:
            return []

        targeted_keys = {self._translation_qa_failure_key(failure) for failure in targeted_failures}
        skipped_failures = [
            failure
            for failure in all_failures
            if self._translation_qa_failure_key(failure) not in targeted_keys
        ]
        self._translation_run_output_mode_override = "refinement"
        self._translation_run_is_multipass_qa_refinement = True
        self._translation_run_qa_refinement_mode = multipass_refinement_mode
        self._translation_run_targeted_qa_failures = targeted_failures
        self._translation_run_skipped_qa_failures = skipped_failures
        self._translation_run_followup_translation_after_refinement = bool(skipped_failures)
        os.environ['OUTPUT_MODE'] = 'refinement'
        os.environ['ENABLE_REFINEMENT_OUTPUT_MODE'] = '1'
        os.environ['ENABLE_AUDIO_OUTPUT_MODE'] = '0'
        os.environ['ENABLE_IMAGE_OUTPUT_MODE'] = '0'
        os.environ['ENABLE_VIDEO_OUTPUT_MODE'] = '0'
        return targeted_failures

    def _clear_translation_run_overrides(self):
        self._translation_run_output_mode_override = None
        self._translation_run_is_multipass_qa_refinement = False
        self._translation_run_qa_refinement_mode = ""
        self._translation_run_targeted_qa_failures = []
        self._translation_run_skipped_qa_failures = []
        self._translation_run_followup_translation_after_refinement = False
        try:
            mode = self._get_output_mode()
            os.environ['OUTPUT_MODE'] = mode
            os.environ['ENABLE_REFINEMENT_OUTPUT_MODE'] = '1' if mode == 'refinement' else '0'
            os.environ['ENABLE_AUDIO_OUTPUT_MODE'] = '1' if mode == 'audio' else '0'
            os.environ['ENABLE_IMAGE_OUTPUT_MODE'] = self._get_allowed_image_output_mode()
            os.environ['ENABLE_VIDEO_OUTPUT_MODE'] = self._get_allowed_video_output_mode()
        except Exception:
            pass
        if getattr(self, '_input_output_run_active', False):
            self._apply_direct_text_runtime_environment()

    def _format_chapter_list(self, chapters):
        def _sort_key(value):
            text = str(value)
            try:
                return (0, int(text))
            except Exception:
                return (1, text)
        return ", ".join(str(chapter) for chapter in sorted(chapters, key=_sort_key))

    def _log_translation_qa_failure_summary(self, phase="current"):
        failures = self._collect_translation_qa_failures()
        if not failures:
            return

        self.append_log("")
        self.append_log("⚠️ QA failure summary:")
        if phase == "start":
            self.append_log("   Existing failed chapters were found before this run starts:")
        else:
            self.append_log("   Failed chapters found at the end of this translation run:")

        grouped = {}
        for failure in failures:
            source = failure["source"]
            for issue in failure["issues"]:
                grouped.setdefault((source, issue), []).append(failure["chapter"])

        for (source, issue), chapters in grouped.items():
            chapter_label = "Chapters" if len(chapters) != 1 else "Chapter"
            self.append_log(f"   - {source} - {chapter_label} {self._format_chapter_list(chapters)}: {issue}")
        issue_set = {issue for failure in failures for issue in failure["issues"]}
        self.append_log("")
        self.append_log("   What these QA issues mean:")
        if "TRUNCATED" in issue_set:
            self.append_log(
                "   - TRUNCATED: the provider/server ended the response early. Increase the compression factor "
                "or reduce the output token limit, use a different model, or increase the auto-retry truncated value."
            )
        if "PROHIBITED_CONTENT" in issue_set or "PROHIBITED CONTENT" in issue_set:
            self.append_log(
                "   • PROHIBITED_CONTENT: the model/provider likely blocked the request because of safety or censorship. "
                "Use a different model/provider for that chapter."
            )
        if "SPLIT_FAILED" in issue_set:
            self.append_log(
                "   • SPLIT_FAILED: the AI ignored or mishandled the split-marker instructions, so the output could not "
                "be safely mapped back to the original split chapters."
            )

        if "API_ERROR" in issue_set:
            self.append_log(
                "   - API_ERROR: the provider/API request failed before a usable response was returned. "
                "Retry the chapter, check the API/provider logs, or switch model/provider if it repeats."
            )

        known = {"TRUNCATED", "PROHIBITED_CONTENT", "PROHIBITED CONTENT", "SPLIT_FAILED", "API_ERROR"}
        unknown = sorted(issue for issue in issue_set if issue not in known)
        if unknown:
            self.append_log(
                f"   • Other issue(s) ({', '.join(unknown)}): the exact cause is not known from the saved QA marker. "
                "Retry the chapter, check the surrounding logs, or switch model/provider if it repeats."
            )

    def open_output_folder(self):
        """Open the output folder that is expected to be created"""
        if not hasattr(self, 'selected_files') or not self.selected_files:
             # Try to use self.file_path if set (single file legacy/other mode)
             if hasattr(self, 'file_path') and self.file_path:
                 files = [self.file_path]
             else:
                 QMessageBox.warning(self, "No File Selected", "Please select a file first.")
                 return
        else:
            files = self.selected_files
            
        if not files:
             QMessageBox.warning(self, "No File Selected", "Please select a file first.")
             return

        # Check for output directory override
        override_dir = os.environ.get('OUTPUT_DIRECTORY') or self.config.get('output_directory')
        
        # Check for batch image mode
        image_extensions = {'.png', '.jpg', '.jpeg', '.gif', '.bmp', '.webp'}
        image_files = [f for f in files if os.path.splitext(f)[1].lower() in image_extensions]
        
        if len(image_files) > 1 and len(image_files) == len(files):
            # Batch image mode — single combined folder
            parent_dir = os.path.dirname(files[0])
            folder_name = os.path.basename(parent_dir) if parent_dir else "OCR"
            if override_dir:
                output_path = os.path.join(override_dir, folder_name)
            else:
                base_dir = self._get_output_base_dir(files[0])
                output_path = os.path.join(base_dir, folder_name)
            self._open_single_output_folder(output_path)
            return
        
        if len(files) == 1:
            file_path = files[0]
            # Single file — open directly
            output_path = self._resolve_open_output_folder_for_file(file_path)
            self._open_single_output_folder(output_path)
            return
        
        # ── Multiple files — show picker dialog ──────────────────────
        self._show_output_folder_picker(files, override_dir)

    def _open_single_output_folder(self, output_path):
        """Open a single output folder, with fallback to parent if it doesn't exist."""
        expected_path = os.path.abspath(output_path)
        if not os.path.exists(output_path):
            reply = QMessageBox.question(self, "Folder Not Found", 
                                  f"The output folder '{os.path.basename(output_path)}' does not exist yet.\n"
                                  f"Expected path: {expected_path}\n"
                                  "Do you want to open the parent directory instead?",
                                  QMessageBox.Yes | QMessageBox.No)
            if reply == QMessageBox.Yes:
                output_path = os.path.dirname(expected_path)
            else:
                return
        else:
            output_path = expected_path
        
        try:
            self._open_folder_in_file_manager(output_path)
        except Exception as e:
             QMessageBox.warning(self, "Error", f"Could not open folder: {e}")

    def _show_output_folder_picker(self, files, override_dir):
        """Show a dropdown menu to pick which output folder to open."""
        menu = QMenu(self)
        menu.setStyleSheet("""
            QMenu {
                background-color: #1e1e1e;
                color: #e0e0e0;
                border: 1px solid #4a5568;
                padding: 4px;
            }
            QMenu::item {
                padding: 6px 16px;
                border-radius: 3px;
            }
            QMenu::item:selected {
                background-color: #3d4f6a;
            }
            QMenu::item:disabled {
                color: #555;
            }
            QMenu::separator {
                height: 1px;
                background-color: #4a5568;
                margin: 4px 8px;
            }
        """)
        
        existing_paths = []
        
        for file_path in files:
            base_name = os.path.splitext(os.path.basename(file_path))[0]
            output_path = self._resolve_open_output_folder_for_file(file_path)
            
            exists = os.path.exists(output_path)
            icon = "📂" if exists else "📁"
            suffix = "" if exists else "  (not created)"
            
            action = menu.addAction(f"{icon}  {base_name}{suffix}")
            action.setToolTip(output_path)
            
            if exists:
                existing_paths.append(output_path)
                action.triggered.connect(lambda checked=False, p=output_path: self._open_single_output_folder(p))
            else:
                action.setEnabled(False)
        
        if existing_paths:
            menu.addSeparator()
            open_all_action = menu.addAction(f"📂  Open All ({len(existing_paths)} folders)")
            
            def open_all():
                for p in existing_paths:
                    try:
                        self._open_folder_in_file_manager(p)
                    except Exception:
                        pass
            
            open_all_action.triggered.connect(open_all)
        
        # Show the menu at the button's position
        btn = self.open_folder_btn if hasattr(self, 'open_folder_btn') else None
        if btn:
            menu.exec(btn.mapToGlobal(btn.rect().bottomLeft()))
        else:
            menu.exec(self.mapToGlobal(self.rect().center()))

