    # ===== Progress Manager (Retranslation) fast opener =====
    def _show_cached_progress_manager_if_any(self) -> bool:
        """Bring any cached Progress Manager dialog to front instantly. Returns True if shown."""
        try:
            def _refresh_dialog(dlg):
                try:
                    # Prefer explicit refresh function on dialog
                    if hasattr(dlg, '_refresh_func') and callable(dlg._refresh_func):
                        dlg._refresh_func()
                        return
                    # Multi-file dialog: per-tab refresh handlers
                    if hasattr(self, '_refresh_all_tabs') and hasattr(dlg, '_tab_data'):
                        # If tabs have explicit refresh_func, call them; otherwise use bulk refresh
                        used_handler = False
                        for tab_data in getattr(dlg, '_tab_data', []):
                            func = tab_data.get('refresh_func')
                            if callable(func):
                                func()
                                used_handler = True
                        if used_handler:
                            return
                        self._refresh_all_tabs(dlg._tab_data)
                        return
                    # Single-file dialog stores its data as _data
                    if hasattr(self, '_refresh_retranslation_data') and hasattr(dlg, '_data'):
                        if callable(getattr(dlg, '_refresh_func', None)):
                            dlg._refresh_func()
                        else:
                            self._refresh_retranslation_data(dlg._data)
                except Exception:
                    pass
            # Single-file cache
            if hasattr(self, 'entry_epub') and hasattr(self.entry_epub, 'text'):
                p = self.entry_epub.text().strip()
                if p:
                    key = os.path.abspath(p)
                    cache = getattr(self, '_retranslation_dialog_cache', None)
                    if isinstance(cache, dict) and key in cache and cache[key].get('dialog'):
                        dlg = cache[key]['dialog']
                        try:
                            dlg.setWindowState((dlg.windowState() & ~Qt.WindowMinimized) | Qt.WindowActive)
                            dlg.show(); dlg.raise_(); dlg.activateWindow()
                            _refresh_dialog(dlg)
                            return True
                        except Exception:
                            pass
            # Multi-file
            if hasattr(self, '_multi_file_retranslation_dialog') and self._multi_file_retranslation_dialog:
                dlg = self._multi_file_retranslation_dialog
                # Validate selection hasn't changed (user may have cleared/added EPUBs)
                current_key = tuple(sorted(getattr(self, 'selected_files', [])))
                cached_key = getattr(self, '_multi_file_selection_key', None)
                if cached_key is not None and current_key != cached_key:
                    # Selection changed — destroy stale dialog so it gets rebuilt
                    try:
                        dlg.close()
                        dlg.deleteLater()
                    except Exception:
                        pass
                    self._multi_file_retranslation_dialog = None
                    self._multi_file_selection_key = None
                else:
                    try:
                        dlg.setWindowState((dlg.windowState() & ~Qt.WindowMinimized) | Qt.WindowActive)
                        dlg.show(); dlg.raise_(); dlg.activateWindow()
                        _refresh_dialog(dlg)
                        return True
                    except Exception:
                        pass
            # Image folder cache
            if hasattr(self, '_image_retranslation_dialog_cache') and hasattr(self, 'selected_files') and self.selected_files:
                first = self.selected_files[0]
                folder_key = os.path.abspath(first if os.path.isdir(first) else os.path.dirname(first))
                cache = getattr(self, '_image_retranslation_dialog_cache', None)
                if isinstance(cache, dict) and folder_key in cache and cache[folder_key]:
                    dlg = cache[folder_key]
                    try:
                        dlg.setWindowState((dlg.windowState() & ~Qt.WindowMinimized) | Qt.WindowActive)
                        dlg.show(); dlg.raise_(); dlg.activateWindow()
                        _refresh_dialog(dlg)
                        return True
                    except Exception:
                        pass
        except Exception:
            pass
        return False

    def _profiles_button_clicked(self):
        """Single entry point for profile import/export."""
        try:
            from PySide6.QtWidgets import QMessageBox

            msg = QMessageBox(self)
            msg.setWindowTitle("Profiles")
            msg.setIcon(QMessageBox.Question)
            msg.setText("Choose what you want to do with profiles:")

            import_btn = msg.addButton("Import", QMessageBox.AcceptRole)
            export_btn = msg.addButton("Export", QMessageBox.AcceptRole)
            msg.addButton("Cancel", QMessageBox.RejectRole)

            msg.exec()
            clicked = msg.clickedButton()

            if clicked == import_btn:
                return self.import_profiles()
            if clicked == export_btn:
                return self.export_profiles()
            return
        except Exception:
            # Fallback: do nothing (avoid crashing the GUI)
            return

    def _stop_pm_spin(self):
        if hasattr(self, 'pm_spinner') and self.pm_spinner:
            self.pm_spinner.stop()
        if hasattr(self, '_pm_spin_timer') and self._pm_spin_timer:
            try:
                self._pm_spin_timer.stop()
            except Exception:
                pass

    def open_progress_manager(self):
        """User clicked Progress Manager. Show instantly if cached; otherwise show a tiny loader and open lazily."""
        # Start spin now using its own timer so heavy work can't starve it
        if hasattr(self, 'pm_spinner') and self.pm_spinner and not self.pm_spinner.is_running():
            self.pm_spinner.start()
            try:
                import time as _t
                self._pm_spin_started_at = _t.monotonic()
            except Exception:
                self._pm_spin_started_at = None
            # Kick a dedicated timer to tick spinner even if main loop is busy
            from PySide6.QtCore import QTimer
            if not hasattr(self, '_pm_spin_timer') or self._pm_spin_timer is None:
                self._pm_spin_timer = QTimer(self)
                # Call twice per tick to double effective speed
                self._pm_spin_timer.timeout.connect(lambda: self.pm_spinner and self.pm_spinner._advance())
                self._pm_spin_timer.timeout.connect(lambda: self.pm_spinner and self.pm_spinner._advance())
            self._pm_spin_timer.start(10)  # faster cadence
        # If cached, just show
        if self._show_cached_progress_manager_if_any():
            self._stop_pm_spin()
            return
        # No loading dialog — keep the toolbar icon spinning until the dialog is ready
        def _emit():
            try:
                time.sleep(0.02)
            except Exception:
                pass
            self.open_progress_manager_signal.emit()
        threading.Thread(target=_emit, name="PMOpenDefer", daemon=True).start()

    def _open_progress_manager_on_main_thread(self):
        try:
            # If user opened something else and dialog now exists, just raise it
            if self._show_cached_progress_manager_if_any():
                self._stop_pm_spin()
                return
            # Build using existing mixin method on the main thread
            self.force_retranslation()
        finally:
            # Poll until the actual dialog exists, then stop spinning
            def _finish_when_ready(attempts=0):
                if self._show_cached_progress_manager_if_any():
                    self._stop_pm_spin()
                elif attempts >= 60:  # ~6s max
                    self._stop_pm_spin()
                else:
                    QTimer.singleShot(100, lambda: _finish_when_ready(attempts + 1))
            QTimer.singleShot(50, _finish_when_ready)

    def _on_save_config_clicked(self):
        """Provide inline feedback when saving config from the toolbar button."""
        try:
            from PySide6.QtWidgets import QApplication
            from PySide6.QtCore import QTimer
            btn = getattr(self, 'save_config_button', None)
            original_text = None
            original_style = None
            if btn is not None:
                original_text = btn.text()
                original_style = btn.styleSheet()
                btn.setEnabled(False)
                btn.setText("Saving…")
                # Subtle highlight during save
                btn.setStyleSheet("background-color: #17a2b8; color: white; border: none; border-radius: 0px; font-weight: bold;")
                QApplication.processEvents()
            # Log feedback
            try:
                self.append_log("💾 Saving configuration…")
            except Exception:
                pass
            # Perform save (keep message box behavior as-is)
            self.save_config(show_message=True)
            if btn is not None:
                btn.setText("Saved ✓")
                btn.setStyleSheet("background-color: #27ae60; color: white; border: none; border-radius: 0px; font-weight: bold;")
                # Restore after a short delay
                def _restore():
                    try:
                        btn.setText(original_text or "Save Config")
                        if original_style:
                            btn.setStyleSheet(original_style)
                        btn.setEnabled(True)
                    except Exception:
                        pass
                QTimer.singleShot(900, _restore)
            try:
                self.append_log("✅ Configuration saved")
            except Exception:
                pass
        except Exception as e:
            # Best-effort restore on failure
            try:
                if getattr(self, 'save_config_button', None):
                    self.save_config_button.setText("Save Failed")
                    self.save_config_button.setStyleSheet("background-color: #dc3545; color: white; border: none; border-radius: 0px; font-weight: bold;")
                    def _restore_fail():
                        try:
                            self.save_config_button.setText("Save Config")
                            # Do not assume original style on failure
                            self.save_config_button.setEnabled(True)
                        except Exception:
                            pass
                    from PySide6.QtCore import QTimer
                    QTimer.singleShot(1500, _restore_fail)
            except Exception:
                pass
            # Surface error minimally in log
            try:
                self.append_log(f"❌ Save failed: {e}")
            except Exception:
                pass
    
    def keyPressEvent(self, event):
        """Handle key press events for shortcuts"""
        if event.key() == Qt.Key_F11:
            self.toggle_fullscreen()
        else:
            super().keyPressEvent(event)
    
    def toggle_fullscreen(self):
        """Toggle fullscreen mode and expand log area"""
        if not self.is_fullscreen:
            # Enter fullscreen
            self.showFullScreen()
            self.is_fullscreen = True
            
            # Make log area expand more in fullscreen
            # Set all rows to zero stretch except log (row 11)
            for r in range(13):
                if r == 11:
                    self.frame.setRowStretch(r, 5)  # Log gets all the stretch
                else:
                    self.frame.setRowStretch(r, 0)  # All other rows including toolbar (12) don't stretch
            
            self.append_log("🖥️ Fullscreen mode enabled (Press F11 to exit)")
        else:
            # Exit fullscreen
            self.showNormal()
            self.is_fullscreen = False
            
            # Restore default stretches for all rows
            for r in range(13):
                self.frame.setRowStretch(r, self._default_row_stretches.get(r, 0))
            
            self.append_log("🖥️ Fullscreen mode disabled")
    
    def _on_spine_order_toggle(self, state):
        """Save spine order checkbox state to config."""
        checked = state == Qt.Checked.value if hasattr(Qt.Checked, 'value') else bool(state)
        self.config['use_spine_order'] = checked
        # Update placeholder to hint the user
        if checked:
            self.chapter_range_entry.setPlaceholderText("e.g. 5 or 5-10  📓")
        else:
            self.chapter_range_entry.setPlaceholderText("e.g. 5 or 5-10")

    def _parse_chapter_range_text(self, value):
        """Parse chapter range text. A single number means that one chapter."""
        value = str(value or '').strip()
        if re.match(r"^\d+$", value):
            num = int(value)
            return num, num
        if re.match(r"^\d+\s*-\s*\d+$", value):
            return tuple(map(int, re.split(r"\s*-\s*", value, 1)))
        return None

    def _show_chapter_range_context_menu(self, pos):
        """Show right-click context menu on chapter range entry with file preview option."""
        menu = QMenu(self)
        menu.setStyleSheet("""
            QMenu { background-color: #2d2d2d; color: white; border: 1px solid #4a5568; }
            QMenu::item:selected { background-color: #5a9fd4; }
            QMenu::item:disabled { color: #888888; }
        """)

        # Standard text edit actions
        undo_action = menu.addAction("Undo")
        undo_action.triggered.connect(self.chapter_range_entry.undo)
        redo_action = menu.addAction("Redo")
        redo_action.triggered.connect(self.chapter_range_entry.redo)
        menu.addSeparator()
        cut_action = menu.addAction("Cut")
        cut_action.triggered.connect(self.chapter_range_entry.cut)
        copy_action = menu.addAction("Copy")
        copy_action.triggered.connect(self.chapter_range_entry.copy)
        paste_action = menu.addAction("Paste")
        paste_action.triggered.connect(self.chapter_range_entry.paste)
        menu.addSeparator()
        select_all_action = menu.addAction("Select All")
        select_all_action.triggered.connect(self.chapter_range_entry.selectAll)
        menu.addSeparator()

        # Preview action
        preview_action = menu.addAction("📋 Preview files in range")
        preview_action.triggered.connect(self._preview_chapter_range_files)

        menu.exec(self.chapter_range_entry.mapToGlobal(pos))

    def _preview_chapter_range_files(self):
        """Show a non-modal, stay-on-top dialog previewing which files will be translated."""
        chap_range = self.chapter_range_entry.text().strip()
        parsed_range = self._parse_chapter_range_text(chap_range)
        if not parsed_range:
            QMessageBox.information(self, "Preview", "Enter a valid chapter range (e.g. 5 or 5-10) first.")
            return

        start, end = parsed_range
        use_spine = getattr(self, 'use_spine_order_checkbox', None)
        spine_mode = use_spine and use_spine.isChecked()

        # Get input file
        input_path = ""
        if hasattr(self, 'entry_epub') and hasattr(self.entry_epub, 'text'):
            input_path = self.entry_epub.text().strip()

        if not input_path or not os.path.isfile(input_path):
            QMessageBox.information(self, "Preview", "Please select an EPUB file first.")
            return

        if not input_path.lower().endswith('.epub'):
            QMessageBox.information(self, "Preview", "File preview is only available for EPUB files.")
            return

        # Check translate_special_files setting
        translate_special = getattr(self, 'translate_special_files_var', False)

        filenames = self._get_spine_filenames_for_preview(input_path, start, end, spine_mode, translate_special)

        if not filenames:
            QMessageBox.information(self, "Preview",
                f"No files found in range {start}-{end}" +
                (" (spine order)" if spine_mode else "") + ".")
            return

        # Count translatable vs skipped
        translatable = [f for f in filenames if not f[2]]
        skipped = [f for f in filenames if f[2]]

        # Build non-modal, stay-on-top preview dialog
        dlg = QDialog(self, Qt.WindowStaysOnTopHint)
        dlg.setWindowTitle(f"Chapter Range Preview ({start}-{end})" +
                          (" — Spine Order" if spine_mode else ""))
        # Use ratio-based sizing (20% width, 35% height of screen)
        try:
            screen = QApplication.primaryScreen()
            if screen:
                geom = screen.availableGeometry()
                dlg_w = int(geom.width() * 0.20)
                dlg_h = int(geom.height() * 0.35)
            else:
                dlg_w, dlg_h = 380, 360
        except Exception:
            dlg_w, dlg_h = 380, 360
        dlg.resize(dlg_w, dlg_h)
        dlg.setMinimumSize(280, 200)
        dlg.setStyleSheet("background-color: #1e1e1e; color: white;")
        layout = QVBoxLayout(dlg)

        header_text = (f"{'Spine' if spine_mode else 'Chapter'} range {start}–{end}: "
                       f"{len(translatable)} file(s) will be translated")
        if skipped:
            header_text += f"  •  {len(skipped)} special file(s) skipped"
        header = QLabel(header_text)
        header.setStyleSheet("color: #5a9fd4; font-weight: bold; font-size: 10pt;")
        header.setWordWrap(True)
        layout.addWidget(header)

        from PySide6.QtWidgets import QListWidget, QListWidgetItem
        file_list = QListWidget()
        file_list.setStyleSheet("""
            QListWidget { background-color: #2d2d2d; color: white; border: 1px solid #4a5568; }
            QListWidget::item { padding: 3px; }
            QListWidget::item:alternate { background-color: #333333; }
        """)
        file_list.setAlternatingRowColors(True)
        for pos_label, fname, is_special in filenames:
            if is_special:
                item = QListWidgetItem(f"  {pos_label}  →  {fname}  ⏩ Skipped (special file)")
                item.setForeground(QColor("#888888"))
            else:
                item = QListWidgetItem(f"  {pos_label}  →  {fname}")
            file_list.addItem(item)
        layout.addWidget(file_list)

        # Legend for special files
        if skipped and not translate_special:
            legend = QLabel("ℹ️ Special files (cover, nav, toc, etc.) are skipped because "
                           "\"Translate Special Files\" is disabled.")
            legend.setStyleSheet("color: #888888; font-size: 9pt; font-style: italic;")
            legend.setWordWrap(True)
            layout.addWidget(legend)

        close_btn = QPushButton("Close")
        close_btn.setStyleSheet("background-color: #3d3d3d; color: white; padding: 6px 16px;")
        close_btn.clicked.connect(dlg.close)
        layout.addWidget(close_btn)

        # Set Halgakos icon
        try:
            ico_path = os.path.join(self.base_dir, 'Halgakos.ico')
            if os.path.isfile(ico_path):
                dlg.setWindowIcon(QIcon(ico_path))
        except Exception:
            pass

        # Non-modal: show() instead of exec()
        dlg.setAttribute(Qt.WA_DeleteOnClose)
        dlg.show()
        dlg.raise_()
        dlg.activateWindow()
        # Keep a reference so it doesn't get garbage collected
        self._preview_dialog = dlg

    def _is_special_file(self, filename):
        """Check if a filename is a special file using configurable keyword lists.
        
        Numbered HTML translation is handled separately; files whose name
        contains a digit can still be classified as special.
        """
        name_lower = filename.lower()
        base = os.path.basename(name_lower)
        # Strip response_ prefix (output filenames use this convention)
        if base.startswith("response_"):
            base = base[len("response_"):]
        name_noext = os.path.splitext(base)[0]
        # Check configured special-file patterns (substring match).
        # Non-numbered filenames are allowed to display as Ch.000 elsewhere, but that
        # must not make them special unless they match these configured lists.
        _kw_str = getattr(self, 'special_file_keywords_var', '')
        is_keyword_match = False
        if _kw_str:
            _keywords = [k.strip().lower() for k in _kw_str.split(',') if k.strip()]
            if any(kw in name_noext for kw in _keywords):
                is_keyword_match = True
        # Exact-match keywords
        if not is_keyword_match:
            _exact_str = getattr(self, 'special_file_exact_var', '')
            if _exact_str:
                _exact = [k.strip().lower() for k in _exact_str.split(',') if k.strip()]
                if name_noext in _exact:
                    is_keyword_match = True
        return is_keyword_match

    def _should_skip_special_file(self, filename, translate_special=False):
        """Return True when a configured special file should be skipped."""
        if translate_special:
            return False
        if not self._is_special_file(filename):
            return False
        if getattr(self, 'translate_all_numbered_html_var', True):
            import re as _re
            name = os.path.splitext(os.path.basename(str(filename or '')))[0]
            if name.lower().startswith("response_"):
                name = name[len("response_"):]
            if _re.search(r'\d', name):
                return False
        return True

    def _get_spine_filenames_for_preview(self, epub_path, start, end, spine_mode, translate_special=False):
        """
        Read the EPUB spine and return list of (position_label, filename, is_special_skipped) tuples
        that fall within the given range.
        If spine_mode is True, range refers to raw OPF spine position (1-based),
        matching the Progress Manager display.
        If spine_mode is False, range refers to chapter numbers extracted from filenames.
        is_special_skipped is True when translate_special is False and the file is a special file.
        """
        results = []
        try:
            import xml.etree.ElementTree as ET
            import zipfile

            with zipfile.ZipFile(epub_path, 'r') as zf:
                # Find content.opf
                opf_path = None
                try:
                    container_content = zf.read('META-INF/container.xml')
                    container_root = ET.fromstring(container_content)
                    rootfile = container_root.find('.//{urn:oasis:names:tc:opendocument:xmlns:container}rootfile')
                    if rootfile is not None:
                        opf_path = rootfile.get('full-path')
                except Exception:
                    pass

                if not opf_path:
                    for name in zf.namelist():
                        if name.endswith('content.opf') or name.endswith('.opf'):
                            opf_path = name
                            break

                if not opf_path:
                    return results

                opf_content = zf.read(opf_path)
                root = ET.fromstring(opf_content)

                ns = {'opf': 'http://www.idpf.org/2007/opf'}
                if root.tag.startswith('{'):
                    default_ns = root.tag[1:root.tag.index('}')]
                    ns = {'opf': default_ns}

                # Build manifest
                manifest = {}
                for item in root.findall('.//opf:manifest/opf:item', ns):
                    item_id = item.get('id')
                    href = item.get('href')
                    media_type = item.get('media-type', '')
                    if item_id and href and (
                        'html' in media_type.lower() or
                        href.endswith(('.html', '.xhtml', '.htm'))
                    ):
                        manifest[item_id] = os.path.basename(href)

                # Get spine order
                spine = root.find('.//opf:spine', ns)
                spine_items = []
                if spine is not None:
                    for itemref in spine.findall('opf:itemref', ns):
                        idref = itemref.get('idref')
                        if idref and idref in manifest:
                            spine_items.append(manifest[idref])

                if spine_mode:
                    for i, fname in enumerate(spine_items):
                        raw_pos = i + 1
                        if not (start <= raw_pos <= end):
                            continue
                        skip_this = self._should_skip_special_file(fname, translate_special)
                        results.append((f"[{raw_pos:03d}]", fname, skip_this))
                else:
                    # Range refers to chapter numbers parsed from filenames
                    for i, fname in enumerate(spine_items):
                        is_special = self._is_special_file(fname)
                        skip_this = self._should_skip_special_file(fname, translate_special)

                        if is_special:
                            chap_num = 0
                        else:
                            matches = re.findall(r'(\d+)', fname)
                            if matches:
                                chap_num = int(matches[-1])
                            else:
                                chap_num = 0
                        if start <= chap_num <= end:
                            if skip_this:
                                results.append((f"Ch.{chap_num}", fname, True))
                            else:
                                results.append((f"Ch.{chap_num}", fname, False))

        except Exception as e:
            print(f"⚠️ Could not preview chapter range: {e}")

        return results

    def _get_opf_file_order(self, file_list):
        """
        Sort files based on OPF spine order if available.
        Uses STRICT OPF ordering - includes ALL files from spine without filtering.
        This ensures notice files, copyright pages, etc. are processed in the correct order.
        Returns sorted file list based on OPF, or original list if no OPF found.
        """
        try:
            import xml.etree.ElementTree as ET
            import zipfile
            import re
            
            # First, check if we have content.opf in the current directory
            opf_file = None
            if file_list:
                current_dir = os.path.dirname(file_list[0]) if file_list else os.getcwd()
                possible_opf = os.path.join(current_dir, 'content.opf')
                if os.path.exists(possible_opf):
                    opf_file = possible_opf
                    self.append_log(f"📋 Found content.opf in directory")
            
            # If no OPF, check if any of the files is an OPF
            if not opf_file:
                for file_path in file_list:
                    if file_path.lower().endswith('.opf'):
                        opf_file = file_path
                        self.append_log(f"📋 Found OPF file: {os.path.basename(opf_file)}")
                        break
            
            # If no OPF, try to extract from EPUB
            if not opf_file:
                epub_files = [f for f in file_list if f.lower().endswith('.epub')]
                if epub_files:
                    epub_path = epub_files[0]
                    try:
                        with zipfile.ZipFile(epub_path, 'r') as zf:
                            for name in zf.namelist():
                                if name.endswith('.opf'):
                                    opf_content = zf.read(name)
                                    temp_opf = os.path.join(os.path.dirname(epub_path), 'temp_content.opf')
                                    with open(temp_opf, 'wb') as f:
                                        f.write(opf_content)
                                    opf_file = temp_opf
                                    self.append_log(f"📋 Extracted OPF from EPUB: {os.path.basename(epub_path)}")
                                    break
                    except Exception as e:
                        self.append_log(f"⚠️ Could not extract OPF from EPUB: {e}")
            
            if not opf_file:
                self.append_log(f"ℹ️ No OPF file found, using default file order")
                return file_list
            
            # Parse the OPF file
            try:
                tree = ET.parse(opf_file)
                root = tree.getroot()
                
                # Handle namespaces
                ns = {'opf': 'http://www.idpf.org/2007/opf'}
                if root.tag.startswith('{'):
                    default_ns = root.tag[1:root.tag.index('}')]
                    ns = {'opf': default_ns}
                
                # Get manifest to map IDs to files
                manifest = {}
                for item in root.findall('.//opf:manifest/opf:item', ns):
                    item_id = item.get('id')
                    href = item.get('href')
                    
                    if item_id and href:
                        filename = os.path.basename(href)
                        manifest[item_id] = filename
                        # Store multiple variations for matching
                        name_without_ext = os.path.splitext(filename)[0]
                        manifest[item_id + '_noext'] = name_without_ext
                        # Also store with response_ prefix for matching
                        manifest[item_id + '_response'] = f"response_{filename}"
                        manifest[item_id + '_response_noext'] = f"response_{name_without_ext}"
                
                # Get spine order - include ALL files first for correct indexing
                spine_order_full = []
                spine = root.find('.//opf:spine', ns)
                if spine is not None:
                    for itemref in spine.findall('opf:itemref', ns):
                        idref = itemref.get('idref')
                        if idref and idref in manifest:
                            spine_order_full.append(manifest[idref])
                
                # Now filter out special files for processing (unless override is enabled)
                translate_special = os.environ.get('TRANSLATE_SPECIAL_FILES', '0') == '1'
                
                spine_order = []
                for item in spine_order_full:
                    # Numbered special files may be translated, but they still
                    # remain special for chapter numbering/progress display.
                    if not self._should_skip_special_file(item, translate_special):
                        spine_order.append(item)
                
                self.append_log(f"📋 Found {len(spine_order_full)} items in OPF spine ({len(spine_order)} after filtering)")
                
                # Count file types
                notice_count = sum(1 for f in spine_order if 'notice' in f.lower())
                chapter_count = sum(1 for f in spine_order if 'chapter' in f.lower() and 'notice' not in f.lower())
                skipped_count = len(spine_order_full) - len(spine_order)
                
                if skipped_count > 0:
                    self.append_log(f"   • Skipped files (cover/nav/toc): {skipped_count}")
                if notice_count > 0:
                    self.append_log(f"   • Notice/Copyright files: {notice_count}")
                if chapter_count > 0:
                    self.append_log(f"   • Chapter files: {chapter_count}")
                
                # Show first few spine entries
                if spine_order:
                    self.append_log(f"   📖 Spine order preview:")
                    for i, entry in enumerate(spine_order[:5]):
                        self.append_log(f"      [{i}]: {entry}")
                    if len(spine_order) > 5:
                        self.append_log(f"      ... and {len(spine_order) - 5} more")
                
                # Map input files to spine positions
                ordered_files = []
                unordered_files = []
                
                for file_path in file_list:
                    basename = os.path.basename(file_path)
                    basename_noext = os.path.splitext(basename)[0]
                    
                    # Try to find this file in the spine
                    found_position = None
                    matched_spine_file = None
                    
                    # Direct exact match
                    if basename in spine_order:
                        found_position = spine_order.index(basename)
                        matched_spine_file = basename
                    # Match without extension
                    elif basename_noext in spine_order:
                        found_position = spine_order.index(basename_noext)
                        matched_spine_file = basename_noext
                    else:
                        # Try pattern matching for response_ files
                        for idx, spine_item in enumerate(spine_order):
                            spine_noext = os.path.splitext(spine_item)[0]
                            
                            # Check if this is a response_ file matching spine item
                            if basename.startswith('response_'):
                                # Remove response_ prefix and try to match
                                clean_name = basename[9:]  # Remove 'response_'
                                clean_noext = os.path.splitext(clean_name)[0]
                                
                                if clean_name == spine_item or clean_noext == spine_noext:
                                    found_position = idx
                                    matched_spine_file = spine_item
                                    break
                                
                                # Try matching by chapter number
                                spine_num = re.search(r'(\d+)', spine_item)
                                file_num = re.search(r'(\d+)', clean_name)
                                if spine_num and file_num and spine_num.group(1) == file_num.group(1):
                                    # Check if both are notice or both are chapter files
                                    both_notice = 'notice' in spine_item.lower() and 'notice' in clean_name.lower()
                                    both_chapter = 'chapter' in spine_item.lower() and 'chapter' in clean_name.lower()
                                    if both_notice or both_chapter:
                                        found_position = idx
                                        matched_spine_file = spine_item
                                        break
                            else:
                                # For non-response files, check if spine item is contained
                                if spine_noext in basename_noext:
                                    found_position = idx
                                    matched_spine_file = spine_item
                                    break
                                
                                # Number-based matching
                                spine_num = re.search(r'(\d+)', spine_item)
                                file_num = re.search(r'(\d+)', basename)
                                if spine_num and file_num and spine_num.group(1) == file_num.group(1):
                                    # Check file type match
                                    both_notice = 'notice' in spine_item.lower() and 'notice' in basename.lower()
                                    both_chapter = 'chapter' in spine_item.lower() and 'chapter' in basename.lower()
                                    if both_notice or both_chapter:
                                        found_position = idx
                                        matched_spine_file = spine_item
                                        break
                    
                    if found_position is not None:
                        ordered_files.append((found_position, file_path))
                        self.append_log(f"  ✓ Matched: {basename} → spine[{found_position}]: {matched_spine_file}")
                    else:
                        unordered_files.append(file_path)
                        self.append_log(f"  ⚠️ Not in spine: {basename}")
                
                # Sort by spine position
                ordered_files.sort(key=lambda x: x[0])
                final_order = [f for _, f in ordered_files]
                
                # Add unmapped files at the end
                if unordered_files:
                    self.append_log(f"📋 Adding {len(unordered_files)} unmapped files at the end")
                    final_order.extend(sorted(unordered_files))
                
                # Clean up temp OPF if created
                if opf_file and 'temp_content.opf' in opf_file and os.path.exists(opf_file):
                    try:
                        os.remove(opf_file)
                    except:
                        pass
                
                self.append_log(f"✅ Files sorted using STRICT OPF spine order")
                self.append_log(f"   • Total files: {len(final_order)}")
                self.append_log(f"   • Following exact spine sequence from OPF")
                
                return final_order if final_order else file_list
                
            except Exception as e:
                self.append_log(f"⚠️ Error parsing OPF file: {e}")
                if opf_file and 'temp_content.opf' in opf_file and os.path.exists(opf_file):
                    try:
                        os.remove(opf_file)
                    except:
                        pass
                return file_list
                
        except Exception as e:
            self.append_log(f"⚠️ Error in OPF sorting: {e}")
            return file_list
 
    def run_translation_thread(self):
        """Start translation in a background worker (ThreadPoolExecutor)"""
        # Prevent overlap with glossary extraction
        if (hasattr(self, 'glossary_thread') and self.glossary_thread and self.glossary_thread.is_alive()) or \
           (hasattr(self, 'glossary_future') and self.glossary_future and not self.glossary_future.done()):
            self.append_log("⚠️ Cannot run translation while glossary extraction is in progress.")
            QMessageBox.warning(self, "Process Running", "Please wait for glossary extraction to complete before starting translation.")
            return
        
        if self.translation_thread and self.translation_thread.is_alive():
            self.stop_translation()
            return
        
        # Double-click force stop: if a graceful stop just finished (thread no longer
        # alive) but the user clicks again within 2 seconds, treat it as a force-stop
        # request instead of starting a new translation.  This prevents the race where
        # the translation thread dies between the two clicks of a double-click.
        import time as _time_mod
        _last_stop_ts = getattr(self, '_last_stop_translation_ts', 0)
        _was_graceful = getattr(self, '_last_stop_was_graceful', False)
        if _was_graceful and (_time_mod.time() - _last_stop_ts) < 2.0:
            self.append_log("⚡ Double-click detected after graceful stop — forcing hard cancel!")
            self._last_stop_was_graceful = False
            self.stop_requested = True
            self.graceful_stop_active = False
            os.environ['GRACEFUL_STOP'] = '0'
            os.environ['GRACEFUL_STOP_COMPLETED'] = '0'
            os.environ['TRANSLATION_CANCELLED'] = '1'
            os.environ['WAIT_FOR_CHUNKS'] = '0'
            try:
                import unified_api_client
                if hasattr(unified_api_client, 'set_stop_flag'):
                    unified_api_client.set_stop_flag(True)
                if hasattr(unified_api_client, 'hard_cancel_all'):
                    unified_api_client.hard_cancel_all()
                if hasattr(unified_api_client, '_api_watchdog_reset'):
                    unified_api_client._api_watchdog_reset()
            except Exception:
                pass
            try:
                self._reset_api_watchdog_progress(clear_stale_external_files=True)
            except Exception:
                pass
            return
        
        # Check if files are selected
        _model_name = str(getattr(self, 'model_var', ''))
        _is_generative_model = self._model_is_image_gen(_model_name) or self._model_is_video_gen(_model_name) or self._is_generative_output_mode()

        if not hasattr(self, 'selected_files') or not self.selected_files:
            file_path = self.entry_epub.text().strip()
            if not file_path or file_path.startswith("No file selected") or "files selected" in file_path:
                if _is_generative_model:
                    # Image/video generation models don't need an input file;
                    # use a synthetic sentinel so the rest of the pipeline works
                    self.selected_files = ["__generative_mode__"]
                    self.append_log(
                        f"\ud83c\udfa8 Generative model detected ({_model_name}) – "
                        "running without an input file."
                    )
                else:
                    QMessageBox.critical(self, "Error", "Please select file(s) to translate.")
                    return
            else:
                self.selected_files = [file_path]
                self.selected_files = self._normalize_windows_input_filenames(self.selected_files)
                file_path = self.selected_files[0]
            
            # Auto-clear glossary if file doesn't match (works for both manual and auto-loaded)
            if self.manual_glossary_path:
                current_file_base = os.path.splitext(os.path.basename(file_path))[0]
                # Check both glossary filename AND parent folder name
                glossary_full_path = self.manual_glossary_path
                glossary_name = os.path.basename(glossary_full_path)
                glossary_parent = os.path.basename(os.path.dirname(glossary_full_path))
                
                # Check if the current file's base name appears in the glossary path (filename or parent folder)
                if current_file_base not in glossary_name and current_file_base not in glossary_parent:
                    # Glossary doesn't match, clear it
                    old_glossary = glossary_full_path
                    was_manual = getattr(self, 'manual_glossary_manually_loaded', False)
                    source_type = "manually loaded" if was_manual else "auto-loaded"
                    self.append_log(f"📑 Cleared {source_type} glossary from different source: {os.path.basename(os.path.dirname(old_glossary))}")
                    self.manual_glossary_path = None
                    self.manual_glossary_manually_loaded = False
                    self.auto_loaded_glossary_path = None
                    self.auto_loaded_glossary_for_file = None
        else:
            self.selected_files = self._normalize_windows_input_filenames(self.selected_files)
        
        # Record every selected raw input in the Library's raw-inputs
        # registry so the library dialog can find it later (even if the
        # file itself lives outside the Library folder).
        if not getattr(self, '_input_output_run_active', False):
            try:
                from epub_library import record_library_raw_input
                for _p in (self.selected_files or []):
                    if _p and os.path.isfile(_p):
                        record_library_raw_input(_p)
            except Exception:
                pass

        # Reset stop flags
        self.stop_requested = False
        self._glossary_stop_was_requested = False  # Reset glossary stop flag from previous run
        self._translation_anti_duplicate_logged = False
        self.graceful_stop_active = False  # Reset graceful stop state
        self._zip_inputs_resolved_for_current_run = False
        os.environ.pop('TRANSLATION_CANCELLED', None)  # Clear hard-stop state from previous run
        os.environ.pop('TRANSLATION_ANTI_DUPLICATE_LOGGED', None)
        os.environ['GRACEFUL_STOP'] = '0'  # Reset graceful stop env var
        os.environ['GRACEFUL_STOP_COMPLETED'] = '0'  # Reset completion flag
        os.environ['WAIT_FOR_CHUNKS'] = '0'  # Reset graceful batch-stop mode
        os.environ['GRACEFUL_STOP_API_ACTIVE'] = '0'  # Reset API active flag

        # Assign a new run id so transport logs (httpx) can be suppressed for stale previous runs
        try:
            import uuid as _uuid
            os.environ['GLOSSARION_RUN_ID'] = _uuid.uuid4().hex[:10]
        except Exception:
            os.environ['GLOSSARION_RUN_ID'] = str(int(time.time()))

        self._clear_translation_run_overrides()
        try:
            multipass_enabled, multipass_refinement_mode = self._export_multipass_runtime_env()
            multipass_refinement_mode_label = (
                'Full + raw'
                if multipass_refinement_mode == 'full_with_raw'
                else multipass_refinement_mode.replace('_', ' ').title()
            )
            targeted_refinement_failures = self._prepare_multipass_qa_refinement_run(
                multipass_enabled,
                multipass_refinement_mode,
            )
            if multipass_enabled:
                self.append_log(
                    f"Multipass refinement mode: {multipass_refinement_mode_label} "
                    "(exported for translation)"
                )
            if targeted_refinement_failures:
                chapters = [failure["chapter"] for failure in targeted_refinement_failures]
                self.append_log(
                    f"{multipass_refinement_mode_label} multipass: existing foreign-character QA failures found; "
                    "running refinement instead of translation "
                    f"(chapters: {self._format_chapter_list(chapters)})"
                )
                skipped_failures = getattr(self, '_translation_run_skipped_qa_failures', [])
                if skipped_failures:
                    skipped_chapters = [failure["chapter"] for failure in skipped_failures]
                    self.append_log(
                        "Other QA-failed entries will be retried through normal translation after refinement "
                        f"(chapters: {self._format_chapter_list(skipped_chapters)})"
                    )
        except Exception as e:
            self.append_log(f"Warning: Could not export multipass refinement mode: {e}")

        if translation_stop_flag:
            translation_stop_flag(False)
        
        # Also reset the module's internal stop flag
        try:
            if hasattr(self, '_main_module') and self._main_module:
                if hasattr(self._main_module, 'set_stop_flag'):
                    self._main_module.set_stop_flag(False)
        except:
            pass

        # CRITICAL: Before starting a new run, hard-cancel any lingering streams
        # from the previous run.  A graceful stop does NOT call hard_cancel_all(),
        # so glossary/translation streams can still be alive and printing output.
        # Close them NOW before we reset the stop flags (otherwise they'd keep running
        # after we clear _global_cancelled and leak into the new translation phase).
        try:
            import unified_api_client
            # Close lingering streams/sessions from any previous run
            # (hard_cancel_all also resets the watchdog internally)
            if hasattr(unified_api_client, 'UnifiedClient'):
                try:
                    unified_api_client.UnifiedClient.hard_cancel_all()
                except Exception:
                    pass
        except Exception:
            pass

        # Reset unified_api_client global cancellation (streaming stop) for new runs
        try:
            import unified_api_client
            if hasattr(unified_api_client, 'set_stop_flag'):
                unified_api_client.set_stop_flag(False)
            elif hasattr(unified_api_client, 'UnifiedClient'):
                unified_api_client.UnifiedClient.set_global_cancellation(False)
        except Exception:
            pass

        # Create a watchdog snapshot immediately when starting translation
        try:
            self._create_watchdog_snapshot(context="translation", model=getattr(self, 'model_var', None))
        except Exception:
            pass

        # Prepare shared stop-file for glossary/translation workers
        try:
            import tempfile, os as _os
            stop_file = os.environ.get('GLOSSARY_STOP_FILE') or _os.path.join(
                tempfile.gettempdir(), f"glossarion_glossary_stop_{_os.getpid()}.flag"
            )
            os.environ['GLOSSARY_STOP_FILE'] = stop_file
            if _os.path.exists(stop_file):
                _os.remove(stop_file)
        except Exception:
            pass
        
        # Update button immediately to show translation is starting
        if hasattr(self, 'button_run'):
            self.button_run.config(text="⏹ Stop", state="normal")
        
        # Delay auto-scroll so first log is readable (set to 0 for immediate scrolling)
        self._start_autoscroll_delay(0)
        # Show immediate feedback that translation is starting
        if getattr(self, '_translation_run_is_multipass_qa_refinement', False):
            mode_label = str(getattr(self, '_translation_run_qa_refinement_mode', '') or 'multipass').title()
            self.append_log(f"🚀 Initializing {mode_label} multipass refinement...")
        else:
            self.append_log("🚀 Initializing translation process...")
        
        # Debug: Log stop behavior settings
        graceful_stop = getattr(self, 'graceful_stop_var', False)
        wait_for_chunks = getattr(self, 'wait_for_chunks_var', False)
        print(f"🔧 Stop settings: graceful_stop={graceful_stop}, wait_for_chunks={wait_for_chunks}")
        # Force immediate scroll to bottom so user sees the latest output right away
        try:
            scrollbar = self.log_text.verticalScrollBar()
            scrollbar.setValue(scrollbar.maximum())
        except Exception:
            pass
        try:
            self._log_translation_qa_failure_summary(phase="start")
        except Exception as e:
            self.append_log(f"⚠️ Could not read existing QA failure summary: {e}")
        # Reset stop notice dedupe flag at start of a run
        self._stop_notice_shown = False
        
        # SIMPLIFIED: Skip the wrapper and call run_translation_direct in a thread
        def simple_thread_target():
            try:
                self.append_log("🟢 Thread started successfully!")
                
                # Load modules if needed
                if not self._modules_loaded:
                    self.append_log("📬 Loading translation modules...")
                    if not self._lazy_load_modules():
                        self.append_log("❌ Failed to load modules")
                        return
                    self.append_log("✅ Modules loaded")

                if any(str(f).lower().endswith(('.zip', '.cbz')) for f in getattr(self, 'selected_files', []) or []):
                    self.append_log("📦 Preparing image archive input(s) in translation worker...")
                    self._resolve_zip_inputs_for_translation()
                    if self.stop_requested:
                        return
                
                # Check for large EPUBs and set optimization parameters
                epub_files = [f for f in self.selected_files if f.lower().endswith('.epub')]
                
                for epub_path in epub_files:
                    try:
                        import zipfile
                        with zipfile.ZipFile(epub_path, 'r') as zf:
                            # Quick count without reading content
                            html_files = [f for f in zf.namelist() if f.lower().endswith(('.html', '.xhtml', '.htm'))]
                            file_count = len(html_files)
                            
                            if file_count > 50:
                                self.append_log(f"📚 Large EPUB detected: {file_count} chapters")
                                
                                # Get user-configured worker count
                                if hasattr(self, 'config') and 'extraction_workers' in self.config:
                                    max_workers = self.config.get('extraction_workers', 2)
                                else:
                                    # Fallback to environment variable or default
                                    max_workers = int(os.environ.get('EXTRACTION_WORKERS', '2'))
                                
                                # Set extraction parameters
                                os.environ['EXTRACTION_WORKERS'] = str(max_workers)
                                os.environ['EXTRACTION_PROGRESS_CALLBACK'] = 'enabled'
                                
                                # Set progress interval based on file count
                                if file_count > 500:
                                    progress_interval = 50
                                    os.environ['EXTRACTION_BATCH_SIZE'] = '100'
                                    self.append_log(f"⚡ Using {max_workers} workers with batch size 100")
                                elif file_count > 200:
                                    progress_interval = 25
                                    os.environ['EXTRACTION_BATCH_SIZE'] = '50'
                                    self.append_log(f"⚡ Using {max_workers} workers with batch size 50")
                                elif file_count > 100:
                                    progress_interval = 20
                                    os.environ['EXTRACTION_BATCH_SIZE'] = '25'
                                    self.append_log(f"⚡ Using {max_workers} workers with batch size 25")
                                else:
                                    progress_interval = 10
                                    os.environ['EXTRACTION_BATCH_SIZE'] = '20'
                                    self.append_log(f"⚡ Using {max_workers} workers with batch size 20")
                                
                                os.environ['EXTRACTION_PROGRESS_INTERVAL'] = str(progress_interval)
                                
                                # Enable performance flags for large files
                                os.environ['FAST_EXTRACTION'] = '1'
                                os.environ['PARALLEL_PARSE'] = '1'
                                
                    except Exception as e:
                        # If we can't check, just continue
                        pass
                
                # Set essential environment variables from current config before translation
                os.environ['BATCH_TRANSLATE_HEADERS'] = '1' if self.config.get('batch_translate_headers', True) else '0'
                os.environ['IGNORE_HEADER'] = '1' if self.config.get('ignore_header', False) else '0'
                os.environ['ALLOW_AI_MARKDOWN_HEADERS'] = '1' if self.config.get('allow_ai_markdown_headers', False) else '0'
                os.environ['USE_TITLE'] = '1' if self.config.get('use_title', False) else '0'
                os.environ['REMOVE_DUPLICATE_H1_P'] = '1' if self.config.get('remove_duplicate_h1_p', False) else '0'
                os.environ['FIX_STRAY_P_GT_EPUB'] = '1' if self.config.get('fix_stray_p_gt_epub', False) else '0'
                os.environ['FIX_STRAY_P_GT_BS'] = '1' if self.config.get('fix_stray_p_gt_bs', False) else '0'
                os.environ['USE_SORTED_FALLBACK'] = '1' if self.config.get('use_sorted_fallback', False) else '0'
                # Update temperature and max output tokens from GUI's current values
                os.environ['TRANSLATION_TEMPERATURE'] = str(self.trans_temp.text())
                os.environ['DISABLE_TEMPERATURE'] = '1' if self.disable_temperature_var else '0'
                os.environ['MAX_OUTPUT_TOKENS'] = str(self.max_output_tokens)
                # Set batch header translation prompts from config
                _output_lang = self.config.get('output_language', 'English')
                os.environ['BATCH_HEADER_SYSTEM_PROMPT'] = self.config.get('batch_header_system_prompt', '').replace('{target_lang}', _output_lang)
                os.environ['BATCH_HEADER_PROMPT'] = self.config.get('batch_header_prompt', '').replace('{target_lang}', _output_lang)
                os.environ['BATCH_HEADER_PREPEND_NUMBER_PATTERN'] = str(
                    self.config.get('batch_header_prepend_number_pattern', '') or '')
                os.environ['OUTPUT_LANGUAGE'] = _output_lang
                
                # ===== PRE-TRANSLATION GLOSSARY EXTRACTION (Balanced/Full modes) =====
                auto_glossary_mode = self._current_auto_glossary_mode()

                if getattr(self, '_single_chapter_filter', None) and auto_glossary_mode in ('balanced', 'full'):
                    self.append_log("🎯 Single-chapter mode: skipping auto glossary extraction (jumping straight to translation)")
                    auto_glossary_mode = 'off'

                current_output_mode = self._active_translation_output_mode()
                if current_output_mode == 'refinement' and auto_glossary_mode in ('balanced', 'full'):
                    self.append_log("✨ Skipping auto glossary extraction for refinement mode")
                    auto_glossary_mode = 'off'
                elif current_output_mode == 'audio' and auto_glossary_mode in ('balanced', 'full'):
                    self.append_log("📑 Skipping auto glossary extraction for Audio output mode")
                    auto_glossary_mode = 'off'
                
                if current_output_mode == 'vision' and auto_glossary_mode in ('balanced', 'full'):
                    glossary_merging_enabled, glossary_merge_count, glossary_chapter_split = self._current_glossary_request_env(
                        force_balanced_request_merging=(auto_glossary_mode == 'balanced')
                    )
                    os.environ['GLOSSARY_REQUEST_MERGING_ENABLED'] = glossary_merging_enabled
                    os.environ['GLOSSARY_ENABLE_CHAPTER_SPLIT'] = glossary_chapter_split
                    os.environ['GLOSSARY_REQUEST_MERGE_COUNT'] = glossary_merge_count
                    self.append_log(f"📑 Vision mode: OCR prepass will run before glossary extraction (merge count: {glossary_merge_count})")
                elif auto_glossary_mode in ('balanced', 'full'):
                    # Check if a glossary was MANUALLY loaded by the user for this file
                    # Auto-loaded glossaries (from autofill) could be incomplete from a stopped extraction
                    has_existing_glossary = bool(
                        getattr(self, 'manual_glossary_path', None) and 
                        os.path.exists(getattr(self, 'manual_glossary_path', '')) and
                        getattr(self, 'manual_glossary_manually_loaded', False)
                    )
                    
                    if not has_existing_glossary:
                        # Clear any auto-loaded glossary before re-extraction
                        # (it may be incomplete from a previous stopped extraction)
                        if (getattr(self, 'manual_glossary_path', None) and 
                            not getattr(self, 'manual_glossary_manually_loaded', False)):
                            self.append_log(f"📑 Clearing auto-loaded glossary for fresh extraction")
                            self.manual_glossary_path = None
                            os.environ.pop('MANUAL_GLOSSARY', None)
                        
                        mode_display = auto_glossary_mode.capitalize()
                        self.append_log(f"\n{'='*60}")
                        self.append_log(f"📑 Auto Glossary Mode: {mode_display}")
                        
                        # Apply invisible hardcoded overrides for Balanced mode
                        # (text/EPUB-specific; skip for image-only inputs)
                        saved_env = {}
                        image_exts = {'.png', '.jpg', '.jpeg', '.gif', '.bmp', '.webp'}
                        has_text_files = any(
                            os.path.splitext(f)[1].lower() not in image_exts
                            for f in getattr(self, 'selected_files', [])
                        )
                        if auto_glossary_mode == 'balanced' and has_text_files:
                            _balanced_merge_enabled, _balanced_merge_count, _balanced_chapter_split = self._current_glossary_request_env(
                                force_balanced_request_merging=True
                            )
                            split_status = "enabled" if _balanced_chapter_split == '1' else "disabled"
                            self.append_log(f"📑 Balanced mode: request merging enabled (99), dynamic request splitting {split_status}")
                            self.append_log(f"📑 Request merging is hardcoded for optimal glossary quality")
                            saved_env = {
                                'GLOSSARY_REQUEST_MERGING_ENABLED': os.environ.get('GLOSSARY_REQUEST_MERGING_ENABLED'),
                                'GLOSSARY_REQUEST_MERGE_COUNT': os.environ.get('GLOSSARY_REQUEST_MERGE_COUNT'),
                                'GLOSSARY_ENABLE_CHAPTER_SPLIT': os.environ.get('GLOSSARY_ENABLE_CHAPTER_SPLIT'),
                            }
                            os.environ['GLOSSARY_REQUEST_MERGING_ENABLED'] = _balanced_merge_enabled
                            os.environ['GLOSSARY_REQUEST_MERGE_COUNT'] = _balanced_merge_count
                            os.environ['GLOSSARY_ENABLE_CHAPTER_SPLIT'] = _balanced_chapter_split
                        elif auto_glossary_mode == 'balanced':
                            self.append_log(f"📑 Balanced mode: image glossary extraction")
                        elif has_text_files:  # full + text
                            self.append_log(f"📑 Full mode: chapter-by-chapter extraction (most thorough)")
                        else:  # full + images only
                            self.append_log(f"📑 Full mode: image glossary extraction")
                        
                        self.append_log(f"📑 Running glossary extraction before translation...")
                        self.append_log(f"{'='*60}")
                        
                        try:
                            # Reuse the exact same Extract Glossary flow
                            self._glossary_stop_was_requested = False  # Reset before extraction
                            self.run_glossary_extraction_direct(
                                force_balanced_request_merging=(auto_glossary_mode == 'balanced' and has_text_files)
                            )
                            
                            # Check saved stop flag (run_glossary_extraction_direct resets self.stop_requested in finally)
                            if self.stop_requested or getattr(self, '_glossary_stop_was_requested', False):
                                self.append_log("⏹️ Translation cancelled during glossary extraction")
                                # Clear auto-loaded glossary so next run re-extracts
                                if not getattr(self, 'manual_glossary_manually_loaded', False):
                                    self.manual_glossary_path = None
                                    os.environ.pop('MANUAL_GLOSSARY', None)
                                return
                            
                            # Auto-load the generated glossary (only if extraction completed fully)
                            generated_glossary = self._auto_load_glossary_after_extraction()

                            if getattr(self, '_input_output_run_active', False):
                                self.append_log(
                                    "⏸️ Direct Text: glossary generation is complete; "
                                    "waiting for approval before translation"
                                )
                                if not self._await_direct_text_glossary_approval(
                                    generated_glossary
                                    or getattr(self, 'manual_glossary_path', '')
                                ):
                                    self.append_log(
                                        "⏹️ Direct Text translation cancelled at "
                                        "the glossary approval step"
                                    )
                                    return

                            self.append_log(f"\n📑 Glossary extraction complete, proceeding to translation...")
                        except Exception as e:
                            self.append_log(f"⚠️ Glossary extraction failed: {e}")
                            self.append_log(f"📑 Continuing translation without auto-generated glossary")
                        finally:
                            # Restore env vars for Balanced mode
                            if saved_env:
                                for key, val in saved_env.items():
                                    if val is None:
                                        os.environ.pop(key, None)
                                    else:
                                        os.environ[key] = val
                    else:
                        self.append_log(f"📑 Glossary already loaded, skipping auto-extraction")
                # ===== END PRE-TRANSLATION GLOSSARY EXTRACTION =====
                
                # Call the direct function
                if getattr(self, '_translation_run_is_multipass_qa_refinement', False):
                    mode_label = str(getattr(self, '_translation_run_qa_refinement_mode', '') or 'multipass').title()
                    self.append_log(f"🚀 Starting {mode_label} multipass refinement...")
                else:
                    self.append_log("🚀 Starting translation...")
                translation_completed = self.run_translation_direct()
                if (
                    translation_completed
                    and not self.stop_requested
                    and getattr(self, '_translation_run_followup_translation_after_refinement', False)
                ):
                    skipped_failures = list(getattr(self, '_translation_run_skipped_qa_failures', []))
                    skipped_chapters = [failure["chapter"] for failure in skipped_failures]
                    self._clear_translation_run_overrides()
                    self.append_log(
                        "🚀 Starting regular translation retry for skipped QA-failed entries "
                        f"(chapters: {self._format_chapter_list(skipped_chapters)})"
                    )
                    translation_completed = self.run_translation_direct()
                
                # Post-translation scanning phase
                # If scanning phase toggle is enabled, launch scanner after translation
                # BUT only if translation completed successfully (not stopped by user)
                # SKIP scanning for CSV/JSON files (they are plain text glossaries, not translations)
                # SKIP scanning for image files (they are image translations, not text documents)
                try:
                    # Check if any of the files are CSV/JSON (but NOT TXT - TXT files are valid translation sources)
                    csv_json_files = [f for f in self.selected_files if f.lower().endswith(('.csv', '.json'))]
                    
                    # Check if any files are images
                    image_extensions = {'.png', '.jpg', '.jpeg', '.gif', '.bmp', '.webp'}
                    image_files = [f for f in self.selected_files if os.path.splitext(f)[1].lower() in image_extensions]
                    sdlxliff_files = [f for f in self.selected_files if f.lower().endswith('.sdlxliff')]
                    
                    if csv_json_files:
                        self.append_log("📑 Skipping post-translation scanning for CSV/JSON files")
                    elif image_files:
                        self.append_log("🖼️ Skipping post-translation scanning for image files")
                    if sdlxliff_files:
                        self.append_log("SDLXLIFF: skipping post-translation scanner")
                    current_run_output_mode = self._active_translation_output_mode()
                    if csv_json_files or image_files or sdlxliff_files:
                        pass
                    elif current_run_output_mode == 'refinement':
                        self.append_log("✨ Skipping post-translation scanning for refinement mode")
                    elif current_run_output_mode == 'image':
                        self.append_log("🖼️ Skipping post-translation scanning for image output mode")
                    elif (not getattr(self, '_input_output_run_active', False)
                          and hasattr(self, 'scan_phase_enabled_var')
                          and self.scan_phase_enabled_var
                          and translation_completed
                          and not self.stop_requested):
                        mode = self._get_scan_phase_mode()
                        self.append_log(f"🧪 Scanning phase enabled — launching QA Scanner in {mode} mode...")
                        # Emit signal to trigger QA scan on main thread
                        self.trigger_qa_scan_signal.emit()
                except Exception as e:
                    self.append_log(f"⚠️ Could not launch post-translation scan: {e}")
                    import traceback
                    self.append_log(traceback.format_exc())
                
            except Exception as e:
                self.append_log(f"❌ Error in thread: {e}")
                import traceback
                self.append_log(traceback.format_exc())
            finally:
                # Clean up environment variables
                env_vars = [
                    'EXTRACTION_WORKERS', 'EXTRACTION_BATCH_SIZE',
                    'EXTRACTION_PROGRESS_CALLBACK', 'EXTRACTION_PROGRESS_INTERVAL',
                    'FAST_EXTRACTION', 'PARALLEL_PARSE'
                ]
                for var in env_vars:
                    if var in os.environ:
                        del os.environ[var]

                # Single-chapter mode is strictly per-run — never leak the
                # filter (or forced streaming) into the next regular run.
                self._single_chapter_filter = None
                self._force_stream_all = False
                os.environ.pop('SINGLE_CHAPTER_FILTER', None)

                self._clear_translation_run_overrides()
                # Reset stop flags ONCE, at the true end of the (possibly
                # multi-phase) run. Moved here from run_translation_direct() so a
                # chained phase (refinement → followup translation) does not reset
                # Stop mid-run. The next run's setup also resets these, so this is
                # just clean end-of-run state.
                self.stop_requested = False
                try:
                    if translation_stop_flag:
                        translation_stop_flag(False)
                    if (hasattr(self, '_main_module') and self._main_module
                            and hasattr(self._main_module, 'set_stop_flag')):
                        self._main_module.set_stop_flag(False)
                except Exception:
                    pass
                self.translation_thread = None
                # Emit signal to update button (thread-safe)
                self.thread_complete_signal.emit()
        
        thread_name = f"TranslationThread_{int(time.time())}"
        self.translation_thread = threading.Thread(
            target=simple_thread_target,
            name=thread_name,
            daemon=True
        )
        self.translation_thread.start()
        
        # Update button IMMEDIATELY after starting thread (synchronous)
        self.update_run_button()
        
        self.append_log("🟡 Thread started...")

    def _run_generative_prompt_mode(self):
        """Run a single image/video generation call when no input file was provided.

        The user prompt is taken from:
          1. The 'translation_chunk_prompt' config value (the main prompt field), or
          2. The system prompt, or
          3. A sensible fallback.

        The result (image URL, video URL, or generated text) is logged to the
        GUI and also saved to a timestamped .txt file next to the executable.
        """
        try:
            model = str(getattr(self, 'model_var', '')).strip()
            self.append_log(f"\ud83c\udfa8 Generative mode: sending prompt to {model}\u2026")

            # Build the user prompt from available config fields.
            # The system prompt lives in the prompt_text QTextEdit widget.
            system_prompt = ''
            try:
                system_prompt = self.prompt_text.toPlainText().strip()
            except Exception:
                pass
            if not system_prompt:
                system_prompt = str(self.config.get('system_prompt', '') or '').strip()

            user_prompt = ''
            # 1. Prefer system prompt — it's the actual descriptive prompt the user wrote
            if system_prompt:
                user_prompt = system_prompt
            # 2. Try image-specific chunk prompt (only if not a template)
            if not user_prompt:
                val = getattr(self, 'image_chunk_prompt', '') or self.config.get('image_chunk_prompt', '')
                if val and val.strip() and '{chunk_html}' not in val and '{chunk_idx}' not in val:
                    user_prompt = val.strip()
            # 3. Try translation chunk prompt only if it's not a template
            if not user_prompt:
                val = getattr(self, 'translation_chunk_prompt', '') or self.config.get('translation_chunk_prompt', '')
                if val and val.strip() and '{chunk_html}' not in val and '{chunk_idx}' not in val:
                    user_prompt = val.strip()

            if not user_prompt:
                raise RuntimeError(
                    "No prompt found for generative mode. "
                    "Please enter a system prompt before running."
                )

            messages = []
            if system_prompt and system_prompt != user_prompt:
                messages.append({'role': 'system', 'content': system_prompt})
            messages.append({'role': 'user', 'content': user_prompt})

            self.append_log(f"\ud83d\udcdd Prompt: {user_prompt[:200]}{'...' if len(user_prompt) > 200 else ''}")

            # Push critical output-mode env vars so the client picks them up
            os.environ['ENABLE_IMAGE_OUTPUT_MODE'] = self._get_allowed_image_output_mode()
            os.environ['ENABLE_VIDEO_OUTPUT_MODE'] = self._get_allowed_video_output_mode()
            os.environ['NANOGPT_VIDEO_DURATION'] = str(getattr(self, 'nanogpt_video_duration_var', '60')) + 's'
            os.environ['NANOGPT_VIDEO_RESOLUTION'] = str(getattr(self, 'nanogpt_video_resolution_var', '720p'))

            # Instantiate a UnifiedClient for this call
            from unified_api_client import UnifiedClient
            try:
                api_key = self.api_key_entry.text().strip()
            except Exception:
                api_key = str(getattr(self, 'api_key_var', '') or '').strip()
            if api_key:
                os.environ['OPENAI_API_KEY'] = api_key

            try:
                temperature = float(self.trans_temp.text())
            except Exception:
                temperature = 1.0

            client = UnifiedClient(
                api_key=api_key,
                model=model,
            )

            result_text, _finish = client.send(
                messages,
                temperature=temperature,
                max_tokens=int(getattr(self, 'max_output_tokens', 4096) or 4096),
            )
            result_text = (result_text or '').strip()

            self.append_log(f"\n\u2705 Generation complete!")
            self.append_log(f"\ud83d\udd17 Result: {result_text}")

            # Check if it's a generated media sentinel
            import re, shutil
            match = re.search(r'\[GENERATED_IMAGE:(.+?)\]', result_text)
            
            try:
                import datetime, pathlib
                ts = datetime.datetime.now().strftime('%Y%m%d_%H%M%S')
                safe_model = model.replace('/', '_').replace('\\', '_')

                # All generative output goes to Generated_Media
                out_dir = pathlib.Path(os.path.dirname(os.path.abspath(__file__))) / 'Generated_Media'
                out_dir.mkdir(parents=True, exist_ok=True)

                if match:
                    # It's a media file — already saved in Generated_Media, just log it
                    generated_media_path = match.group(1)
                    if os.path.exists(generated_media_path):
                        self.append_log(f"\ud83d\udcc4 Media saved to: {generated_media_path}")
                        result_text = generated_media_path
                else:
                    # Standard text response, save as .txt
                    fname = f"generated_{safe_model}_{ts}.txt"
                    out_path = out_dir / fname
                    out_path.write_text(result_text, encoding='utf-8')
                    self.append_log(f"\ud83d\udcc4 Saved to: {out_path}")
            except Exception as save_err:
                self.append_log(f"\u26a0\ufe0f Could not save result file: {save_err}")

            return True

        except Exception as exc:
            self.append_log(f"\u274c Generative mode error: {exc}")
            # Don't dump traceback for user-initiated cancellations / stops
            exc_lower = str(exc).lower()
            if not any(k in exc_lower for k in ('cancelled', 'canceled', 'graceful stop', 'stop requested')):
                import traceback
                self.append_log(traceback.format_exc())
            return False

    def run_translation_direct(self):
        """Run translation directly - handles multiple files and different file types"""

        backend_glossary_callback_installed = False
        try:
            self._export_multipass_runtime_env()

            if getattr(self, '_input_output_run_active', False):
                try:
                    import TransateKRtoEN
                    TransateKRtoEN.set_direct_text_glossary_approval_callback(
                        self._await_direct_text_glossary_approval
                    )
                    backend_glossary_callback_installed = True
                except Exception as exc:
                    self.append_log(
                        f"⚠️ Could not install Direct Text glossary approval gate: {exc}"
                    )

            # AUTO-SWITCH PROFILE BASED ON EXTRACTION MODE
            # Check if profile name contains BeautifulSoup or html2text
            current_profile = self.profile_var
            if current_profile:
                profile_lower = current_profile.lower()
                
                # Check if profile indicates an extraction mode
                if 'beautifulsoup' in profile_lower:
                    # Switch to BeautifulSoup extraction mode
                    if hasattr(self, 'text_extraction_method_var'):
                        self.text_extraction_method_var = 'standard'
                        self.append_log(f"🔄 Auto-switched to BeautifulSoup extraction (profile: {current_profile})")
                elif 'html2text' in profile_lower:
                    # Switch to html2text extraction mode  
                    if hasattr(self, 'text_extraction_method_var'):
                        self.text_extraction_method_var = 'enhanced'
                        self.append_log(f"🔄 Auto-switched to html2text extraction (profile: {current_profile})")
            
            # Re-attach GUI logging handlers to reclaim logs from standalone header translation
            try:
                self._attach_gui_logging_handlers()
            except Exception:
                pass
            
            # Restore print hijack if it was captured by manga translator
            # This ensures main GUI logs go to main GUI, not manga GUI
            try:
                import builtins
                # Check if print was hijacked by manga translator
                if hasattr(builtins, '_manga_log_callbacks') and builtins._manga_log_callbacks:
                    # Restore original print for main GUI
                    if hasattr(builtins, 'print') and hasattr(builtins.print, '__name__'):
                        if builtins.print.__name__ == 'manga_print':
                            # Print is hijacked, restore it
                            from manga_translator import MangaTranslator
                            if hasattr(MangaTranslator, '_original_print_backup'):
                                builtins.print = MangaTranslator._original_print_backup
                                # Also restore in unified_api_client
                                try:
                                    import sys
                                    import unified_api_client
                                    uc_module = sys.modules.get('unified_api_client')
                                    if uc_module:
                                        uc_module.__dict__['print'] = MangaTranslator._original_print_backup
                                except Exception:
                                    pass
            except Exception:
                pass
            
            # Check stop at the very beginning
            if self.stop_requested:
                return False
            
            # DON'T CALL _lazy_load_modules HERE!
            # Modules are already loaded in the wrapper
            # Just verify they're loaded
            if not self._modules_loaded:
                self.append_log("❌ Translation modules not loaded")
                return False

            # Check stop after verification
            if self.stop_requested:
                return False
            # Sync streaming toggle to env for all backends.
            # ``_force_stream_all`` (set by the EPUB Reader's live "Translate"
            # action) overrides every streaming toggle to ON for this run,
            # regardless of the user's persisted settings.
            _force_stream = bool(getattr(self, '_force_stream_all', False))
            try:
                stream_on = _force_stream or bool(getattr(self, 'enable_streaming_var', self.config.get('enable_streaming', False)))
                os.environ['ENABLE_STREAMING'] = '1' if stream_on else '0'
                self.append_log(f"🛰️ Streaming {'enabled' if stream_on else 'disabled'} (exported ENABLE_STREAMING)")
            except Exception:
                pass
            try:
                allow_batch_logs = _force_stream or bool(getattr(self, 'allow_batch_stream_logs_var', self.config.get('allow_batch_stream_logs', False)))
                os.environ['ALLOW_BATCH_STREAM_LOGS'] = '1' if allow_batch_logs else '0'
            except Exception:
                pass
            try:
                allow_authgpt_logs = _force_stream or bool(getattr(self, 'allow_authgpt_batch_stream_logs_var', self.config.get('allow_authgpt_batch_stream_logs', False)))
                os.environ['ALLOW_AUTHGPT_BATCH_STREAM_LOGS'] = '1' if allow_authgpt_logs else '0'
            except Exception:
                pass
            try:
                stream_thinking = _force_stream or bool(getattr(self, 'stream_thinking_logs_var', self.config.get('stream_thinking_logs', False)))
                os.environ['STREAM_THINKING_LOGS'] = '1' if stream_thinking else '0'
            except Exception:
                pass
            if _force_stream:
                self._apply_forced_streaming_environment()
                self.append_log("🛰️ Live view: all streaming toggles forced ON for this run")

            # SET GLOSSARY IN ENVIRONMENT
            # If a per-input mapping exists, we set MANUAL_GLOSSARY per file inside the loop.
            use_glossary_map = False
            try:
                mgm = getattr(self, 'manual_glossary_map', None)
                use_glossary_map = isinstance(mgm, dict) and any(v for v in mgm.values())
            except Exception:
                use_glossary_map = False

            if use_glossary_map:
                os.environ.pop('MANUAL_GLOSSARY', None)
                try:
                    mapped = len([1 for _k, _v in (self.manual_glossary_map or {}).items() if _v])
                except Exception:
                    mapped = 0
                self.append_log(f"📑 Glossary mapping enabled ({mapped} file(s) mapped)")
            else:
                if hasattr(self, 'manual_glossary_path') and self.manual_glossary_path:
                    os.environ['MANUAL_GLOSSARY'] = self.manual_glossary_path
                    self.append_log(f"📑 Set glossary in environment: {os.path.basename(self.manual_glossary_path)}")
                else:
                    # Clear any previous glossary from environment
                    os.environ.pop('MANUAL_GLOSSARY', None)
                    self.append_log(f"ℹ️ No glossary loaded")

            # ========== NEW: APPLY OPF-BASED SORTING ==========
            if (
                any(str(f).lower().endswith(('.zip', '.cbz')) for f in getattr(self, 'selected_files', []) or [])
                and not getattr(self, '_zip_inputs_resolved_for_current_run', False)
            ):
                self.append_log("📦 Preparing image archive input(s) before file processing...")
                self._resolve_zip_inputs_for_translation()
                if self.stop_requested:
                    return False

            # Sort files based on OPF order if available
            original_file_count = len(self.selected_files)
            self.selected_files = self._get_opf_file_order(self.selected_files)
            self.append_log(f"📚 Processing {original_file_count} files in reading order")
            # ====================================================

            # ── Generative-only mode (no input file) ───────────────────────
            # When the model indicates image or video generation and no real file
            # was selected, skip the normal file loop and fire a single API call
            # using the system-prompt / translation-chunk-prompt as the user prompt.
            _active_model = str(getattr(self, 'model_var', ''))
            _is_gen_mode = (
                len(self.selected_files) == 1
                and self.selected_files[0] == "__generative_mode__"
            ) or (
                (self._model_is_image_gen(_active_model) or self._model_is_video_gen(_active_model) or self._is_generative_output_mode())
                and not any(
                    os.path.exists(p) for p in (self.selected_files or [])
                    if p != "__generative_mode__"
                )
            )

            if _is_gen_mode:
                return self._run_generative_prompt_mode()

            # Process each file
            total_files = len(self.selected_files)
            successful = 0
            failed = 0

            # Honor OUTPUT_DIRECTORY override globally for this run
            try:
                override_dir = os.environ.get('OUTPUT_DIRECTORY') or self.config.get('output_directory')
                if override_dir:
                    os.environ['OUTPUT_DIRECTORY'] = os.path.abspath(override_dir)
                    os.environ['OUTPUT_DIR'] = os.path.abspath(override_dir)
                    self.append_log(f"📁 Using output override: {os.environ['OUTPUT_DIRECTORY']}")
            except Exception as e:
                self.append_log(f"⚠️ Could not apply OUTPUT_DIRECTORY override: {e}")
            
            # Check if we're processing multiple images - if so, create a combined output folder
            image_extensions = set(_InputOutputDialog._IMAGE_ATTACHMENT_EXTENSIONS)
            video_extensions = {'.mp4', '.mov', '.avi', '.mkv', '.webm'}
            media_extensions = image_extensions | video_extensions
            image_files = [f for f in self.selected_files if os.path.splitext(f)[1].lower() in media_extensions]
            
            combined_image_output_dir = None
            if len(image_files) > 1:
                # Check stop before creating directories
                if self.stop_requested:
                    return False
                    
                # Get the common parent directory name or use timestamp
                parent_dir = os.path.dirname(self.selected_files[0])
                folder_name = os.path.basename(parent_dir) if parent_dir else f"OCR_{int(time.time())}"
                
                # Check for output directory override
                override_dir = os.environ.get('OUTPUT_DIRECTORY') or self.config.get('output_directory')
                if override_dir:
                    combined_image_output_dir = os.path.join(override_dir, folder_name)
                else:
                    combined_image_output_dir = folder_name
                
                os.makedirs(combined_image_output_dir, exist_ok=True)
                
                # Create images subdirectory for originals
                images_dir = os.path.join(combined_image_output_dir, "images")
                os.makedirs(images_dir, exist_ok=True)
                
                self.append_log(f"📁 Created combined output directory: {combined_image_output_dir}")
            
            for i, file_path in enumerate(self.selected_files):
                if self.stop_requested:
                    # Suppress per-file stop spam; summary will be shown later
                    break

                # Apply per-file glossary mapping (if present)
                try:
                    mgm = getattr(self, 'manual_glossary_map', None)
                    if isinstance(mgm, dict) and mgm:
                        key = os.path.normpath(os.path.abspath(file_path))
                        gp = mgm.get(file_path) or mgm.get(key) or mgm.get(os.path.normpath(file_path))
                        if gp:
                            os.environ['MANUAL_GLOSSARY'] = gp
                            # Inform user which glossary is used for this EPUB
                            try:
                                if str(file_path).lower().endswith('.epub'):
                                    self.append_log(
                                        f"📑 Using mapped glossary for {os.path.basename(file_path)}: {os.path.basename(gp)}"
                                    )
                            except Exception:
                                pass
                        else:
                            os.environ.pop('MANUAL_GLOSSARY', None)
                except Exception:
                    pass
                
                self.current_file_index = i
                
                # Log progress for multiple files
                if total_files > 1:
                    self.append_log(f"\n{'='*60}")
                    self.append_log(f"📄 Processing file {i+1}/{total_files}: {os.path.basename(file_path)}")
                    progress_percent = ((i + 1) / total_files) * 100
                    self.append_log(f"📊 Overall progress: {progress_percent:.1f}%")
                    self.append_log(f"{'='*60}")

                if (
                    str(file_path).lower().endswith(('.zip', '.cbz'))
                    and not getattr(self, '_zip_inputs_resolved_for_current_run', False)
                ):
                    old_file_path = file_path
                    file_path = self._convert_zip_input_to_epub_if_needed(file_path)
                    self.selected_files[i] = file_path
                    if file_path != old_file_path:
                        try:
                            self.input_files_updated_signal.emit(list(self.selected_files))
                        except Exception:
                            pass
                
                if not os.path.exists(file_path):
                    self.append_log(f"❌ File not found: {file_path}")
                    failed += 1
                    continue
                
                # Determine file type and process accordingly
                ext = os.path.splitext(file_path)[1].lower()
                
                try:
                    if ext in media_extensions:
                        # Process as image/video with combined output directory if applicable
                        if self._process_image_file(file_path, combined_image_output_dir):
                            successful += 1
                        else:
                            failed += 1
                    elif ext == '.exe':
                        # Process as RPG Maker game via GTool
                        if self._process_rpgmaker_game(file_path):
                            successful += 1
                        else:
                            failed += 1
                    elif ext in {'.epub', '.txt', '.csv', '.json', '.pdf', '.md', '.sdlxliff'}:
                        # Process as EPUB/TXT/CSV/JSON/PDF/MD/SDLXLIFF
                        result = self._process_text_file(file_path)
                        if result:
                            successful += 1
                        else:
                            failed += 1
                    else:
                        self.append_log(f"⚠️ Unsupported file type: {ext}")
                        failed += 1
                        
                except Exception as e:
                    self.append_log(f"❌ Error processing {os.path.basename(file_path)}: {str(e)}")
                    import traceback
                    self.append_log(f"❌ Full error: {traceback.format_exc()}")
                    failed += 1
            
            # Check stop before final summary
            if self.stop_requested:
                self.append_log(f"\n⏹️ Translation stopped - processed {successful} of {total_files} files")
                # Reset progress bar when stopped
                try:
                    if hasattr(self, 'progress_bar') and self.progress_bar:
                        self.progress_bar.setValue(0)
                        self.progress_bar.setFormat("Batch stopped")
                        
                    # Also clean up any lingering watchdog files to ensure "in-flight" count clears
                    # ONLY if WAIT_FOR_CHUNKS=0 (immediate stop behavior)
                    if os.environ.get('WAIT_FOR_CHUNKS', '0') == '0':
                        self._reset_api_watchdog_progress(clear_stale_external_files=True)
                        
                        # And ensure hard cancel is triggered one last time
                        import unified_api_client
                        if hasattr(unified_api_client, 'hard_cancel_all'):
                            unified_api_client.hard_cancel_all()
                except Exception:
                    pass
                return False
                
            # Final summary
            try:
                self._log_translation_qa_failure_summary(phase="end")
            except Exception as e:
                self.append_log(f"⚠️ Could not read final QA failure summary: {e}")

            if total_files > 1:
                self.append_log(f"\n{'='*60}")
                self.append_log(f"📊 Translation Summary:")
                self.append_log(f"   ✅ Successful: {successful} files")
                if failed > 0:
                    self.append_log(f"   ❌ Failed: {failed} files")
                self.append_log(f"   📁 Total: {total_files} files")
                
                # Create CBZ if we have generated images
                if hasattr(self, 'generated_images') and self.generated_images:
                    self.append_log(f"\n📦 Creating CBZ archive with {len(self.generated_images)} generated images...")
                    try:
                        import zipfile
                        # Get output directory from first image path
                        output_dir = os.path.dirname(self.generated_images[0])
                        cbz_path = os.path.join(output_dir, f"{os.path.basename(output_dir)}.cbz")
                        
                        # Create CBZ (which is just a ZIP file)
                        with zipfile.ZipFile(cbz_path, 'w', zipfile.ZIP_DEFLATED) as cbz:
                            for img_path in sorted(self.generated_images):
                                # Add image with just the filename (no path)
                                cbz.write(img_path, os.path.basename(img_path))
                        
                        self.append_log(f"✅ CBZ created: {cbz_path}")
                        self.append_log(f"   📁 Contains {len(self.generated_images)} images")
                        
                        # Clear the list for next batch
                        self.generated_images = []
                    except Exception as e:
                        self.append_log(f"❌ Failed to create CBZ: {e}")
                        import traceback
                        self.append_log(traceback.format_exc())
                
                if combined_image_output_dir and successful > 0:
                    self.append_log(f"\n💡 Tip: You can now compile the HTML files in '{combined_image_output_dir}' into an EPUB")
                    
                    # Check for cover image
                    cover_found = False
                    for img_name in ['cover.png', 'cover.jpg', 'cover.jpeg', 'cover.webp']:
                        if os.path.exists(os.path.join(combined_image_output_dir, "images", img_name)):
                            self.append_log(f"   📖 Found cover image: {img_name}")
                            cover_found = True
                            break
                    
                    if not cover_found:
                        # Use first image as cover
                        images_in_dir = os.listdir(os.path.join(combined_image_output_dir, "images"))
                        if images_in_dir:
                            self.append_log(f"   📖 First image will be used as cover: {images_in_dir[0]}")
                
                self.append_log(f"{'='*60}")
            
            # Only return True if at least one file succeeded
            # This prevents QA scanner from running when all files failed
            if successful == 0:
                return False
            
            return True  # Translation completed successfully
            
        except Exception as e:
            self.append_log(f"❌ Translation setup error: {e}")
            import traceback
            self.append_log(f"❌ Full error: {traceback.format_exc()}")
            return False
        
        finally:
            if backend_glossary_callback_installed:
                try:
                    import TransateKRtoEN
                    TransateKRtoEN.set_direct_text_glossary_approval_callback(None)
                except Exception:
                    pass
            # IMPORTANT: do NOT reset stop flags, null the translation thread, or
            # emit thread_complete_signal here.
            #
            # run_translation_direct() is only ever called from
            # simple_thread_target(), which owns the thread/button lifecycle and
            # performs this cleanup exactly once in its own finally. When a single
            # run chains multiple phases — e.g. Partial.B2 multipass refinement
            # followed by the "regular translation retry" of skipped QA-failed
            # chapters — this finally runs after the FIRST phase and:
            #   • fires thread_complete_signal → update_run_button() flips the run
            #     button to green ("Run Translation") mid-run, during the 2nd
            #     phase's chapter extraction, and
            #   • sets self.stop_requested = False, which wipes a Stop the user
            #     pressed during phase 1 AND makes the followup-gate
            #     (`not self.stop_requested`) always true, so the 2nd phase always
            #     runs and cannot be stopped.
            # Both were the "button turns green / stop doesn't trigger during
            # multipass" reports. Leave lifecycle + stop-flag reset to
            # simple_thread_target()'s finally.
            self.current_file_index = 0

    def _process_image_file(self, image_path, combined_output_dir=None):
        """Process a single image file using the direct image translation API with progress tracking"""
        try:
            import time
            import shutil
            import hashlib
            import os
            import json
            
            # Determine output directory early for progress tracking
            image_name = os.path.basename(image_path)
            base_name = os.path.splitext(image_name)[0]
            
            if combined_output_dir:
                output_dir = combined_output_dir
            else:
                # Check for output directory override
                override_dir = os.environ.get('OUTPUT_DIRECTORY') or self.config.get('output_directory')
                if override_dir:
                    output_dir = os.path.join(override_dir, base_name)
                else:
                    output_dir = base_name
            
            # Initialize progress manager if not already done
            if not hasattr(self, 'image_progress_manager'):
                # Use the determined output directory
                os.makedirs(output_dir, exist_ok=True)
                
                # Import or define a simplified ImageProgressManager
                class ImageProgressManager:
                    def __init__(self, output_dir=None):
                        self.output_dir = output_dir
                        if output_dir:
                            self.PROGRESS_FILE = os.path.join(output_dir, "translation_progress.json")
                            self.prog = self._init_or_load()
                        else:
                            self.PROGRESS_FILE = None
                            self.prog = {"images": {}, "content_hashes": {}, "version": "1.0"}
                    
                    def set_output_dir(self, output_dir):
                        """Set or update the output directory and load progress"""
                        self.output_dir = output_dir
                        self.PROGRESS_FILE = os.path.join(output_dir, "translation_progress.json")
                        self.prog = self._init_or_load()
                    
                    def _init_or_load(self):
                        """Initialize or load progress tracking"""
                        if os.path.exists(self.PROGRESS_FILE):
                            try:
                                with open(self.PROGRESS_FILE, "r", encoding="utf-8") as pf:
                                    return json.load(pf)
                            except Exception as e:
                                if hasattr(self, 'append_log'):
                                    self.append_log(f"⚠️ Creating new progress file due to error: {e}")
                                return {"images": {}, "content_hashes": {}, "version": "1.0"}
                        else:
                            return {"images": {}, "content_hashes": {}, "version": "1.0"}
                    
                    def save(self):
                        """Save progress to file atomically with retry for file locks"""
                        if not self.PROGRESS_FILE:
                            return
                        try:
                            import time as _time
                            import threading as _threading
                            import uuid as _uuid
                            # Ensure directory exists
                            os.makedirs(os.path.dirname(self.PROGRESS_FILE), exist_ok=True)
                            
                            temp_file = (
                                f"{self.PROGRESS_FILE}."
                                f"{os.getpid()}."
                                f"{_threading.get_ident()}."
                                f"{_uuid.uuid4().hex}.tmp"
                            )
                            max_retries = 5
                            for attempt in range(max_retries):
                                try:
                                    with open(temp_file, "w", encoding="utf-8") as pf:
                                        json.dump(self.prog, pf, ensure_ascii=False, indent=2)
                                    break
                                except PermissionError:
                                    if attempt < max_retries - 1:
                                        _time.sleep(0.1 * (2 ** attempt))
                                    else:
                                        raise
                            
                            for attempt in range(max_retries):
                                try:
                                    os.replace(temp_file, self.PROGRESS_FILE)
                                    break
                                except PermissionError:
                                    if attempt < max_retries - 1:
                                        _time.sleep(0.1 * (2 ** attempt))
                                    else:
                                        raise
                        except Exception as e:
                            if hasattr(self, 'append_log'):
                                self.append_log(f"⚠️ Failed to save progress: {e}")
                            else:
                                print(f"⚠️ Failed to save progress: {e}")
                    
                    def get_content_hash(self, file_path):
                        """Generate content hash for a file"""
                        hasher = hashlib.sha256()
                        with open(file_path, 'rb') as f:
                            # Read in chunks to handle large files
                            for chunk in iter(lambda: f.read(4096), b""):
                                hasher.update(chunk)
                        return hasher.hexdigest()
                    
                    def check_image_status(self, image_path, content_hash):
                        """Check if an image needs translation"""
                        image_name = os.path.basename(image_path)
                        
                        # NEW: Check for skip markers created by "Mark as Skipped" button
                        skip_key = f"skip_{image_name}"
                        if skip_key in self.prog:
                            skip_info = self.prog[skip_key]
                            if skip_info.get('status') == 'skipped':
                                return False, f"Image marked as skipped", None
                        
                        # NEW: Check if image already exists in images folder (marked as skipped)
                        if self.output_dir:
                            images_dir = os.path.join(self.output_dir, "images")
                            dest_image_path = os.path.join(images_dir, image_name)
                            
                            if os.path.exists(dest_image_path):
                                return False, f"Image in skipped folder", None
                        
                        # Check if image has already been processed
                        if content_hash in self.prog["images"]:
                            image_info = self.prog["images"][content_hash]
                            status = image_info.get("status")
                            output_file = image_info.get("output_file")
                            
                            if status == "completed" and output_file:
                                # Check if output file exists
                                if output_file and os.path.exists(output_file):
                                    return False, f"Image already translated: {output_file}", output_file
                                else:
                                    # Output file missing, mark for retranslation
                                    image_info["status"] = "file_deleted"
                                    image_info["deletion_detected"] = time.time()
                                    self.save()
                                    return True, None, None
                            
                            elif status == "skipped_cover":
                                return False, "Cover image - skipped", None
                            
                            elif status == "error":
                                # Previous error, retry
                                return True, None, None
                        
                        return True, None, None
                    
                    def update(self, image_path, content_hash, output_file=None, status="in_progress", error=None):
                        """Update progress for an image"""
                        image_name = os.path.basename(image_path)
                        
                        image_info = {
                            "name": image_name,
                            "path": image_path,
                            "content_hash": content_hash,
                            "status": status,
                            "last_updated": time.time()
                        }
                        
                        if output_file:
                            image_info["output_file"] = output_file
                        
                        if error:
                            image_info["error"] = str(error)
                        
                        self.prog["images"][content_hash] = image_info
                        
                        # Update content hash index for duplicates
                        if status == "completed" and output_file:
                            self.prog["content_hashes"][content_hash] = {
                                "original_name": image_name,
                                "output_file": output_file
                            }
                        
                        self.save()
                
                # Initialize the progress manager
                self.image_progress_manager = ImageProgressManager(output_dir)
                # Add append_log reference for the progress manager
                self.image_progress_manager.append_log = self.append_log
                self.append_log(f"📊 Progress tracking in: {os.path.join(output_dir, 'translation_progress.json')}")
            
            # Check for stop request early
            if self.stop_requested:
                self.append_log("⏹️ Image translation cancelled by user")
                return False
            
            # Get content hash for the image
            try:
                content_hash = self.image_progress_manager.get_content_hash(image_path)
            except Exception as e:
                self.append_log(f"⚠️ Could not generate content hash: {e}")
                # Fallback to using file path as identifier
                content_hash = hashlib.sha256(image_path.encode()).hexdigest()
            
            # Check if image needs translation
            needs_translation, skip_reason, existing_output = self.image_progress_manager.check_image_status(
                image_path, content_hash
            )
            
            if not needs_translation:
                self.append_log(f"⏭️ {skip_reason}")
                
                # NEW: If image is marked as skipped but not in images folder yet, copy it there
                if "marked as skipped" in skip_reason and combined_output_dir:
                    images_dir = os.path.join(combined_output_dir, "images")
                    os.makedirs(images_dir, exist_ok=True)
                    dest_image = os.path.join(images_dir, image_name)
                    if not os.path.exists(dest_image):
                        shutil.copy2(image_path, dest_image)
                        self.append_log(f"📁 Copied skipped image to: {dest_image}")
                
                return True
            
            # Update progress to "in_progress"
            self.image_progress_manager.update(image_path, content_hash, status="in_progress")
            
            # Check if image translation is enabled (always allow for direct image/video file input)
            _direct_media_exts = {'.png', '.jpg', '.jpeg', '.gif', '.bmp', '.webp', '.tiff', '.tif', '.svg', '.ico', '.heic', '.heif', '.avif', '.jxl',
                                  '.mp4', '.mov', '.avi', '.mkv', '.webm'}
            _is_direct_media = os.path.splitext(image_path)[1].lower() in _direct_media_exts
            if not _is_direct_media and (not hasattr(self, 'enable_image_translation_var') or not self.enable_image_translation_var):
                self.append_log(f"⚠️ Image translation not enabled. Enable it in settings to translate images.")
                return False
            
            # Check for cover images
            if 'cover' in image_name.lower():
                self.append_log(f"⏭️ Skipping cover image: {image_name}")
                
                # Update progress for cover
                self.image_progress_manager.update(image_path, content_hash, status="skipped_cover")
                
                # Copy cover image to images folder if using combined output
                if combined_output_dir:
                    images_dir = os.path.join(combined_output_dir, "images")
                    os.makedirs(images_dir, exist_ok=True)
                    dest_image = os.path.join(images_dir, image_name)
                    if not os.path.exists(dest_image):
                        shutil.copy2(image_path, dest_image)
                        self.append_log(f"📁 Copied cover to: {dest_image}")
                
                return True  # Return True to indicate successful skip (not an error)
            
            # Check for stop before processing
            if self.stop_requested:
                self.append_log("⏹️ Image translation cancelled before processing")
                self.image_progress_manager.update(image_path, content_hash, status="cancelled")
                return False
            
            # Get the file index for numbering
            file_index = getattr(self, 'current_file_index', 0) + 1
            
            # Get API key and model
            api_key = self.api_key_entry.text().strip()
            model = self.model_var.strip()
            
            # Check if model needs API key (delegates to UnifiedClient's authoritative list)
            try:
                from unified_api_client import UnifiedClient as _UC
                model_needs_api_key = _UC._model_needs_api_key(model)
            except Exception:
                model_needs_api_key = bool(model)  # safe fallback
            
            if model_needs_api_key and not api_key:
                self.append_log("❌ Error: Please enter your API key.")
                self.image_progress_manager.update(image_path, content_hash, status="error", error="No API key")
                return False
            
            if not model:
                self.append_log("❌ Error: Please select a model.")
                self.image_progress_manager.update(image_path, content_hash, status="error", error="No model selected")
                return False
            
            self.append_log(f"🖼️ Processing image: {os.path.basename(image_path)}")
            self.append_log(f"🤖 Using model: {model}")
            # Ensure image output mode/env reflect current settings before client call
            # Use _get_allowed_image_output_mode() so generative models (gpt-image-*, etc.)
            # auto-force ENABLE_IMAGE_OUTPUT_MODE=1 regardless of the toggle state.
            try:
                os.environ['ENABLE_IMAGE_OUTPUT_MODE'] = self._get_allowed_image_output_mode()
                os.environ['ENABLE_VIDEO_OUTPUT_MODE'] = self._get_allowed_video_output_mode()
                os.environ['IMAGE_OUTPUT_RESOLUTION'] = str(getattr(self, 'image_output_resolution_var', '1K')).upper()
                # Tell the video API where the source file is so it can probe metadata
                _video_exts = {'.mp4', '.mov', '.avi', '.mkv', '.webm'}
                if os.path.splitext(image_path)[1].lower() in _video_exts:
                    os.environ['NANOGPT_SOURCE_VIDEO_PATH'] = image_path
                else:
                    os.environ.pop('NANOGPT_SOURCE_VIDEO_PATH', None)
            except Exception:
                pass
            
            # Check if it's a vision-capable model
            vision_models = [
                'claude-opus-4-20250514', 'claude-sonnet-4-20250514',
                'gpt-4-turbo', 'gpt-4o', 'gpt-4o-mini', 'gpt-4.1', 'gpt-4.1-mini', 'gpt-5-mini','gpt-5','gpt-5-nano',
                'gpt-4-vision-preview',
                'gemini-1.5-pro', 'gemini-1.5-flash', 'gemini-2.0-flash', 'gemini-2.0-flash-exp',
                'gemini-2.5-pro', 'gemini-2.5-flash',
                'llama-3.2-11b-vision', 'llama-3.2-90b-vision',
                'gemini-3-pro-image-preview', 'gemini-3.1-flash-image-preview',
                'image-preview',  # catch-all for future image-generating Gemini models
                'eh/gemini-2.5-flash', 'eh/gemini-1.5-flash', 'eh/gpt-4o' # ElectronHub variants
            ]
            
            # Check for stop before API initialization
            if self.stop_requested:
                self.append_log("⏹️ Image translation cancelled before API initialization")
                self.image_progress_manager.update(image_path, content_hash, status="cancelled")
                return False
            
            # Apply multi-key settings for image translation (same as main translation path)
            try:
                use_mk = bool(self.config.get('use_multi_api_keys', False))
                mk_list = self.config.get('multi_api_keys', []) or []
                force_rotation = bool(self.config.get('force_key_rotation', True))
                rotation_frequency = int(self.config.get('rotation_frequency', 1))
                if use_mk and mk_list:
                    os.environ['USE_MULTI_API_KEYS'] = '1'
                    os.environ['USE_MULTI_KEYS'] = '1'
                    os.environ['FORCE_KEY_ROTATION'] = '1' if force_rotation else '0'
                    os.environ['ROTATION_FREQUENCY'] = str(rotation_frequency)
                    try:
                        from unified_api_client import UnifiedClient
                        UnifiedClient.set_in_memory_multi_keys(
                            mk_list,
                            force_rotation=force_rotation,
                            rotation_frequency=rotation_frequency,
                        )
                    except Exception:
                        pass
                    self.append_log(f"🔑 Multi-key mode ENABLED for image translation ({len(mk_list)} keys)")
                else:
                    os.environ['USE_MULTI_API_KEYS'] = '0'
                    os.environ['USE_MULTI_KEYS'] = '0'
                    try:
                        from unified_api_client import UnifiedClient
                        UnifiedClient.clear_in_memory_multi_keys()
                    except Exception:
                        pass
            except Exception:
                pass
            
            # Configure glossary key pool in memory (mirrors multi-key setup)
            try:
                from unified_api_client import UnifiedClient
                if self.config.get('use_glossary_keys', False) and self.config.get('glossary_keys', []):
                    UnifiedClient.set_in_memory_glossary_keys(
                        self.config.get('glossary_keys', []),
                        force_rotation=self.config.get('force_key_rotation', True),
                        rotation_frequency=self.config.get('rotation_frequency', 1),
                    )
                else:
                    UnifiedClient.clear_in_memory_glossary_keys()
                refinement_keys_enabled = bool(self.config.get('use_glossary_refinement_keys', False))
                refinement_keys = self.config.get('glossary_refinement_keys', []) or []
                os.environ['USE_GLOSSARY_REFINEMENT_KEYS'] = '1' if refinement_keys_enabled else '0'
                os.environ['GLOSSARY_REFINEMENT_API_KEYS'] = json.dumps(refinement_keys)
                if refinement_keys_enabled and refinement_keys:
                    UnifiedClient.set_in_memory_glossary_refinement_keys(
                        refinement_keys,
                        force_rotation=self.config.get('force_key_rotation', True),
                        rotation_frequency=self.config.get('rotation_frequency', 1),
                    )
                else:
                    UnifiedClient.clear_in_memory_glossary_refinement_keys()
            except Exception:
                pass

            # Configure rolling summary key pool for memory summary generation calls.
            try:
                from unified_api_client import UnifiedClient
                rolling_summary_keys_enabled = bool(self.config.get('use_rolling_summary_keys', False))
                rolling_summary_keys = self.config.get('rolling_summary_keys', []) or []
                os.environ['USE_ROLLING_SUMMARY_KEYS'] = '1' if rolling_summary_keys_enabled else '0'
                os.environ['ROLLING_SUMMARY_API_KEYS'] = json.dumps(rolling_summary_keys)
                if rolling_summary_keys_enabled and rolling_summary_keys:
                    UnifiedClient.set_in_memory_rolling_summary_keys(
                        rolling_summary_keys,
                        force_rotation=self.config.get('force_key_rotation', True),
                        rotation_frequency=self.config.get('rotation_frequency', 1),
                    )
                    self.append_log(f"[RollingSummary] Key pool ENABLED for rolling summary generation ({len(rolling_summary_keys)} keys)")
                else:
                    UnifiedClient.clear_in_memory_rolling_summary_keys()
                    if rolling_summary_keys_enabled:
                        self.append_log("[RollingSummary] Enabled but no keys configured")
            except Exception:
                pass

            # Configure truncation retry key pool for RETRY_TRUNCATED attempts.
            try:
                from unified_api_client import UnifiedClient
                truncation_retry_keys_enabled = bool(self.config.get('use_truncation_retry_keys', False))
                truncation_retry_keys = self.config.get('truncation_retry_keys', []) or []
                os.environ['USE_TRUNCATION_RETRY_KEYS'] = '1' if truncation_retry_keys_enabled else '0'
                os.environ['TRUNCATION_RETRY_API_KEYS'] = json.dumps(truncation_retry_keys)
                if truncation_retry_keys_enabled and truncation_retry_keys:
                    UnifiedClient.set_in_memory_truncation_retry_keys(
                        truncation_retry_keys,
                        force_rotation=self.config.get('force_key_rotation', True),
                        rotation_frequency=self.config.get('rotation_frequency', 1),
                    )
                    self.append_log(f"[TruncationRetry] Key pool ENABLED for truncation retries ({len(truncation_retry_keys)} keys)")
                else:
                    UnifiedClient.clear_in_memory_truncation_retry_keys()
                    if truncation_retry_keys_enabled:
                        self.append_log("[TruncationRetry] Enabled but no keys configured")
            except Exception:
                pass

            # Configure Image Gen/Edit key pool for image output mode requests.
            try:
                from unified_api_client import UnifiedClient
                inpainter_keys_enabled = bool(self.config.get('use_inpainter_keys', False))
                inpainter_keys = self.config.get('inpainter_keys', []) or []
                os.environ['USE_INPAINTER_KEYS'] = '1' if inpainter_keys_enabled else '0'
                os.environ['INPAINTER_API_KEYS'] = json.dumps(inpainter_keys)
                if inpainter_keys_enabled and inpainter_keys:
                    UnifiedClient.set_in_memory_inpainter_keys(
                        inpainter_keys,
                        force_rotation=self.config.get('force_key_rotation', True),
                        rotation_frequency=self.config.get('rotation_frequency', 1),
                    )
                    self.append_log(f"[ImageGenEdit] Key pool ENABLED for image output ({len(inpainter_keys)} keys)")
                else:
                    UnifiedClient.clear_in_memory_inpainter_keys()
                    if inpainter_keys_enabled:
                        self.append_log("[ImageGenEdit] Enabled but no keys configured")
            except Exception:
                pass
            
            # Initialize API client with output_dir to enable multi-key mode from environment
            try:
                from unified_api_client import UnifiedClient
                # Pass output_dir to enable environment-based multi-key initialization
                client = UnifiedClient(model=model, api_key=api_key, output_dir=output_dir)
                
                # Set stop flag if the client supports it
                if hasattr(client, 'set_stop_flag'):
                    client.set_stop_flag(self.stop_requested)
                elif hasattr(client, 'stop_flag'):
                    client.stop_flag = self.stop_requested
                    
            except Exception as e:
                self.append_log(f"❌ Failed to initialize API client: {str(e)}")
                self.image_progress_manager.update(image_path, content_hash, status="error", error=f"API client init failed: {e}")
                return False
            
            # Read the image
            try:
                # Get image name for payload naming
                base_name = os.path.splitext(image_name)[0]
                
                with open(image_path, 'rb') as img_file:
                    image_data = img_file.read()
                
                # Convert to base64
                import base64
                image_base64 = base64.b64encode(image_data).decode('utf-8')
                
                # Check image size
                size_mb = len(image_data) / (1024 * 1024)
                self.append_log(f"📊 Image size: {size_mb:.2f} MB")
                
            except Exception as e:
                self.append_log(f"❌ Failed to read image: {str(e)}")
                self.image_progress_manager.update(image_path, content_hash, status="error", error=f"Failed to read image: {e}")
                return False
            
            # Get system prompt from configuration
            profile_name = self.config.get('active_profile', 'Korean_BeautifulSoup')
            prompt_profiles = self.config.get('prompt_profiles', {})
            
            # Get the main translation prompt
            system_prompt = ""
            if isinstance(prompt_profiles, dict) and profile_name in prompt_profiles:
                profile_data = prompt_profiles[profile_name]
                if isinstance(profile_data, str):
                    # Old format: prompt_profiles[profile_name] = "prompt text"
                    system_prompt = profile_data
                elif isinstance(profile_data, dict):
                    # New format: prompt_profiles[profile_name] = {"prompt": "...", "book_title_prompt": "..."}
                    system_prompt = profile_data.get('prompt', '')
            else:
                # Fallback to check if prompt is stored directly in config
                system_prompt = self.config.get(profile_name, '')
            
            if not system_prompt:
                # Last fallback - empty string
                system_prompt = ""

            if getattr(self, '_input_output_run_active', False):
                profile_as_user = bool(
                    getattr(self, 'system_prompt_to_user_var', False)
                )
                skip_prompt_profile = bool(
                    getattr(
                        self,
                        '_direct_text_skip_prompt_profile',
                        False,
                    )
                )
                if profile_as_user or skip_prompt_profile:
                    system_prompt = ""

            # Replace split marker instruction placeholder
            split_instr = ""
            if getattr(self, 'request_merging_enabled_var', False):
                split_instr = "- CRITICAL Requirement: If you see any HTML tags containing 'SPLIT MARKER' (Example: <h1 id=\"split-1\">SPLIT MARKER: Do Not Remove This Tag</h1>), you MUST preserve them EXACTLY as they appear. Do not translate, modify, or remove these markers."
            
            # Use a regex to replace the placeholder regardless of surrounding whitespace or newlines
            import re
            system_prompt = re.sub(r'\s*\{split_marker_instruction\}\s*', lambda m: '\n' + split_instr if split_instr else '', system_prompt)

            # Check if we should append glossary to the prompt
            append_glossary = self.config.get('append_glossary', True)  # Default to True
            if hasattr(self, 'append_glossary_var'):
                append_glossary = self.append_glossary_var
            
            # Check if automatic glossary is enabled (only minimal mode uses the subprocess path)
            auto_glossary_mode = self.config.get('auto_glossary_mode', None)
            if auto_glossary_mode is None:
                auto_glossary_mode = 'minimal' if self.config.get('enable_auto_glossary', False) else 'off'
            enable_auto_glossary_subprocess = (auto_glossary_mode == 'minimal')
            
            # "No Glossary" mode overrides append_glossary for all file types
            if auto_glossary_mode == 'no_glossary':
                append_glossary = False
            
            if append_glossary:
                # Check for manual glossary
                manual_glossary_path = os.getenv('MANUAL_GLOSSARY')
                if not manual_glossary_path and hasattr(self, 'manual_glossary_path'):
                    manual_glossary_path = self.manual_glossary_path
                # If the file exists but is empty, treat it as missing so auto generation can run
                if manual_glossary_path and os.path.exists(manual_glossary_path):
                    try:
                        if os.path.getsize(manual_glossary_path) == 0:
                            self.append_log("ℹ️ Glossary file is empty; treating as missing so automatic glossary generation can run.")
                            manual_glossary_path = None
                            # Clear env/config so workers don't think a glossary exists
                            os.environ.pop('MANUAL_GLOSSARY', None)
                            if hasattr(self, 'manual_glossary_path'):
                                self.manual_glossary_path = ''
                            self.config['manual_glossary_path'] = ''
                    except Exception:
                        pass
                
                # If minimal mode automatic glossary is enabled and no manual glossary exists, defer appending
                if enable_auto_glossary_subprocess and (not manual_glossary_path or not os.path.exists(manual_glossary_path)):
                    self.append_log(f"📑 Automatic glossary enabled (minimal mode) - glossary will be appended after generation")
                    # Set a flag to indicate deferred glossary appending
                    os.environ['DEFER_GLOSSARY_APPEND'] = '1'
                    # Store the append prompt for later use
                    glossary_prompt = self.config.get('append_glossary_prompt', 
                        "- Follow this reference glossary for consistent translation (Do not output any raw entries):\n")
                    os.environ['GLOSSARY_APPEND_PROMPT'] = glossary_prompt
                else:
                    # Original behavior - append manual glossary immediately
                    if manual_glossary_path and os.path.exists(manual_glossary_path):
                        try:
                            self.append_log(f"📑 Loading glossary for system prompt: {os.path.basename(manual_glossary_path)}")
                            
                            # Copy to output as the same extension, and prefer CSV naming
                            ext = os.path.splitext(manual_glossary_path)[1].lower()
                            out_name = "glossary.csv" if ext == ".csv" else "glossary.json"
                            output_glossary_path = os.path.join(output_dir, out_name)
                            try:
                                import shutil as _shutil
                                _shutil.copy(manual_glossary_path, output_glossary_path)
                                self.append_log(f"💾 Saved glossary to output folder for auto-loading: {out_name}")
                            except Exception as copy_err:
                                self.append_log(f"⚠️ Could not copy glossary into output: {copy_err}")
                            
                            # Append to prompt
                            if ext == ".csv":
                                with open(manual_glossary_path, 'r', encoding='utf-8') as f:
                                    csv_text = f.read()
                                if system_prompt:
                                    system_prompt += "\n\n"
                                glossary_prompt = self.config.get('append_glossary_prompt', 
                                    "- Follow this reference glossary for consistent translation (Do not output any raw entries):\n")
                                system_prompt += f"{glossary_prompt}\n{csv_text}"
                                self.append_log(f"✅ Appended CSV glossary to system prompt")
                            else:
                                with open(manual_glossary_path, 'r', encoding='utf-8') as f:
                                    glossary_data = json.load(f)
                                
                                formatted_entries = {}
                                if isinstance(glossary_data, list):
                                    for char in glossary_data:
                                        if not isinstance(char, dict):
                                            continue
                                        original = char.get('original_name', '')
                                        translated = char.get('name', original)
                                        if original and translated:
                                            formatted_entries[original] = translated
                                        title = char.get('title')
                                        if title and original:
                                            formatted_entries[f"{original} ({title})"] = f"{translated} ({title})"
                                        refer_map = char.get('how_they_refer_to_others', {})
                                        if isinstance(refer_map, dict):
                                            for other_name, reference in refer_map.items():
                                                if other_name and reference:
                                                    formatted_entries[f"{original} → {other_name}"] = f"{translated} → {reference}"
                                elif isinstance(glossary_data, dict):
                                    if "entries" in glossary_data and isinstance(glossary_data["entries"], dict):
                                        formatted_entries = glossary_data["entries"]
                                    else:
                                        formatted_entries = {k: v for k, v in glossary_data.items() if k != "metadata"}
                                if formatted_entries:
                                    glossary_block = json.dumps(formatted_entries, ensure_ascii=False, indent=2)
                                    if system_prompt:
                                        system_prompt += "\n\n"
                                    glossary_prompt = self.config.get('append_glossary_prompt', 
                                        "- Follow this reference glossary for consistent translation (Do not output any raw entries):\n")
                                    system_prompt += f"{glossary_prompt}\n{glossary_block}"
                                    self.append_log(f"✅ Added {len(formatted_entries)} glossary entries to system prompt")
                                else:
                                    self.append_log(f"⚠️ Glossary file has no valid entries")
                                
                        except Exception as e:
                            self.append_log(f"⚠️ Failed to append glossary to prompt: {str(e)}")
                    else:
                        self.append_log(f"ℹ️ No glossary file found to append to prompt")
            else:
                self.append_log(f"ℹ️ Glossary appending disabled in settings")
                # Clear any deferred append flag
                if 'DEFER_GLOSSARY_APPEND' in os.environ:
                    del os.environ['DEFER_GLOSSARY_APPEND']
            
            # Get temperature and max tokens from GUI
            temperature = float(self.trans_temp.text()) if hasattr(self, 'trans_temp') else 0.3
            max_tokens = self.max_output_tokens
            
            # Initialize history manager for contextual translation if enabled
            history_manager = None
            # Check both checkbox state (runtime) and config variable (initial)
            contextual_enabled = bool(getattr(self, 'contextual_var', False))
            if contextual_enabled:
                try:
                    from history_manager import HistoryManager
                    history_manager = HistoryManager(output_dir)
                    
                    # Add previous context to messages if available
                    history_limit = int(self.trans_history.text()) if hasattr(self, 'trans_history') else 3
                    context_messages = history_manager.load_history()
                    
                    # Limit to the most recent exchanges
                    if context_messages:
                        # Each exchange is 2 messages (user + assistant)
                        messages_to_keep = history_limit * 2
                        context_messages = context_messages[-messages_to_keep:] if len(context_messages) > messages_to_keep else context_messages
                    
                    # Build messages with history. A skipped profile is omitted
                    # entirely; do not send an empty system-role placeholder.
                    messages = []
                    if system_prompt:
                        messages.append({"role": "system", "content": system_prompt})
                    messages.extend(context_messages)
                    
                    if context_messages:
                        num_exchanges = len(context_messages) // 2
                        self.append_log(f"📚 Using {num_exchanges} previous image(s) for context")
                except Exception as e:
                    self.append_log(f"⚠️ Failed to initialize history manager: {e}")
                    import traceback
                    self.append_log(traceback.format_exc())
                    messages = (
                        [{"role": "system", "content": system_prompt}]
                        if system_prompt else []
                    )
            else:
                # Build messages for vision API without history
                messages = (
                    [{"role": "system", "content": system_prompt}]
                    if system_prompt else []
                )

            if getattr(self, '_input_output_run_active', False):
                try:
                    from TransateKRtoEN import (
                        _apply_direct_text_prompt_overrides_to_messages,
                    )
                    messages = _apply_direct_text_prompt_overrides_to_messages(
                        messages
                    )
                except Exception as prompt_error:
                    self.append_log(
                        f"⚠️ Could not apply Direct Text attachment prompt: "
                        f"{prompt_error}"
                    )
            
            self.append_log(f"🌐 Sending image to vision API...")
            self.append_log(f"   System prompt length: {len(system_prompt)} chars")
            self.append_log(f"   Temperature: {temperature}")
            self.append_log(f"   Max tokens: {max_tokens}")          
            
            # Debug: Show first 200 chars of system prompt
            if system_prompt:
                preview = system_prompt[:] if len(system_prompt) > 200 else system_prompt
                prompt_type = "User prompt" if os.environ.get('SYSTEM_PROMPT_TO_USER', '0') == '1' else "System prompt"
                self.append_log(f"   {prompt_type}: {preview}")
            
            # Check stop before making API call
            if self.stop_requested:
                self.append_log("⏹️ Image translation cancelled before API call")
                self.image_progress_manager.update(image_path, content_hash, status="cancelled")
                return False
            
            # Make the API call
            try:
                # Create Payloads/image directory for API response tracking
                # Route to the image subfolder to match unified_api_client routing
                payloads_dir = os.path.join("Payloads", "image")
                try:
                    os.makedirs(payloads_dir, exist_ok=True)
                except (PermissionError, OSError):
                    # Fall back to temp directory if CWD is not writable
                    import tempfile
                    payloads_dir = os.path.join(tempfile.gettempdir(), "Glossarion_Payloads", "image")
                    try:
                        os.makedirs(payloads_dir, exist_ok=True)
                    except Exception:
                        payloads_dir = None  # Skip payload saving entirely
                
                # Create timestamp for unique filename
                timestamp = time.strftime("%Y%m%d_%H%M%S")
                if payloads_dir:
                    payload_file = os.path.join(payloads_dir, f"image_api_{timestamp}_{base_name}.json")
                
                    # Save the request payload
                    request_payload = {
                        "timestamp": time.strftime("%Y-%m-%d %H:%M:%S"),
                        "model": model,
                        "image_file": image_name,
                        "image_size_mb": size_mb,
                        "temperature": temperature,
                        "max_tokens": max_tokens,
                        "messages": messages,
                        "image_base64": image_base64  # Full payload without truncation
                    }
                
                    with open(payload_file, 'w', encoding='utf-8') as f:
                        json.dump(request_payload, f, ensure_ascii=False, indent=2)
                
                    self.append_log(f"📝 Saved request payload: {payload_file}")
                
                # Call the vision API with interrupt support
                # Check if the client supports a stop_callback parameter
                # Import the send_with_interrupt function from TransateKRtoEN
                try:
                    from TransateKRtoEN import send_with_interrupt
                except ImportError:
                    self.append_log("⚠️ send_with_interrupt not available, using direct call")
                    send_with_interrupt = None
                
                # Initialize raw_obj to None for both paths
                raw_obj = None
                
                # Call the vision API with interrupt support
                if send_with_interrupt:
                    # For image calls, we need a wrapper since send_with_interrupt expects client.send()
                    # Create a temporary wrapper client that handles image calls
                    class ImageClientWrapper:
                        def __init__(self, real_client, image_data, response_name):
                            self.real_client = real_client
                            self.image_data = image_data
                            self.response_name = response_name
                        
                        def send(self, messages, temperature, max_tokens):
                            return self.real_client.send_image(messages, self.image_data, temperature=temperature, max_tokens=max_tokens, response_name=self.response_name if hasattr(self, 'response_name') else None)
                        
                        def __getattr__(self, name):
                            return getattr(self.real_client, name)
                    
                    # Create wrapped client with source filename
                    wrapped_client = ImageClientWrapper(client, image_base64, image_name)
                    
                    # Use send_with_interrupt
                    response, finish_reason_from_send, raw_obj = send_with_interrupt(
                        messages,
                        wrapped_client,
                        temperature,
                        max_tokens,
                        lambda: self.stop_requested,
                        chunk_timeout=self.config.get('chunk_timeout', 1200)  # 20 min default
                    )
                else:
                    # Fallback to direct call
                    response = client.send_image(
                        messages,
                        image_base64,
                        temperature=temperature,
                        max_tokens=max_tokens,
                        response_name=image_name
                    )
                    # Try to get raw_obj from response if available
                    if hasattr(response, 'raw_content_object'):
                        raw_obj = response.raw_content_object
                
                # Check if stopped after API call
                if self.stop_requested:
                    self.append_log("⏹️ Image translation stopped after API call")
                    self.image_progress_manager.update(image_path, content_hash, status="cancelled")
                    return False
                
                # Extract content and finish reason from response
                response_content = None
                finish_reason = None
                
                if hasattr(response, 'content'):
                    response_content = response.content
                    finish_reason = response.finish_reason if hasattr(response, 'finish_reason') else 'unknown'
                elif isinstance(response, tuple) and len(response) >= 2:
                    # Handle tuple response (content, finish_reason)
                    response_content, finish_reason = response
                elif isinstance(response, str):
                    # Handle direct string response
                    response_content = response
                    finish_reason = 'complete'
                else:
                    self.append_log(f"❌ Unexpected response type: {type(response)}")
                    self.append_log(f"   Response: {response}")
                
                # Save the response payload
                response_payload = {
                    "timestamp": time.strftime("%Y-%m-%d %H:%M:%S"),
                    "response_content": response_content,
                    "finish_reason": finish_reason,
                    "content_length": len(response_content) if response_content else 0
                }
                
                if payloads_dir:
                    response_file = os.path.join(payloads_dir, f"image_api_response_{timestamp}_{base_name}.json")
                    with open(response_file, 'w', encoding='utf-8') as f:
                        json.dump(response_payload, f, ensure_ascii=False, indent=2)
                
                    self.append_log(f"📝 Saved response payload: {response_file}")
                
                # Check if we got valid content
                if not response_content or response_content.strip() == "[IMAGE TRANSLATION FAILED]":
                    self.append_log(f"❌ Image translation failed - no text extracted from image")
                    self.append_log(f"   This may mean:")
                    self.append_log(f"   - The image doesn't contain readable text")
                    self.append_log(f"   - The model couldn't process the image")
                    self.append_log(f"   - The image format is not supported")
                    
                    # Try to get more info about the failure
                    if hasattr(response, 'error_details'):
                        self.append_log(f"   Error details: {response.error_details}")
                    
                    self.image_progress_manager.update(image_path, content_hash, status="error", error="No text extracted")
                    return False
                
                if response_content:
                    self.append_log(f"✅ Received translation from API")
                    
                    # ── Decode data:image/...;base64, responses (gpt-image-2, etc.) ──────
                    if response_content.startswith("data:image/"):
                        try:
                            # Parse   data:<mime>;base64,<data>
                            header, b64data = response_content.split(",", 1)
                            # Determine extension from mime type
                            mime = header.split(";")[0].split(":")[1].lower()  # e.g. image/png
                            ext  = mime.split("/")[-1]  # png / jpeg / webp …
                            if ext == "jpeg":
                                ext = "jpg"

                            # Build output path next to other translated images
                            os.makedirs(output_dir, exist_ok=True)
                            base_name = os.path.splitext(image_name)[0]
                            generated_image_path = os.path.join(output_dir, f"{base_name}_generated.{ext}")

                            import base64 as _b64
                            with open(generated_image_path, "wb") as _f:
                                _f.write(_b64.b64decode(b64data))

                            self.append_log(f"✅ Generated image decoded and saved: {os.path.basename(generated_image_path)}")

                            # Track for CBZ compilation
                            if not hasattr(self, 'generated_images'):
                                self.generated_images = []
                            self.generated_images.append(generated_image_path)

                            self.image_progress_manager.update(image_path, content_hash, output_file=generated_image_path, status="completed")

                            self.append_log(f"💾 Image saved to: {generated_image_path}")
                            self.append_log(f"📁 Output directory: {output_dir}")
                            return True
                        except Exception as _dec_err:
                            self.append_log(f"⚠️ Failed to decode base64 image: {_dec_err} — saving as text")
                            # Fall through to normal text handling below

                    # Check if this is a generated image response (Gemini-style sentinel)
                    if response_content.startswith("[GENERATED_IMAGE:"):

                        # Extract the image path
                        import re
                        match = re.search(r'\[GENERATED_IMAGE:(.+?)\]', response_content)
                        if match:
                            generated_image_path = match.group(1)
                            if os.path.exists(generated_image_path):
                                # Move the generated file to the actual output folder with the proper name
                                import shutil
                                _, ext = os.path.splitext(generated_image_path)
                                final_media_name = f"response_{file_index:03d}_{base_name}{ext}"
                                final_media_path = os.path.join(output_dir, final_media_name)
                                os.makedirs(output_dir, exist_ok=True)
                                shutil.move(generated_image_path, final_media_path)
                                generated_image_path = final_media_path
                                
                                self.append_log(f"✅ Generated media saved directly as: {final_media_name}")
                                
                                # Track this image for CBZ compilation
                                if not hasattr(self, 'generated_images'):
                                    self.generated_images = []
                                self.generated_images.append(generated_image_path)
                                
                                # Update progress as completed (no HTML file needed)
                                self.image_progress_manager.update(image_path, content_hash, output_file=generated_image_path, status="completed")
                                
                                # Save to history manager if contextual translation is enabled
                                if history_manager:
                                    try:
                                        # Use raw_obj from send_with_interrupt or response.raw_content_object
                                        thought_signature = raw_obj if raw_obj else None
                                        
                                        # Use microsecond lock for thread safety
                                        import threading
                                        if not hasattr(self, '_history_lock'):
                                            self._history_lock = threading.Lock()
                                        
                                        with self._history_lock:
                                            # For generated images, save only the assistant message with image
                                            # No user message needed - just the generated image as context
                                            history_limit = int(self.trans_history.text()) if hasattr(self, 'trans_history') else 3
                                            rolling_history = True
                                            
                                            # Store structured payload for image exchange
                                            assistant_payload = {
                                                "type": "image_exchange",
                                                "version": 1,
                                                "image_path": generated_image_path,
                                                "image_name": os.path.basename(generated_image_path)
                                            }
                                            
                                            history_manager.append_to_history(
                                                user_content="",  # Empty - no need to send source image name to API
                                                assistant_content=assistant_payload,
                                                hist_limit=history_limit,
                                                reset_on_limit=not rolling_history,
                                                rolling_window=rolling_history,
                                                raw_assistant_object=thought_signature
                                            )
                                        self.append_log(f"📚 Saved to translation history with image context")
                                    except Exception as e:
                                        self.append_log(f"⚠️ Failed to save to history: {e}")
                                        import traceback
                                        self.append_log(traceback.format_exc())
                                
                                # Skip HTML generation for generated images
                                self.append_log(f"💾 Image saved to: {generated_image_path}")
                                self.append_log(f"📁 Output directory: {output_dir}")
                                return True
                    
                    # We already have output_dir defined at the top
                    # Copy original image to the output directory if not using combined output
                    if not combined_output_dir and not os.path.exists(os.path.join(output_dir, image_name)):
                        os.makedirs(output_dir, exist_ok=True)
                        shutil.copy2(image_path, os.path.join(output_dir, image_name))
                    
                    # Get book title prompt for translating the filename
                    book_title_prompt = self.config.get('book_title_prompt', '')
                    book_title_system_prompt = self.config.get('book_title_system_prompt', '')
                    
                    # If no book title prompt in main config, check in profile
                    if not book_title_prompt and isinstance(prompt_profiles, dict) and profile_name in prompt_profiles:
                        profile_data = prompt_profiles[profile_name]
                        if isinstance(profile_data, dict):
                            book_title_prompt = profile_data.get('book_title_prompt', '')
                            # Also check for system prompt in profile
                            if 'book_title_system_prompt' in profile_data:
                                book_title_system_prompt = profile_data['book_title_system_prompt']
                    
                    # If still no book title prompt, use the main system prompt
                    if not book_title_prompt:
                        book_title_prompt = system_prompt
                    
                    # If no book title system prompt configured, use the main system prompt
                    if not book_title_system_prompt:
                        book_title_system_prompt = system_prompt
                    
                    # Translate the image filename/title (unless skipped)
                    skip_img_title = bool(getattr(self, 'skip_image_title_translation_var', True) or self.config.get('skip_image_title_translation', True) or os.environ.get('SKIP_IMAGE_TITLE_TRANSLATION') == '1')
                    if skip_img_title:
                        self.append_log("⏭️ Skipping image title translation (setting enabled)")
                        translated_title = base_name
                    else:
                        self.append_log(f"📝 Translating image title...")
                    
                    # Replace {target_lang} variable in both system and user prompts with output language
                    output_lang = self.config.get('output_language', 'English')
                    book_title_system_prompt_formatted = book_title_system_prompt.replace('{target_lang}', output_lang)
                    book_title_prompt_formatted = book_title_prompt.replace('{target_lang}', output_lang)
                    
                    title_messages = [
                        {"role": "system", "content": book_title_system_prompt_formatted},
                        {"role": "user", "content": f"{book_title_prompt_formatted}\n\n{base_name}" if book_title_prompt != system_prompt else base_name}
                    ]
                    
                    if not skip_img_title:
                        try:
                            # Check for stop before title translation
                            graceful_stop_active = os.environ.get('GRACEFUL_STOP') == '1'
                            if self.stop_requested or graceful_stop_active:
                                self.append_log("⏹️ Image translation cancelled before title translation")
                                self.image_progress_manager.update(image_path, content_hash, status="cancelled")
                                return False
                            
                            title_response = client.send(
                                title_messages,
                                temperature=temperature,
                                max_tokens=max_tokens
                            )
                            
                            # Extract title translation
                            if hasattr(title_response, 'content'):
                                translated_title = title_response.content.strip() if title_response.content else base_name
                            else:
                                # Handle tuple response
                                title_content, *_ = title_response
                                translated_title = title_content.strip() if title_content else base_name
                        except Exception as e:
                            # If stop/graceful stop toggled during title call, don't treat as failure
                            if self.stop_requested or os.environ.get('GRACEFUL_STOP') == '1' or "cancelled" in str(e).lower():
                                self.append_log("⏹️ Image title translation cancelled")
                                translated_title = base_name
                            else:
                                self.append_log(f"⚠️ Title translation failed: {str(e)}")
                                translated_title = base_name  # Fallback to original if translation fails
                    
                    # Create clean HTML content with just the translated title and content
                    html_content = f'''<!DOCTYPE html>
    <html>
    <head>
        <meta charset="utf-8"/>
        <title>{translated_title}</title>
        <style>
            body {{ 
                font-family: Arial, sans-serif; 
                line-height: 1.6; 
                margin: 40px;
                max-width: 800px;
            }}
            h1 {{
                color: #333;
                border-bottom: 2px solid #0066cc;
                padding-bottom: 10px;
            }}
        </style>
    </head>
    <body>
        <h1>{translated_title}</h1>
        {response_content}
    </body>
    </html>'''
                    
                    # Save HTML file with proper numbering
                    html_file = os.path.join(output_dir, f"response_{file_index:03d}_{base_name}.html")
                    with open(html_file, 'w', encoding='utf-8') as f:
                        f.write(html_content)
                    
                    # Copy original image to the output directory (for reference, not displayed)
                    if not combined_output_dir:
                        shutil.copy2(image_path, os.path.join(output_dir, image_name))
                    
                    # Update progress to completed
                    self.image_progress_manager.update(image_path, content_hash, output_file=html_file, status="completed")
                    
                    # Show preview
                    if response_content and response_content.strip():
                        preview = response_content[:200] + "..." if len(response_content) > 200 else response_content
                        self.append_log(f"📝 Translation preview:")
                        self.append_log(f"{preview}")
                    else:
                        self.append_log(f"⚠️ Translation appears to be empty")
                    
                    self.append_log(f"✅ Translation saved to: {html_file}")
                    self.append_log(f"📁 Output directory: {output_dir}")
                    
                    return True
                else:
                    self.append_log(f"❌ No translation received from API")
                    if finish_reason:
                        self.append_log(f"   Finish reason: {finish_reason}")
                    self.image_progress_manager.update(image_path, content_hash, status="error", error="No response from API")
                    return False
                    
            except Exception as e:
                # Check if this was a stop/interrupt exception
                if "stop" in str(e).lower() or "interrupt" in str(e).lower() or self.stop_requested:
                    self.append_log("⏹️ Image translation interrupted")
                    self.image_progress_manager.update(image_path, content_hash, status="cancelled")
                    return False
                else:
                    self.append_log(f"❌ API call failed: {str(e)}")
                    import traceback
                    self.append_log(f"❌ Full error: {traceback.format_exc()}")
                    self.image_progress_manager.update(image_path, content_hash, status="error", error=f"API call failed: {e}")
                    return False
            
        except Exception as e:
            self.append_log(f"❌ Error processing image: {str(e)}")
            import traceback
            self.append_log(f"❌ Full error: {traceback.format_exc()}")
            return False
        
    def _process_rpgmaker_game(self, exe_path):
        """Process an RPG Maker game executable via GTool pipeline.

        Mode behaviour:
          - Text mode  → text-only translation (unchanged)
          - Image mode → image-asset-only translation (no text)
        """
        try:
            import rpgmaker_handler

            self.append_log(f"\n{'='*60}")
            self.append_log(f"🎮 GTool: RPG Maker Game Translation")
            self.append_log(f"📁 Game: {os.path.basename(exe_path)}")
            self.append_log(f"{'='*60}")

            # Load translation modules if needed
            if not self._modules_loaded:
                if not self._lazy_load_modules():
                    self.append_log("❌ Failed to load translation modules")
                    return False

            game_dir = os.path.dirname(os.path.abspath(exe_path))

            # Detect version & data dir (needed by both modes)
            version, data_dir, all_strings = rpgmaker_handler.extract_all(
                game_dir, self.append_log)

            if version == rpgmaker_handler.RPGMakerVersion.UNKNOWN:
                self.append_log("❌ Could not detect RPG Maker version")
                return False

            # ── Check output mode ────────────────────────────────
            image_mode = (
                os.environ.get('ENABLE_IMAGE_TRANSLATION', '0') == '1'
                or getattr(self, 'enable_image_translation_var', False)
            )

            # Set up common env / client
            api_key = self.api_key_entry.text()
            output_lang = self.config.get('output_language', 'English')
            from unified_api_client import UnifiedClient
            gtool_out = os.path.join(game_dir, "GTool_Translation")

            # Initialize key pools from config (normally done by _get_environment_variables,
            # but image mode bypasses that path)
            try:
                # Env toggles
                os.environ['USE_MULTI_KEYS'] = '1' if self.config.get('use_multi_api_keys', False) else '0'
                os.environ['USE_FALLBACK_KEYS'] = '1' if self.config.get('use_fallback_keys', False) else '0'
                os.environ['USE_MAIN_KEY_FALLBACK'] = '1' if self.config.get('use_main_key_fallback', True) else '0'
                os.environ['FALLBACK_KEY_SHUFFLE'] = '1' if self.config.get('fallback_key_shuffle', False) else '0'
                os.environ['USE_GLOSSARY_KEYS'] = '1' if self.config.get('use_glossary_keys', False) else '0'
                refinement_keys_enabled = self.config.get('use_glossary_refinement_keys', False)
                refinement_keys = self.config.get('glossary_refinement_keys', [])
                metadata_keys_enabled = self.config.get('use_metadata_keys', False)
                metadata_keys = self.config.get('metadata_keys', [])
                vision_keys_enabled = self.config.get('use_qa_scan_keys', False)
                vision_keys = self.config.get('qa_scan_keys', [])
                rolling_summary_keys_enabled = self.config.get('use_rolling_summary_keys', False)
                rolling_summary_keys = self.config.get('rolling_summary_keys', [])
                truncation_retry_keys_enabled = self.config.get('use_truncation_retry_keys', False)
                truncation_retry_keys = self.config.get('truncation_retry_keys', [])
                inpainter_keys_enabled = self.config.get('use_inpainter_keys', False)
                inpainter_keys = self.config.get('inpainter_keys', [])
                os.environ['USE_VISION_KEYS'] = '1' if vision_keys_enabled else '0'
                os.environ['USE_QA_SCAN_KEYS'] = os.environ['USE_VISION_KEYS']
                os.environ['USE_ROLLING_SUMMARY_KEYS'] = '1' if rolling_summary_keys_enabled else '0'
                os.environ['USE_TRUNCATION_RETRY_KEYS'] = '1' if truncation_retry_keys_enabled else '0'
                os.environ['USE_INPAINTER_KEYS'] = '1' if inpainter_keys_enabled else '0'
                os.environ['FALLBACK_KEYS'] = json.dumps(self.config.get('fallback_keys', []))
                os.environ['GLOSSARY_API_KEYS'] = json.dumps(self.config.get('glossary_keys', []))
                os.environ['USE_GLOSSARY_REFINEMENT_KEYS'] = '1' if refinement_keys_enabled else '0'
                os.environ['GLOSSARY_REFINEMENT_API_KEYS'] = json.dumps(refinement_keys)
                os.environ['USE_METADATA_KEYS'] = '1' if metadata_keys_enabled else '0'
                os.environ['METADATA_API_KEYS'] = json.dumps(metadata_keys)
                os.environ['VISION_API_KEYS'] = json.dumps(vision_keys)
                os.environ['QA_SCAN_API_KEYS'] = os.environ['VISION_API_KEYS']
                os.environ['ROLLING_SUMMARY_API_KEYS'] = json.dumps(rolling_summary_keys)
                os.environ['TRUNCATION_RETRY_API_KEYS'] = json.dumps(truncation_retry_keys)
                os.environ['INPAINTER_API_KEYS'] = json.dumps(inpainter_keys)

                # In-memory key pools
                if self.config.get('use_multi_api_keys', False) and self.config.get('multi_api_keys', []):
                    UnifiedClient.set_in_memory_multi_keys(
                        self.config.get('multi_api_keys', []),
                        force_rotation=self.config.get('force_key_rotation', True),
                        rotation_frequency=self.config.get('rotation_frequency', 1),
                    )
                if self.config.get('use_glossary_keys', False) and self.config.get('glossary_keys', []):
                    UnifiedClient.set_in_memory_glossary_keys(
                        self.config.get('glossary_keys', []),
                        force_rotation=self.config.get('force_key_rotation', True),
                        rotation_frequency=self.config.get('rotation_frequency', 1),
                    )
                if refinement_keys_enabled and refinement_keys:
                    UnifiedClient.set_in_memory_glossary_refinement_keys(
                        refinement_keys,
                        force_rotation=self.config.get('force_key_rotation', True),
                        rotation_frequency=self.config.get('rotation_frequency', 1),
                    )
                if vision_keys_enabled and vision_keys:
                    ok = UnifiedClient.set_in_memory_vision_keys(
                        vision_keys,
                        force_rotation=self.config.get('force_key_rotation', True),
                        rotation_frequency=self.config.get('rotation_frequency', 1),
                    )
                    pool = getattr(UnifiedClient, '_qa_scan_key_pool', None)
                    configured_count = len(vision_keys)
                    loaded_count = len(getattr(pool, 'keys', [])) if pool else 0
                    load_note = f", {loaded_count} loaded" if loaded_count != configured_count else ""
                    status_detail = str(getattr(UnifiedClient, '_last_qa_scan_pool_setup_status', '') or '').strip()
                    status_note = f": {status_detail}" if (not ok and status_detail) else ""
                    self.append_log(f"[GTool] Vision key pool: {configured_count} entries configured{load_note} (setup={'OK' if ok else 'FAILED'}{status_note})")
                else:
                    if vision_keys_enabled:
                        self.append_log("[GTool] Vision Keys enabled but no keys configured")
                if rolling_summary_keys_enabled and rolling_summary_keys:
                    ok = UnifiedClient.set_in_memory_rolling_summary_keys(
                        rolling_summary_keys,
                        force_rotation=self.config.get('force_key_rotation', True),
                        rotation_frequency=self.config.get('rotation_frequency', 1),
                    )
                    pool = getattr(UnifiedClient, '_rolling_summary_key_pool', None)
                    pool_count = len(getattr(pool, 'keys', [])) if pool else 0
                    self.append_log(f"[GTool] Rolling summary key pool: {pool_count} keys loaded (setup={'OK' if ok else 'FAILED'})")
                elif rolling_summary_keys_enabled:
                    self.append_log("[GTool] Rolling Summary Keys enabled but no keys configured")
                if truncation_retry_keys_enabled and truncation_retry_keys:
                    ok = UnifiedClient.set_in_memory_truncation_retry_keys(
                        truncation_retry_keys,
                        force_rotation=self.config.get('force_key_rotation', True),
                        rotation_frequency=self.config.get('rotation_frequency', 1),
                    )
                    pool = getattr(UnifiedClient, '_truncation_retry_key_pool', None)
                    pool_count = len(getattr(pool, 'keys', [])) if pool else 0
                    self.append_log(f"[GTool] Truncation retry key pool: {pool_count} keys loaded (setup={'OK' if ok else 'FAILED'})")
                elif truncation_retry_keys_enabled:
                    self.append_log("[GTool] Truncation Retry Keys enabled but no keys configured")
                if inpainter_keys_enabled and inpainter_keys:
                    ok = UnifiedClient.set_in_memory_inpainter_keys(
                        inpainter_keys,
                        force_rotation=self.config.get('force_key_rotation', True),
                        rotation_frequency=self.config.get('rotation_frequency', 1),
                    )
                    pool = getattr(UnifiedClient, '_inpainter_key_pool', None)
                    configured_count = len(inpainter_keys)
                    loaded_count = len(getattr(pool, 'keys', [])) if pool else 0
                    load_note = f", {loaded_count} loaded" if loaded_count != configured_count else ""
                    status_detail = str(getattr(UnifiedClient, '_last_inpainter_pool_setup_status', '') or '').strip()
                    status_note = f": {status_detail}" if (not ok and status_detail) else ""
                    self.append_log(f"[GTool] Image gen/edit key pool: {configured_count} entries configured{load_note} (setup={'OK' if ok else 'FAILED'}{status_note})")
                elif inpainter_keys_enabled:
                    self.append_log("[GTool] Image Gen / Edit Keys enabled but no keys configured")
            except Exception as e:
                self.append_log(f"[GTool] ⚠️ Key pool init error: {e}")

            # ── IMAGE MODE: image-asset-only translation ─────────
            if image_mode:
                # MV/MZ only (older engines don't use JS encryption)
                if version not in (rpgmaker_handler.RPGMakerVersion.MV,
                                   rpgmaker_handler.RPGMakerVersion.MZ):
                    self.append_log("⚠️ Image translation is only supported for MV/MZ games")
                    return False

                self.append_log("🖼️ Output mode: Image — translating game image assets only")

                # Set API call delay from GUI
                os.environ['SEND_INTERVAL_SECONDS'] = str(self.delay_entry.text() or '2.0')

                # Determine parallelism from batch settings
                use_batch = getattr(self, 'batch_translation_var', True)
                batch_size = max(1, int(getattr(self, 'batch_size_var', 5))) if use_batch else 1
                if use_batch:
                    self.append_log(f"⚡ Batch mode: {batch_size} parallel workers")

                img_client = UnifiedClient(
                    model=self.model_var,
                    api_key=api_key,
                    output_dir=gtool_out,
                )

                # Load system prompt from the image profile
                img_prompt = ""
                try:
                    profiles = getattr(self, 'prompt_profiles', {})
                    if "RPGMaker_GTool_Image" in profiles:
                        img_prompt = profiles["RPGMaker_GTool_Image"]
                    elif hasattr(self, 'default_prompts') and "RPGMaker_GTool_Image" in self.default_prompts:
                        img_prompt = self.default_prompts["RPGMaker_GTool_Image"]
                except Exception:
                    pass

                # Load filter prompts from settings
                filter_sys = getattr(self, 'gtool_filter_user_prompt_var', '') or ''  # system prompt (legacy var name)
                filter_usr = getattr(self, 'gtool_scan_user_prompt_var', '') or ''    # user prompt

                img_count = rpgmaker_handler.translate_game_images(
                    game_dir=game_dir,
                    data_dir=data_dir,
                    client=img_client,
                    target_lang=output_lang,
                    system_prompt=img_prompt,
                    filter_system_prompt=filter_sys,
                    filter_user_prompt=filter_usr,
                    temperature=float(self.trans_temp.text() or "0.3"),
                    max_tokens=self.max_output_tokens,
                    batch_size=batch_size,
                    api_key=api_key,
                    model=self.model_var,
                    output_dir=gtool_out,
                    log=self.append_log,
                    stop_check=lambda: self.stop_requested,
                )

                self.append_log(f"🎮 GTool: Image translation complete!")
                self.append_log(f"💾 Translation data: {gtool_out}")
                self.append_log(f"📁 Backups: {os.path.join(gtool_out, 'originals_backup')}")
                return img_count > 0

            # ── TEXT MODE: text-only translation (original path) ──
            if not all_strings:
                self.append_log("❌ No translatable strings found - is this an RPG Maker game?")
                return False

            total_strings = sum(len(v) for v in all_strings.values())
            self.append_log(f"📊 Found {total_strings} translatable strings")

            # Build chunks — use tiktoken for accurate token counting.
            # Budget = output_limit / compression_factor (each JP token
            # typically expands to ~compression_factor EN tokens in output).
            compression_factor = float(getattr(self, 'compression_factor_var', '3.0') or '3.0')
            if compression_factor <= 0:
                compression_factor = 3.0
            safety_margin = 200
            max_chunk_tokens = max(500, int((self.max_output_tokens - safety_margin) / compression_factor))
            chunks = rpgmaker_handler.build_translation_chunks(all_strings, max_tokens=max_chunk_tokens)
            self.append_log(f"📦 Split into {len(chunks)} translation chunks "
                          f"(max {max_chunk_tokens:,} tokens/chunk, "
                          f"compression: {compression_factor}x, "
                          f"output limit: {self.max_output_tokens:,})")

            # Load progress for resume
            progress = rpgmaker_handler.load_progress(game_dir)
            # Scrub empty-valued and escape-code-only entries from previous runs
            # (e.g. AI returned empty or bare \\c translation, old code stored it as "done")
            bad_keys = [k for k, v in progress.items()
                        if isinstance(v, str) and (not v or not v.strip()
                                                   or rpgmaker_handler._is_escape_only(v))]
            if bad_keys:
                for k in bad_keys:
                    del progress[k]
                rpgmaker_handler.save_progress(game_dir, progress)
                self.append_log(f"🧹 Cleaned {len(bad_keys)} invalid translations from progress")

            # Detect stale translations from previous runs where originals
            # were corrupted (now restored from backup).
            stale_count = rpgmaker_handler.scrub_stale_progress(
                progress, all_strings, self.append_log)
            if stale_count:
                rpgmaker_handler.save_progress(game_dir, progress)

            # Ensure identical originals get the same translation
            # (e.g. '留奈' must always be 'Runa', never sometimes 'Luna')
            consistency_fixes = rpgmaker_handler.enforce_translation_consistency(
                progress, all_strings, self.append_log)
            if consistency_fixes:
                rpgmaker_handler.save_progress(game_dir, progress)

            if progress:
                self.append_log(f"📋 Resuming: {len(progress)} strings already translated")

            # Create translation map file
            trans_path = rpgmaker_handler.create_translation_file(
                game_dir, all_strings, self.append_log)

            # Set up environment for translation
            system_prompt = self.prompt_text.toPlainText().strip()
            system_prompt = system_prompt.replace('{target_lang}', output_lang)
            import re
            system_prompt = re.sub(r'\s*\{split_marker_instruction\}\s*', '', system_prompt)

            os.environ['API_KEY'] = api_key
            os.environ['SYSTEM_PROMPT'] = system_prompt
            os.environ['MODEL'] = self.model_var
            os.environ['IS_TEXT_FILE_TRANSLATION'] = '1'

            # Set API call delay from GUI (same as image mode + main pipeline)
            os.environ['SEND_INTERVAL_SECONDS'] = str(self.delay_entry.text() or '2.0')
            os.environ['THREAD_SUBMISSION_DELAY_SECONDS'] = self.thread_delay_entry.text().strip() or '0.0001'

            # Determine parallelism from batch settings
            use_batch = getattr(self, 'batch_translation_var', True)
            batch_size = max(1, int(getattr(self, 'batch_size_var', 5))) if use_batch else 1
            if use_batch:
                self.append_log(f"⚡ Batch mode: {batch_size} parallel workers")

            # Pre-filter chunks to only those with untranslated keys
            pending_chunks = []
            for i, chunk in enumerate(chunks):
                new_keys = []
                new_texts = []
                for k, t in zip(chunk["keys"], chunk["texts"]):
                    if k not in progress or not progress[k].strip():
                        new_keys.append(k)
                        new_texts.append(t)
                if new_keys:
                    pending_chunks.append((i, {"keys": new_keys, "texts": new_texts}))

            self.append_log(f"📦 {len(pending_chunks)} chunks need translation (of {len(chunks)} total)")

            translated_count = 0
            progress_lock = __import__('threading').Lock()

            # Tell _send_core not to serialise requests behind the sequential lock
            _prev_batch = os.environ.get('BATCH_TRANSLATION', '')
            if batch_size > 1:
                os.environ['BATCH_TRANSLATION'] = '1'

            # Single shared client — same pattern as Chapter_Extractor / image mode.
            # BATCH_TRANSLATION=1 bypasses _sequential_send_lock in _send_core.
            shared_client = UnifiedClient(
                model=self.model_var,
                api_key=api_key,
                output_dir=gtool_out,
            )

            def _translate_chunk(chunk_info):
                """Worker function for translating a single chunk."""
                idx, sub_chunk = chunk_info
                source = rpgmaker_handler.format_chunk_for_translation(sub_chunk)
                messages = [
                    {"role": "system", "content": system_prompt},
                    {"role": "user", "content": source},
                ]
                result = shared_client.send(
                    messages=messages,
                    temperature=float(self.trans_temp.text() or "0.3"),
                    max_tokens=self.max_output_tokens,
                )
                response_text = ""
                if result:
                    if isinstance(result, tuple):
                        response_text = result[0] if result[0] else ""
                    elif isinstance(result, str):
                        response_text = result
                    elif hasattr(result, 'content'):
                        response_text = result.content or ""
                if response_text:
                    parsed = rpgmaker_handler.parse_translated_chunk(
                        response_text, sub_chunk)
                    return idx, parsed, len(sub_chunk["keys"])
                return idx, {}, len(sub_chunk["keys"])

            from concurrent.futures import ThreadPoolExecutor, as_completed

            with ThreadPoolExecutor(max_workers=batch_size) as pool:
                futures = {}
                for chunk_info in pending_chunks:
                    if self.stop_requested:
                        break
                    future = pool.submit(_translate_chunk, chunk_info)
                    futures[future] = chunk_info[0]  # map future -> chunk index

                for future in as_completed(futures):
                    if self.stop_requested:
                        self.append_log("⏹️ Translation stopped by user")
                        break
                    chunk_idx = futures[future]
                    try:
                        idx, parsed, total_keys = future.result()
                        if parsed:
                            with progress_lock:
                                progress.update(parsed)
                                translated_count += len(parsed)
                                rpgmaker_handler.save_progress(game_dir, progress)
                            self.append_log(
                                f"   ✅ Chunk {idx+1}/{len(chunks)}: "
                                f"{len(parsed)}/{total_keys} translated")
                        else:
                            self.append_log(
                                f"   ⚠️ Chunk {idx+1}/{len(chunks)}: "
                                f"no translations parsed")
                    except Exception as e:
                        self.append_log(f"   ⚠️ Chunk {chunk_idx+1} failed: {e}")

            self.append_log(f"\n📊 Translated {translated_count} strings total")

            # Restore batch mode env var
            if _prev_batch:
                os.environ['BATCH_TRANSLATION'] = _prev_batch
            elif 'BATCH_TRANSLATION' in os.environ:
                del os.environ['BATCH_TRANSLATION']

            # Update translation map
            try:
                with open(trans_path, 'r', encoding='utf-8') as f:
                    trans_data = json.load(f)
                for full_key, translated in progress.items():
                    parts = full_key.split("::", 1)
                    if len(parts) == 2:
                        fn, key = parts
                        if fn in trans_data and key in trans_data[fn]:
                            trans_data[fn][key]["translated"] = translated
                with open(trans_path, 'w', encoding='utf-8') as f:
                    json.dump(trans_data, f, ensure_ascii=False, indent=2)
            except Exception as e:
                self.append_log(f"⚠️ Failed to update translation map: {e}")

            # Apply translations to game files (always — also applies settings like font size)
            if progress:
                self.append_log("🔧 Applying translations to game files...")
                rpgmaker_handler.apply_translations(
                    data_dir, trans_path, self.append_log, version=version,
                    game_dir=game_dir)

            self.append_log(f"🎮 GTool: Translation complete!")
            self.append_log(f"💾 Translation data: {os.path.join(game_dir, 'GTool_Translation')}")
            self.append_log(f"📁 Backups: {os.path.join(game_dir, 'GTool_Translation', 'originals_backup')}")
            return translated_count > 0

        except Exception as e:
            self.append_log(f"❌ GTool error: {str(e)}")
            import traceback
            self.append_log(f"❌ Full error: {traceback.format_exc()}")
            return False

    def _process_text_file(self, file_path):
        """Process EPUB, text-like, PDF, or SDLXLIFF files."""
        try:
            if translation_main is None:
                self.append_log("❌ Translation module is not available")
                return False

            api_key = self.api_key_entry.text()
            model = self.model_var
            
            # Check if model needs API key (delegates to UnifiedClient's authoritative list)
            try:
                from unified_api_client import UnifiedClient as _UC
                model_needs_api_key = _UC._model_needs_api_key(model)
            except Exception:
                model_needs_api_key = bool(model)  # safe fallback
            
            # Validate API key and model (same as original)
            if '@' in model or model.startswith('vertex/'):
                google_creds = self.config.get('google_cloud_credentials')
                if not google_creds or not os.path.exists(google_creds):
                    self.append_log("❌ Error: Google Cloud credentials required for Vertex AI models.")
                    return False
                
                os.environ['GOOGLE_APPLICATION_CREDENTIALS'] = google_creds
                self.append_log(f"🔑 Using Google Cloud credentials: {os.path.basename(google_creds)}")
                
                if not api_key:
                    try:
                        with open(google_creds, 'r') as f:
                            creds_data = json.load(f)
                            api_key = creds_data.get('project_id', 'vertex-ai-project')
                            self.append_log(f"🔑 Using project ID as API key: {api_key}")
                    except:
                        api_key = 'vertex-ai-project'
            elif model_needs_api_key and not api_key:
                self.append_log("❌ Error: Please enter your API key.")
                return False

            # Determine output directory and save source EPUB path
            if file_path.lower().endswith('.epub'):
                base_name = os.path.splitext(os.path.basename(file_path))[0]
                
                # Check for output directory override
                override_dir = os.environ.get('OUTPUT_DIRECTORY') or self.config.get('output_directory')
                if override_dir:
                    # If absolute, use as is. If relative, join with CWD (or file dir?)
                    # TransateKRtoEN treats it as root, so we should too.
                    # It creates a subdir 'base_name' inside it if it's a root.
                    # Wait, TransateKRtoEN logic: out = os.path.join(output_root, file_base)
                    
                    # So here we should expect the same:
                    output_dir = os.path.join(override_dir, base_name)
                else:
                    output_dir = base_name  # Relative to CWD (default)
                
                # Save source EPUB path for EPUB converter
                source_epub_file = os.path.join(output_dir, 'source_epub.txt')
                try:
                    os.makedirs(output_dir, exist_ok=True)  # Ensure output dir exists
                    with open(source_epub_file, 'w', encoding='utf-8') as f:
                        f.write(file_path)
                    self.append_log(f"📚 Saved source EPUB reference for chapter ordering")
                except Exception as e:
                    self.append_log(f"⚠️ Could not save source EPUB reference: {e}")
                
                # Set EPUB_PATH in environment for immediate use
                os.environ['EPUB_PATH'] = file_path
                
                # Rename existing output files to match current retain-source-extension toggle
                # This must run before translation starts so the progress tracker sees correct filenames
                try:
                    from other_settings import _rename_output_files_for_retain
                    retain = os.getenv('RETAIN_SOURCE_EXTENSION', '0') == '1' or self.config.get('retain_source_extension', False)
                    _rename_output_files_for_retain(self, retain, output_dir=output_dir)
                except Exception as e:
                    self.append_log(f"⚠️ Could not sync output filenames: {e}")

                
            old_argv = sys.argv
            old_env = dict(os.environ)
            

            try:
                # Set up environment (same as original)
                self.append_log(f"🔧 Setting up environment variables...")
                self.append_log(f"📖 File: {os.path.basename(file_path)}")
                self.append_log(f"🤖 Model: {self.model_var}")
                
                # Get the system prompt and log first 100 characters
                system_prompt = self.prompt_text.toPlainText().strip()
                
                # Replace split marker instruction placeholder
                split_instr = ""
                if getattr(self, 'request_merging_enabled_var', False):
                    split_instr = "- CRITICAL Requirement: If you see any HTML tags containing 'SPLIT MARKER' (Example: <h1 id=\"split-1\">SPLIT MARKER: Do Not Remove This Tag</h1>), you MUST preserve them EXACTLY as they appear. Do not translate, modify, or remove these markers."
                
                # Use a regex to replace the placeholder regardless of surrounding whitespace or newlines
                import re
                system_prompt = re.sub(r'\s*\{split_marker_instruction\}\s*', lambda m: '\n' + split_instr if split_instr else '', system_prompt)

                prompt_preview = system_prompt[:] if len(system_prompt) > 100 else system_prompt
                prompt_type = "User prompt" if os.environ.get('SYSTEM_PROMPT_TO_USER', '0') == '1' else "System prompt"
                self.append_log(f"📝 {prompt_type}: {prompt_preview}")
                self.append_log(f"📏 {prompt_type} length: {len(system_prompt)} characters")
                
                # Log assistant prompt if set
                if hasattr(self, 'assistant_prompt') and self.assistant_prompt and self.assistant_prompt.strip():
                    self.append_log(f"🤖 Assistant Prompt: {self.assistant_prompt}")
                
                
                
                # Log glossary status
                if hasattr(self, 'manual_glossary_path') and self.manual_glossary_path:
                    self.append_log(f"📑 Manual glossary loaded: {os.path.basename(self.manual_glossary_path)}")
                else:
                    self.append_log(f"📑 No manual glossary loaded")
                
                # IMPORTANT: Set IS_TEXT_FILE_TRANSLATION flag for text files
                if file_path.lower().endswith(('.txt', '.csv', '.json', '.pdf', '.sdlxliff')):
                    os.environ['IS_TEXT_FILE_TRANSLATION'] = '1'
                    self.append_log("📄 Processing as text file")
                
                # Set environment variables
                multipass_enabled, multipass_refinement_mode = self._export_multipass_runtime_env()
                env_vars = self._get_environment_variables(file_path, api_key)
                env_vars['MULTIPASS_MODE'] = '1' if multipass_enabled else '0'
                env_vars['MULTIPASS_REFINEMENT_MODE'] = multipass_refinement_mode
                
                # Enable async chapter extraction for EPUBs, PDFs, and SDLXLIFF to prevent GUI freezing
                if file_path.lower().endswith(('.epub', '.pdf', '.sdlxliff')):
                    env_vars['USE_ASYNC_CHAPTER_EXTRACTION'] = '1'
                    self.append_log("🚀 Using async chapter extraction (subprocess mode)")
                
                import large_env
                large_env.update_env(env_vars)
                # ``_get_environment_variables`` reflects persisted checkboxes.
                # Live input/output and reader runs intentionally override those
                # values, so re-assert the forced flags after the bulk export.
                if getattr(self, '_force_stream_all', False):
                    self._apply_forced_streaming_environment()
                if getattr(self, '_input_output_run_active', False):
                    self._apply_direct_text_runtime_environment()
                
                # Handle chapter range
                chap_range = self.chapter_range_entry.text().strip()
                if chap_range:
                    os.environ['CHAPTER_RANGE'] = chap_range
                    use_spine = getattr(self, 'use_spine_order_checkbox', None)
                    if use_spine and use_spine.isChecked():
                        os.environ['USE_SPINE_ORDER'] = '1'
                        self.append_log(f"📊 Chapter Range (Spine Order): {chap_range}")
                    else:
                        os.environ['USE_SPINE_ORDER'] = '0'
                        self.append_log(f"📊 Chapter Range: {chap_range}")
                else:
                    os.environ.pop('USE_SPINE_ORDER', None)
                
                # Set other environment variables (token limits, etc.)
                if hasattr(self, 'token_limit_disabled') and self.token_limit_disabled:
                    os.environ['MAX_INPUT_TOKENS'] = ''
                else:
                    token_val = self.token_limit_entry.text().replace(',', '').strip()
                    if token_val and token_val.isdigit():
                        os.environ['MAX_INPUT_TOKENS'] = token_val
                    else:
                        os.environ['MAX_INPUT_TOKENS'] = '1000000'
                
                # Validate glossary path
                if self._current_auto_glossary_mode() == 'no_glossary':
                    # A manual glossary can be reattached during normal text-file
                    # setup. Keep No Glossary authoritative for this run.
                    os.environ.pop('MANUAL_GLOSSARY', None)
                else:
                    # Check per-file mapping first (set by the main loop before calling this method)
                    _mapped_gp = os.environ.get('MANUAL_GLOSSARY', '')
                    if _mapped_gp and os.path.exists(_mapped_gp):
                        # Already set by the per-EPUB mapping loop – keep it
                        pass
                    elif hasattr(self, 'manual_glossary_path') and self.manual_glossary_path:
                        if (hasattr(self, 'auto_loaded_glossary_path') and
                            self.manual_glossary_path == self.auto_loaded_glossary_path):
                            if (hasattr(self, 'auto_loaded_glossary_for_file') and
                                hasattr(self, 'file_path') and
                                self.file_path == self.auto_loaded_glossary_for_file):
                                os.environ['MANUAL_GLOSSARY'] = self.manual_glossary_path
                                self.append_log(f"📑 Using auto-loaded glossary: {os.path.basename(self.manual_glossary_path)}")
                        else:
                            os.environ['MANUAL_GLOSSARY'] = self.manual_glossary_path
                            self.append_log(f"📑 Using manual glossary: {os.path.basename(self.manual_glossary_path)}")
                
                # ── Single-chapter mode (Library / Reader "Translate") ──
                # Only the targeted HTML file is extracted from the EPUB and
                # the run jumps straight to the translation phase. The filter
                # is consumed by Chapter_Extractor._extract_chapters_universal.
                _sc_filter = getattr(self, '_single_chapter_filter', None)
                if _sc_filter:
                    os.environ['SINGLE_CHAPTER_FILTER'] = str(_sc_filter)
                    # Targeted extraction is tiny — run it in-process.
                    os.environ['USE_ASYNC_CHAPTER_EXTRACTION'] = '0'
                    # A leftover chapter range could exclude the target file.
                    os.environ.pop('CHAPTER_RANGE', None)
                    # Re-assert forced streaming AFTER large_env.update_env —
                    # _get_environment_variables exports the user's toggle
                    # values, which would otherwise override the live view.
                    if getattr(self, '_force_stream_all', False):
                        self._apply_forced_streaming_environment()
                    self.append_log(
                        f"🎯 Single-chapter mode: {os.path.basename(str(_sc_filter))} "
                        "(skipping full extraction, jumping to translation)")
                else:
                    os.environ.pop('SINGLE_CHAPTER_FILTER', None)

                # Set sys.argv to match what TransateKRtoEN.py expects
                sys.argv = ['TransateKRtoEN.py', file_path]

                if getattr(self, '_translation_run_is_multipass_qa_refinement', False):
                    mode_label = str(getattr(self, '_translation_run_qa_refinement_mode', '') or 'multipass').title()
                    self.append_log(f"🚀 Starting {mode_label} multipass refinement...")
                else:
                    self.append_log("🚀 Starting translation...")
                
                # Ensure Payloads directory exists (non-fatal if it fails)
                try:
                    os.makedirs("Payloads", exist_ok=True)
                except (PermissionError, OSError):
                    pass  # Payload saving handled by unified_api_client fallback
                
                # Run translation
                translation_result = translation_main(
                    log_callback=self.append_log,
                    stop_callback=lambda: self.stop_requested
                )

                if translation_result is False:
                    self.append_log("❌ Translation did not complete successfully.")
                    return False
                
                if not self.stop_requested:
                    if getattr(self, '_translation_run_is_multipass_qa_refinement', False):
                        mode_label = str(getattr(self, '_translation_run_qa_refinement_mode', '') or 'Multipass').title()
                        self.append_log(f"✅ {mode_label} multipass refinement completed successfully!")
                    else:
                        self.append_log("✅ Translation completed successfully!")
                    return True
                else:
                    return False
                    
            except ValueError as e:
                # ValueError is used for user-facing errors like invalid chapter range
                # These already have clear error messages, so no need for traceback
                error_msg = str(e)
                self.append_log(f"[DEBUG] ValueError caught in _process_text_file: {error_msg}")
                if "Chapter range" not in error_msg:
                    # If it's not a chapter range error, show the message
                    self.append_log(f"❌ Translation error: {e}")
                # Don't show traceback for user-friendly errors
                return False
                
            except Exception as e:
                # Suppress noisy traceback when user stops/cancels (including graceful stop).
                err_str = str(e).lower()

                # Prefer structured cancellation detection when available.
                is_cancelled = False
                try:
                    from unified_api_client import UnifiedClientError
                    if isinstance(e, UnifiedClientError) and getattr(e, 'error_type', None) == 'cancelled':
                        is_cancelled = True
                except Exception:
                    pass

                # Fallback to string matching for legacy/foreign exceptions.
                if (
                    "cancelled by user" in err_str or "canceled by user" in err_str or
                    "operation cancelled" in err_str or "operation canceled" in err_str or
                    "graceful stop active" in err_str
                ):
                    is_cancelled = True

                if is_cancelled:
                    # Keep messaging user-friendly and avoid traceback spam.
                    if "graceful stop" in err_str:
                        self.append_log("⏹️ Graceful stop: not starting new API call")
                    else:
                        self.append_log("❌ Translation stopped by user")
                else:
                    # For other exceptions, show full details
                    self.append_log(f"❌ Translation error: {e}")
                    if hasattr(self, 'append_log_with_api_error_detection'):
                        self.append_log_with_api_error_detection(str(e))
                    import traceback
                    self.append_log(f"❌ Full error: {traceback.format_exc()}")
                return False
            
            finally:
                sys.argv = old_argv
                os.environ.clear()
                os.environ.update(old_env)
                try:
                    import large_env
                    large_env.clear_store()
                except Exception:
                    pass
                
        except Exception as e:
            self.append_log(f"❌ Error in text file processing: {str(e)}")
            return False

    def _apply_forced_streaming_environment(self):
        """Force every streaming/logging switch on for an interactive run."""
        for key in _InputOutputDialog._FORCED_STREAM_ENV_KEYS:
            os.environ[key] = '1'

    def _apply_direct_text_runtime_environment(self):
        """Apply the scoped Direct Text overrides after normal GUI env export."""
        if not getattr(self, '_input_output_run_active', False):
            return

        try:
            import large_env
        except Exception:
            large_env = None

        attachment_prompt = str(
            getattr(self, '_direct_text_attachment_prompt', '') or ''
        ).strip()
        attachment_prompt_role = str(
            getattr(self, '_direct_text_attachment_prompt_role', 'user') or 'user'
        ).strip().lower()
        if attachment_prompt_role not in {'system', 'assistant', 'user'}:
            attachment_prompt_role = 'user'
        skip_prompt_profile = bool(
            getattr(self, '_direct_text_skip_prompt_profile', False)
        )
        os.environ['DIRECT_TEXT_ATTACHMENT_PROMPT_ROLE'] = attachment_prompt_role
        os.environ['DIRECT_TEXT_SKIP_PROMPT_PROFILE'] = (
            '1' if skip_prompt_profile else '0'
        )
        if large_env is not None:
            large_env.set_env('DIRECT_TEXT_ATTACHMENT_PROMPT', attachment_prompt)
        else:
            os.environ['DIRECT_TEXT_ATTACHMENT_PROMPT'] = attachment_prompt

        # Keep the typed attachment instruction's selected role exact. When
        # the selected profile is configured as a user prompt, route only that
        # profile through the scoped user-prefix helper instead of applying the
        # global transform to every system message in the request.
        profile_as_user = bool(getattr(self, 'system_prompt_to_user_var', False))
        profile_prompt = ''
        try:
            profile_prompt = self.prompt_text.toPlainText().strip()
        except Exception:
            profile_prompt = str(self.config.get('system_prompt', '') or '').strip()
        direct_profile_user_prompt = (
            profile_prompt if profile_as_user and not skip_prompt_profile else ''
        )
        if large_env is not None:
            large_env.set_env(
                'DIRECT_TEXT_PROFILE_USER_PROMPT', direct_profile_user_prompt
            )
        else:
            os.environ['DIRECT_TEXT_PROFILE_USER_PROMPT'] = direct_profile_user_prompt
        os.environ['SYSTEM_PROMPT_TO_USER'] = '0'

        output_mode = str(
            getattr(self, '_direct_text_output_mode', 'text') or 'text'
        ).strip().lower()
        if output_mode == 'refine':
            output_mode = 'refinement'
        if output_mode not in {
            'text', 'vision', 'image', 'video', 'audio', 'refinement'
        }:
            output_mode = 'text'
        os.environ['OUTPUT_MODE'] = output_mode
        os.environ['VISION_OCR_FIRST'] = '1' if output_mode == 'vision' else '0'
        os.environ['ENABLE_IMAGE_TRANSLATION'] = (
            '1' if output_mode in {'vision', 'image', 'video'} else '0'
        )
        os.environ['ENABLE_IMAGE_OUTPUT_MODE'] = (
            '1' if output_mode == 'image' else '0'
        )
        os.environ['ENABLE_VIDEO_OUTPUT_MODE'] = (
            '1' if output_mode == 'video' else '0'
        )
        os.environ['ENABLE_AUDIO_OUTPUT_MODE'] = (
            '1' if output_mode == 'audio' else '0'
        )
        os.environ['ENABLE_REFINEMENT_OUTPUT_MODE'] = (
            '1' if output_mode == 'refinement' else '0'
        )

        if getattr(self, '_direct_text_force_multipass_off', True):
            os.environ['MULTIPASS_MODE'] = '0'

        manual_glossary_path = str(
            getattr(self, '_direct_text_manual_glossary_path', '') or ''
        ).strip()
        use_manual_glossary = bool(
            getattr(self, '_direct_text_use_manual_glossary', False)
            and manual_glossary_path
            and os.path.isfile(manual_glossary_path)
        )
        if use_manual_glossary:
            os.environ['AUTO_GLOSSARY_MODE'] = 'off_no_automap'
            os.environ['ENABLE_AUTO_GLOSSARY'] = '0'
            os.environ['SINGLE_PASS_GLOSSARY_MODE'] = '0'
            os.environ['FUZZY_AUTO_MAPPING'] = '0'
            os.environ['APPEND_GLOSSARY'] = '1'
            os.environ['MANUAL_GLOSSARY'] = manual_glossary_path
            os.environ['DEFER_GLOSSARY_APPEND'] = '0'
        elif getattr(self, '_direct_text_force_no_glossary', True):
            os.environ['AUTO_GLOSSARY_MODE'] = 'no_glossary'
            os.environ['ENABLE_AUTO_GLOSSARY'] = '0'
            os.environ['SINGLE_PASS_GLOSSARY_MODE'] = '0'
            os.environ['FUZZY_AUTO_MAPPING'] = '0'
            os.environ['APPEND_GLOSSARY'] = '0'
            os.environ['MANUAL_GLOSSARY'] = ''
            os.environ['DEFER_GLOSSARY_APPEND'] = '0'

        if getattr(self, '_direct_text_skip_thinking', False):
            # Match the Manga custom-API disable-thinking override, and cover
            # GPT/OpenAI-compatible routes as well.
            os.environ['ENABLE_ANTHROPIC_THINKING'] = '0'
            os.environ['ANTHROPIC_THINKING_BUDGET'] = '0'
            os.environ['ANTHROPIC_FORCE_ADAPTIVE'] = '0'
            os.environ['ENABLE_GEMINI_THINKING'] = '0'
            os.environ['ENABLE_DEEPSEEK_THINKING'] = '0'
            os.environ['ENABLE_GPT_THINKING'] = '0'
            os.environ['GPT_REASONING_TOKENS'] = ''
            os.environ['GPT_EFFORT'] = 'none'
            os.environ['PASS_THINKING_TO_OPENAI_COMPATIBLE'] = '0'
            os.environ['GEMINI_THINKING_LEVEL'] = 'minimal'
            os.environ.pop('THINKING_BUDGET', None)
            os.environ['STREAM_THINKING_LOGS'] = '0'
            os.environ['AUTHND_STREAM_THINKING_LOGS'] = '0'
            os.environ['ENABLE_THOUGHTS'] = '0'

    def _format_translation_anti_duplicate_settings(self, env_vars=None):
        """Return the translation anti-duplicate startup log line, or empty if disabled."""
        env = env_vars or os.environ
        try:
            enabled = str(env.get('ENABLE_ANTI_DUPLICATE', '0')).strip() == '1'
        except Exception:
            enabled = False
        if not enabled:
            return ''
        top_p = f"{float(env.get('TOP_P', '1.0')):g}"
        min_p = str(env.get('MIN_P', '0.0'))
        top_k = str(env.get('TOP_K', '0'))
        freq = str(env.get('FREQUENCY_PENALTY', '0.0'))
        pres = str(env.get('PRESENCE_PENALTY', '0.0'))
        rep = str(env.get('REPETITION_PENALTY', '1.0'))
        return (
            f"🎯 Anti-duplicate enabled for translation "
            f"(top_p={top_p}, min_p={min_p}, top_k={top_k}, "
            f"freq_penalty={freq}, presence_penalty={pres}, repetition_penalty={rep})"
        )

    def _log_translation_anti_duplicate_settings(self, env_vars=None):
        """Log translation anti-duplicate settings once per GUI translation run."""
        if getattr(self, '_translation_anti_duplicate_logged', False):
            return
        message = self._format_translation_anti_duplicate_settings(env_vars)
        if not message:
            return
        self.append_log(message)
        self._translation_anti_duplicate_logged = True
        try:
            os.environ['TRANSLATION_ANTI_DUPLICATE_LOGGED'] = '1'
        except Exception:
            pass

    def _resolve_glossary_for_env(self, file_path: str) -> str:
        """Return the glossary path to use for a given input file.

        Priority:
        1) Per-EPUB mapping (manual_glossary_map) — used when multiple EPUBs are loaded
        2) Global manual_glossary_path — used for single-EPUB or manual load
        3) Empty string — no glossary
        """
        try:
            if self._current_auto_glossary_mode() == 'no_glossary':
                return ''
        except Exception:
            pass

        try:
            mgm = getattr(self, 'manual_glossary_map', None)
            if isinstance(mgm, dict) and mgm and file_path:
                key = os.path.normpath(os.path.abspath(file_path))
                gp = mgm.get(file_path) or mgm.get(key) or mgm.get(os.path.normpath(file_path))
                if gp and os.path.exists(gp):
                    return gp
        except Exception:
            pass

        try:
            if hasattr(self, 'manual_glossary_path') and self.manual_glossary_path:
                return self.manual_glossary_path
        except Exception:
            pass

        return ''

    def _get_environment_variables(self, epub_path, api_key):
        """Get all environment variables for translation/glossary"""

        # Get Google Cloud project ID if using Vertex AI
        google_cloud_project = ''
        model = self.model_var
        if '@' in model or model.startswith('vertex/'):
            google_creds = self.config.get('google_cloud_credentials')
            if google_creds and os.path.exists(google_creds):
                try:
                    with open(google_creds, 'r') as f:
                        creds_data = json.load(f)
                        google_cloud_project = creds_data.get('project_id', '')
                except:
                    pass
                    
        output_mode = self._active_translation_output_mode()

        # Handle extraction mode - check which variables exist
        if hasattr(self, 'text_extraction_method_var'):
            # New cleaner UI variables
            extraction_method = self.text_extraction_method_var
            filtering_level = self.file_filtering_level_var
            
            if extraction_method == 'enhanced':
                extraction_mode = 'enhanced'
                enhanced_filtering = filtering_level
            else:
                extraction_mode = filtering_level
                enhanced_filtering = 'smart'  # default
        else:
            # Old UI variables
            extraction_mode = self.extraction_mode_var
            extraction_method = 'enhanced' if extraction_mode == 'enhanced' else 'standard'
            if extraction_mode == 'enhanced':
                enhanced_filtering = getattr(self, 'enhanced_filtering_var', 'smart')
            else:
                enhanced_filtering = 'smart'

        if output_mode == 'vision':
            extraction_method = 'enhanced'
            extraction_mode = 'enhanced'
            enhanced_filtering = filtering_level if hasattr(self, 'file_filtering_level_var') else getattr(self, 'enhanced_filtering_var', 'smart')
                    
        # Ensure multi-key env toggles are set early for the main translation path as well
        try:
            if self.config.get('use_multi_api_keys', False):
                os.environ['USE_MULTI_KEYS'] = '1'
            else:
                os.environ['USE_MULTI_KEYS'] = '0'
            if self.config.get('use_fallback_keys', False):
                os.environ['USE_FALLBACK_KEYS'] = '1'
            else:
                os.environ['USE_FALLBACK_KEYS'] = '0'
            os.environ['FALLBACK_KEY_SHUFFLE'] = '1' if self.config.get('fallback_key_shuffle', False) else '0'
            if self.config.get('use_glossary_keys', False):
                os.environ['USE_GLOSSARY_KEYS'] = '1'
            else:
                os.environ['USE_GLOSSARY_KEYS'] = '0'
            os.environ['USE_GLOSSARY_REFINEMENT_KEYS'] = '1' if self.config.get('use_glossary_refinement_keys', False) else '0'
            os.environ['GLOSSARY_REFINEMENT_API_KEYS'] = json.dumps(self.config.get('glossary_refinement_keys', []))
            os.environ['USE_METADATA_KEYS'] = '1' if self.config.get('use_metadata_keys', False) else '0'
            os.environ['METADATA_API_KEYS'] = json.dumps(self.config.get('metadata_keys', []))
            if self.config.get('use_qa_scan_keys', False):
                os.environ['USE_VISION_KEYS'] = '1'
                os.environ['USE_QA_SCAN_KEYS'] = '1'
            else:
                os.environ['USE_VISION_KEYS'] = '0'
                os.environ['USE_QA_SCAN_KEYS'] = '0'
            os.environ['VISION_API_KEYS'] = json.dumps(self.config.get('qa_scan_keys', []))
            os.environ['QA_SCAN_API_KEYS'] = os.environ['VISION_API_KEYS']
            os.environ['USE_AI_TRUNCATION_DETECTION_KEYS'] = '1' if self.config.get('use_ai_truncation_detection_keys', False) else '0'
            os.environ['AI_TRUNCATION_DETECTION_API_KEYS'] = json.dumps(self.config.get('ai_truncation_detection_keys', []))
            os.environ['USE_ROLLING_SUMMARY_KEYS'] = '1' if self.config.get('use_rolling_summary_keys', False) else '0'
            os.environ['ROLLING_SUMMARY_API_KEYS'] = json.dumps(self.config.get('rolling_summary_keys', []))
            os.environ['USE_TRUNCATION_RETRY_KEYS'] = '1' if self.config.get('use_truncation_retry_keys', False) else '0'
            os.environ['TRUNCATION_RETRY_API_KEYS'] = json.dumps(self.config.get('truncation_retry_keys', []))
        except Exception:
            pass

        # Configure multi-key list in memory (avoid Windows env var size limit for MULTI_API_KEYS)
        try:
            from unified_api_client import UnifiedClient
            if self.config.get('use_multi_api_keys', False) and self.config.get('multi_api_keys', []):
                UnifiedClient.set_in_memory_multi_keys(
                    self.config.get('multi_api_keys', []),
                    force_rotation=self.config.get('force_key_rotation', True),
                    rotation_frequency=self.config.get('rotation_frequency', 1),
                )
            else:
                UnifiedClient.clear_in_memory_multi_keys()
            
            # Configure glossary key pool in memory (mirrors multi-key setup)
            if self.config.get('use_glossary_keys', False) and self.config.get('glossary_keys', []):
                UnifiedClient.set_in_memory_glossary_keys(
                    self.config.get('glossary_keys', []),
                    force_rotation=self.config.get('force_key_rotation', True),
                    rotation_frequency=self.config.get('rotation_frequency', 1),
                )
            else:
                UnifiedClient.clear_in_memory_glossary_keys()
            if self.config.get('use_glossary_refinement_keys', False) and self.config.get('glossary_refinement_keys', []):
                UnifiedClient.set_in_memory_glossary_refinement_keys(
                    self.config.get('glossary_refinement_keys', []),
                    force_rotation=self.config.get('force_key_rotation', True),
                    rotation_frequency=self.config.get('rotation_frequency', 1),
                )
            else:
                UnifiedClient.clear_in_memory_glossary_refinement_keys()
            
            # Configure Vision key pool in memory (mirrors glossary-key setup)
            if self.config.get('use_qa_scan_keys', False) and self.config.get('qa_scan_keys', []):
                UnifiedClient.set_in_memory_vision_keys(
                    self.config.get('qa_scan_keys', []),
                    force_rotation=self.config.get('force_key_rotation', True),
                    rotation_frequency=self.config.get('rotation_frequency', 1),
                )
            else:
                UnifiedClient.clear_in_memory_vision_keys()

            # Configure rolling summary key pool in memory (used by context='summary').
            if self.config.get('use_rolling_summary_keys', False) and self.config.get('rolling_summary_keys', []):
                UnifiedClient.set_in_memory_rolling_summary_keys(
                    self.config.get('rolling_summary_keys', []),
                    force_rotation=self.config.get('force_key_rotation', True),
                    rotation_frequency=self.config.get('rotation_frequency', 1),
                )
            else:
                UnifiedClient.clear_in_memory_rolling_summary_keys()

            # Configure truncation retry key pool in memory (used by RETRY_TRUNCATED attempts)
            if self.config.get('use_truncation_retry_keys', False) and self.config.get('truncation_retry_keys', []):
                UnifiedClient.set_in_memory_truncation_retry_keys(
                    self.config.get('truncation_retry_keys', []),
                    force_rotation=self.config.get('force_key_rotation', True),
                    rotation_frequency=self.config.get('rotation_frequency', 1),
                )
            else:
                UnifiedClient.clear_in_memory_truncation_retry_keys()

            # Configure Image gen/edit key pool for image output and manga custom-image-edit requests.
            if self.config.get('use_inpainter_keys', False) and self.config.get('inpainter_keys', []):
                UnifiedClient.set_in_memory_inpainter_keys(
                    self.config.get('inpainter_keys', []),
                    force_rotation=self.config.get('force_key_rotation', True),
                    rotation_frequency=self.config.get('rotation_frequency', 1),
                )
            else:
                UnifiedClient.clear_in_memory_inpainter_keys()
        except Exception:
            pass

        # CRITICAL: Use current GUI value for max_output_tokens, not the initial value
        # This ensures user changes via the button are reflected in image translation
        current_max_tokens = self.max_output_tokens
        resolved_max_retry_tokens = self._resolve_max_retry_tokens(current_max_tokens)
        resolved_max_retries = self._resolve_max_retries()
        
        auto_inject_book_title = bool(getattr(self, 'auto_inject_book_title_var', self.config.get('auto_inject_book_title', False)))
        auto_glossary_mode = self._current_auto_glossary_mode()
        (
            glossary_request_merging_enabled,
            glossary_request_merge_count,
            glossary_enable_chapter_split,
        ) = self._current_glossary_request_env(
            force_balanced_request_merging=(output_mode == 'vision' and auto_glossary_mode == 'balanced')
        )
        output_override_for_env = os.environ.get('OUTPUT_DIRECTORY') or self.config.get('output_directory')
        if output_override_for_env:
            glossary_shared_dir = os.path.join(os.path.abspath(output_override_for_env), 'Glossary')
        else:
            glossary_shared_dir = os.path.join(_get_app_dir(), 'Glossary')
        try:
            from glossary_paths import migrate_all_legacy_glossary_files
            migrate_all_legacy_glossary_files(
                glossary_shared_dir,
                logger=lambda msg: self.append_log(msg) if hasattr(self, 'append_log') else None,
            )
        except Exception:
            pass

        def _bool_setting(value, default=False):
            if value is None:
                return bool(default)
            if hasattr(value, 'isChecked'):
                return bool(value.isChecked())
            if hasattr(value, 'get'):
                try:
                    return _bool_setting(value.get(), default)
                except Exception:
                    return bool(default)
            if isinstance(value, str):
                return value.strip().lower() in ('1', 'true', 'yes', 'on')
            return bool(value)

        def _positive_config_int(attr_name, config_key, default):
            try:
                value = getattr(self, attr_name, self.config.get(config_key, default))
                return str(max(1, int(value or default)))
            except (TypeError, ValueError):
                return str(default)

        def _bounded_config_int(attr_name, config_key, default, minimum=0, maximum=None):
            try:
                value = getattr(self, attr_name, self.config.get(config_key, default))
                numeric_value = int(float(value if value is not None else default))
                numeric_value = max(int(minimum), numeric_value)
                if maximum is not None:
                    numeric_value = min(int(maximum), numeric_value)
                return str(numeric_value)
            except (TypeError, ValueError):
                return str(default)

        def _bounded_config_float(attr_name, config_key, default, minimum=0.0, maximum=None):
            try:
                value = getattr(self, attr_name, self.config.get(config_key, default))
                numeric_value = float(value if value is not None else default)
                numeric_value = max(float(minimum), numeric_value)
                if maximum is not None:
                    numeric_value = min(float(maximum), numeric_value)
                return f"{numeric_value:g}"
            except (TypeError, ValueError):
                return f"{float(default):g}"

        def _bool_config_value(attr_name, config_key, default=False):
            value = getattr(self, attr_name, self.config.get(config_key, default))
            return _bool_setting(value, default)

        def _choice_config_value(attr_name, config_key, default, allowed):
            value = str(getattr(self, attr_name, self.config.get(config_key, default)) or default).strip().lower()
            return value if value in allowed else default

        def _authnd_effective_token_limits():
            if _bool_config_value('authnd_token_concurrency_auto_var', 'authnd_token_concurrency_auto', True):
                token_limit, subprocess_limit, _cores = _authnd_auto_token_limits()
                return str(token_limit), str(subprocess_limit), '1'
            return (
                _positive_config_int('authnd_token_concurrency_var', 'authnd_token_concurrency', 1),
                _positive_config_int('authnd_token_subprocess_concurrency_var', 'authnd_token_subprocess_concurrency', 1),
                '0',
            )

        authnd_token_limit, authnd_subprocess_limit, authnd_auto_flag = _authnd_effective_token_limits()

        def _explicit_blank_prompt_value(attr_name, config_key, default_attr):
            if hasattr(self, attr_name):
                value = getattr(self, attr_name)
                return str(value if value is not None else '')
            if config_key in self.config:
                value = self.config.get(config_key)
                return str(value if value is not None else '')
            return str(getattr(self, default_attr, '') or '')

