    def _reset_api_watchdog_progress(self, *, clear_stale_external_files: bool = True) -> None:
        """Reset the API watchdog (and the UI bar) immediately - thread-safe.

        This is used when the user clicks Stop so the progress bar doesn't remain stuck
        due to stale watchdog counts/files.
        """
        # 1) Reset watchdog counters in unified_api_client (best effort)
        try:
            import unified_api_client
            if hasattr(unified_api_client, '_api_watchdog_reset'):
                unified_api_client._api_watchdog_reset()
        except Exception:
            pass

        # 2) Clear cross-process watchdog files so aggregation can't keep the bar "busy".
        # On Stop clicks we intentionally delete ALL watchdog files (including .tmp), even if the
        # originating process is still alive, because the user explicitly requested a hard reset.
        if clear_stale_external_files:
            try:
                watchdog_dir = os.environ.get("GLOSSARION_WATCHDOG_DIR")
                if watchdog_dir and os.path.isdir(watchdog_dir):
                    import glob
                    for fp in glob.glob(os.path.join(watchdog_dir, "api_watchdog_*.json*")):
                        try:
                            os.remove(fp)
                        except Exception:
                            continue
            except Exception:
                pass

        # 3) Reset the UI bar immediately (timer will keep it consistent going forward)
        # Use QMetaObject.invokeMethod to ensure this runs on the main GUI thread
        def _do_reset_ui():
            try:
                if hasattr(self, 'api_watchdog_bar') and self.api_watchdog_bar:
                    self.api_watchdog_bar.setRange(0, 1)
                    self.api_watchdog_bar.setValue(0)
                    self.api_watchdog_bar.setFormat("API idle")
                    self.api_watchdog_bar.setToolTip("No API calls in flight")
            except Exception:
                pass
        
        # Check if we're on the main thread
        try:
            from PySide6.QtCore import QThread
            if QThread.currentThread() == QApplication.instance().thread():
                # We're on the main thread, safe to call directly
                _do_reset_ui()
            else:
                # We're on a worker thread, use invokeMethod with QueuedConnection
                QMetaObject.invokeMethod(self, "_reset_api_watchdog_ui", Qt.QueuedConnection)
        except Exception:
            # Fallback: try direct call (might fail if on wrong thread)
            try:
                _do_reset_ui()
            except Exception:
                pass
    
    @Slot()
    def _reset_api_watchdog_ui(self):
        """Slot for resetting watchdog UI - always runs on main thread"""
        try:
            if hasattr(self, 'api_watchdog_bar') and self.api_watchdog_bar:
                self.api_watchdog_bar.setRange(0, 1)
                self.api_watchdog_bar.setValue(0)
                self.api_watchdog_bar.setFormat("API idle")
                self.api_watchdog_bar.setToolTip("No API calls in flight")
        except Exception:
            pass

    def _create_watchdog_snapshot(self, context: str = None, model: str = None) -> None:
        """Create/update a watchdog state file immediately when a run starts."""
        try:
            watchdog_dir = os.environ.get("GLOSSARION_WATCHDOG_DIR")
            if not watchdog_dir:
                return
            os.makedirs(watchdog_dir, exist_ok=True)
            state = {}
            try:
                import unified_api_client
                if hasattr(unified_api_client, 'get_api_watchdog_state'):
                    state = unified_api_client.get_api_watchdog_state() or {}
            except Exception:
                state = {}
            if not isinstance(state, dict):
                state = {}
            now = time.time()
            if context:
                state["last_context"] = context
            if model:
                state["last_model"] = model
            state.setdefault("in_flight", 0)
            state.setdefault("peak_in_flight", 0)
            state.setdefault("last_change_ts", now)
            state["updated_ts"] = now
            state["pid"] = os.getpid()
            path = os.path.join(watchdog_dir, f"api_watchdog_{os.getpid()}.json")
            tmp_path = f"{path}.tmp"
            with open(tmp_path, "w", encoding="utf-8") as f:
                json.dump(state, f, ensure_ascii=False)
            os.replace(tmp_path, path)
        except Exception:
            pass

    def stop_translation(self):
        """Stop translation while preserving loaded file"""
        current_file = self.entry_epub.text() if hasattr(self, 'entry_epub') else None
        self.stop_requested = True
        if getattr(self, '_zip_conversion_active', False):
            self.append_log("⏹️ Stop requested — cancelling ZIP preparation...")
        
        # Check if graceful stop is enabled
        graceful_stop = getattr(self, 'graceful_stop_var', False)
        
        # Double-click detection for force stop during graceful stop
        # Check if we're already in graceful stop mode by looking at button text
        already_in_graceful_stop = False
        if hasattr(self, 'run_button_text'):
            button_text = self.run_button_text.text()
            already_in_graceful_stop = (button_text == "Finishing...")
        
        import time
        current_time = time.time()
        if not hasattr(self, '_stop_click_times'):
            self._stop_click_times = []
        
        # Add current click
        self._stop_click_times.append(current_time)
        # Remove clicks older than 1 second
        self._stop_click_times = [t for t in self._stop_click_times if current_time - t < 1.0]
        
        # Force stop on double-click (within 1s) regardless of current mode
        force_stop = len(self._stop_click_times) >= 2
        if force_stop:
            graceful_stop = False
            self.graceful_stop_active = False
            self._last_stop_was_graceful = False
            os.environ['TRANSLATION_CANCELLED'] = '1'
            os.environ['GRACEFUL_STOP'] = '0'
            os.environ['GRACEFUL_STOP_COMPLETED'] = '0'
            os.environ['WAIT_FOR_CHUNKS'] = '0'
            try:
                import unified_api_client
                if hasattr(unified_api_client, 'set_stop_flag'):
                    unified_api_client.set_stop_flag(True)
                if hasattr(unified_api_client, 'UnifiedClient'):
                    unified_api_client.UnifiedClient._global_cancelled = True
            except Exception:
                pass
            self._stop_click_times = []
            self.append_log("⚡ Double-click detected — forcing immediate stop!")

        # Only on FULL stop (non-graceful): clear watchdog state/files so the bar can't stick "busy".
        # For graceful stop we keep watchdog files intact so the UI can continue tracking in-flight calls.
        if not graceful_stop:
            try:
                self._reset_api_watchdog_progress(clear_stale_external_files=True)
            except Exception:
                pass
        # SPECIAL CASE: Batch mode with WAIT_FOR_CHUNKS=0.
        # In this case, we are not waiting for the full queue to finish, just the current in-flight chunks.
        # However, the overall progress bar (which tracks total chapters) might stick if we don't reset it
        # because the remaining chapters are simply skipped/cancelled.
        # For the API watchdog bar, we want it to drain naturally (showing the last few chunks finishing).
        elif os.environ.get('BATCH_TRANSLATION', '0') == '1' and os.environ.get('WAIT_FOR_CHUNKS', '0') == '0':
            # Force reset the MAIN progress bar to indicate stopped state, since we are cancelling future items.
            # We do NOT clear stale files here (keep False) because some chunks might still be genuinely in-flight
            # and we want to see them finish on the API watchdog bar.
            try:
                # Reset main UI progress bar directly if available
                if hasattr(self, 'progress_bar') and self.progress_bar:
                    self.progress_bar.setValue(0)
                    self.progress_bar.setFormat("Batch stopped")
                
                # Also reset the "Overall" status text in the log if possible?
                # Actually, simply setting the bar to 0 is the clearest signal.
            except Exception:
                pass
        # During graceful stop, keep button enabled to allow triple-click force stop
        
        # During graceful stop, keep button enabled to allow triple-click force stop
        # Otherwise disable it immediately
        if hasattr(self, 'run_button'):
            if graceful_stop:
                # Graceful stop mode - keep enabled to allow triple-click
                self.run_button.setEnabled(True)
            else:
                # Immediate stop or force stop - disable
                self.run_button.setEnabled(False)
            if hasattr(self, 'run_button_text'):
                if graceful_stop:
                    self.run_button_text.setText("Finishing...")
                else:
                    self.run_button_text.setText("Stopping...")
            self.run_button.setStyleSheet("QPushButton { background-color: #6c757d; border: none; }")
        
        # Set environment variable to suppress multi-key logging and signal hard abort.
        # During graceful stop, do NOT set TRANSLATION_CANCELLED — it would kill
        # in-flight AuthGem/AuthGPT SSE streams via _is_externally_stopped().
        if not graceful_stop:
            os.environ['TRANSLATION_CANCELLED'] = '1'
        
        # Set graceful stop mode in environment so API client knows to show logs
        os.environ['GRACEFUL_STOP'] = '1' if graceful_stop else '0'
        if not graceful_stop:
            os.environ['GRACEFUL_STOP_COMPLETED'] = '0'
        
        # Set wait for chunks mode - only applies when graceful stop is also enabled
        wait_for_chunks = getattr(self, 'wait_for_chunks_var', False) and graceful_stop
        os.environ['WAIT_FOR_CHUNKS'] = '1' if wait_for_chunks else '0'

        # Drop any queued API-delay reservations now. Stopped worker threads may
        # have already reserved future send slots, and keeping those slots makes
        # the next translation inherit a stacked "Sending API call in ..." timer.
        try:
            import unified_api_client
            if hasattr(unified_api_client, 'reset_api_call_stagger'):
                unified_api_client.reset_api_call_stagger()
            elif hasattr(unified_api_client, 'UnifiedClient') and hasattr(unified_api_client.UnifiedClient, 'reset_api_call_stagger'):
                unified_api_client.UnifiedClient.reset_api_call_stagger()
        except Exception:
            pass
        
        # Debug: Log the stop settings being applied
        print(f"🔧 Stop triggered: graceful_stop={graceful_stop}, wait_for_chunks_var={getattr(self, 'wait_for_chunks_var', False)}, WAIT_FOR_CHUNKS={os.environ.get('WAIT_FOR_CHUNKS')}")
        
        # Track graceful stop state - when True, stop_callback returns False to allow in-flight calls to complete
        self.graceful_stop_active = graceful_stop
        
        # Record stop timestamp so run_translation_thread can detect a rapid re-click
        # after the translation thread has already died (double-click force stop).
        self._last_stop_translation_ts = time.time()
        self._last_stop_was_graceful = graceful_stop
        
        self.stop_requested = True

        # Touch stop file for cross-process glossary workers (only for immediate stop)
        if not graceful_stop:
            try:
                stop_file = os.environ.get('GLOSSARY_STOP_FILE')
                if stop_file:
                    with open(stop_file, 'w', encoding='utf-8') as f:
                        f.write('stop')
            except Exception:
                pass
        
        # For graceful stop: DON'T abort in-flight API calls, let them finish
        # For immediate stop: abort everything aggressively
        if not graceful_stop:
            # Use the imported translation_stop_flag function from TransateKRtoEN
            # This was imported during lazy loading as: translation_stop_flag = TransateKRtoEN.set_stop_flag
            if 'translation_stop_flag' in globals() and translation_stop_flag:
                translation_stop_flag(True)
            
            # Also try to call it directly on the module if imported
            try:
                import TransateKRtoEN
                if hasattr(TransateKRtoEN, 'set_stop_flag'):
                    TransateKRtoEN.set_stop_flag(True)
            except: 
                pass
            
            try:
                import unified_api_client
                if hasattr(unified_api_client, 'set_stop_flag'):
                    unified_api_client.set_stop_flag(True)
                # If there's a global client instance, stop it too
                if hasattr(unified_api_client, 'global_stop_flag'):
                    unified_api_client.global_stop_flag = True
                
                # Set the _cancelled flag on the UnifiedClient class itself
                if hasattr(unified_api_client, 'UnifiedClient'):
                    unified_api_client.UnifiedClient._global_cancelled = True
            except Exception as e:
                print(f"Error setting stop flags: {e}")
            
            # ── SLOW PATH (background thread): close connections, kill procs ──
            def _stop_heavy_work():
                # Hard cancel: close active HTTP sessions to abort in-flight requests
                try:
                    import unified_api_client as _uac
                    if hasattr(_uac, 'hard_cancel_all'):
                        _uac.hard_cancel_all()
                    # Also reset watchdog counts so progress bar clears immediately
                    if hasattr(_uac, '_api_watchdog_reset'):
                        _uac._api_watchdog_reset()
                except Exception:
                    pass

                # Delete watchdog files again after stop flags/hard-cancel
                try:
                    self._reset_api_watchdog_progress(clear_stale_external_files=True)
                except Exception:
                    pass
                
                # Best-effort: terminate only known helper subprocesses we started.
                try:
                    import psutil
                    current_process = psutil.Process(os.getpid())
                    children = current_process.children(recursive=True)

                    # Collect inpainter worker PIDs to protect from termination.
                    _protected_pids = set()
                    try:
                        from manga_translator import MangaTranslator
                        if hasattr(MangaTranslator, '_inpaint_pool') and MangaTranslator._inpaint_pool:
                            for _key, _rec in MangaTranslator._inpaint_pool.items():
                                if _rec and 'spares' in _rec:
                                    for _inp in _rec['spares']:
                                        if _inp and getattr(_inp, '_mp_worker', None):
                                            try:
                                                _pid = _inp._mp_worker.pid
                                                if _pid:
                                                    _protected_pids.add(_pid)
                                            except Exception:
                                                pass
                    except Exception:
                        pass

                    def _cmdline_s(proc) -> str:
                        try:
                            cmd = proc.cmdline()
                            return " ".join(cmd) if isinstance(cmd, list) else str(cmd)
                        except Exception:
                            return ""

                    def _is_mp_internal(cmd_s: str) -> bool:
                        cs = (cmd_s or "")
                        return ("--multiprocessing-fork" in cs) or ("spawn_main" in cs) or ("multiprocessing.spawn" in cs)

                    # Only terminate explicit helper modes (safe).
                    processes_to_terminate = []
                    for child in children:
                        try:
                            if child.pid in _protected_pids:
                                continue
                            cmd_s = _cmdline_s(child)
                            if _is_mp_internal(cmd_s):
                                continue

                            # Known helper flags / scripts
                            #
                            # Browser-backed routes (AuthND / Gemini-Free) spawn a
                            # short-lived QtWebEngine helper subprocess to mint a
                            # captcha/search token. If a stop races the spawn, the
                            # helper (and its Chromium children) can linger holding
                            # PyInstaller _MEIPASS DLLs, which makes the bootloader's
                            # temp-dir cleanup fail with "Failed to remove temporary
                            # directory". Kill them here so they don't outlive Stop.
                            if ("--run-chapter-extraction" in cmd_s or "chapter_extraction_worker" in cmd_s
                                    or "--run-pdf-extraction" in cmd_s or "_pdf_extraction_worker" in cmd_s
                                    or "pdf_extraction_manager" in cmd_s or "pdf_extractor" in cmd_s
                                    or "--authnd-mint-token" in cmd_s or "--mint-token" in cmd_s
                                    or "--gemini-free-search" in cmd_s or "--search-helper" in cmd_s):
                                processes_to_terminate.append(child)
                        except (psutil.NoSuchProcess, psutil.AccessDenied):
                            continue

                    if processes_to_terminate:
                        for proc in processes_to_terminate:
                            try:
                                proc.terminate()
                            except (psutil.NoSuchProcess, psutil.AccessDenied):
                                pass

                        try:
                            gone, alive = psutil.wait_procs(processes_to_terminate, timeout=1)
                        except Exception:
                            alive = processes_to_terminate

                        for proc in alive:
                            try:
                                proc.kill()
                            except (psutil.NoSuchProcess, psutil.AccessDenied):
                                pass
                except Exception as e:
                    print(f"Error terminating helper child processes: {e}")
            
            import threading
            threading.Thread(target=_stop_heavy_work, daemon=True, name="translation-stop-cleanup").start()
        
        # Only poke the EPUB converter stop flag when the converter itself is
        # running. Translation/image stop should not wake or dirty converter
        # state just because the module is importable.
        try:
            epub_running = False
            epub_future = getattr(self, 'epub_future', None)
            if epub_future is not None and hasattr(epub_future, 'done'):
                epub_running = not epub_future.done()
            epub_thread = getattr(self, 'epub_thread', None)
            if epub_thread is not None and hasattr(epub_thread, 'is_alive'):
                epub_running = epub_running or epub_thread.is_alive()
            if epub_running:
                import epub_converter
                if hasattr(epub_converter, 'set_stop_flag'):
                    epub_converter.set_stop_flag(True)
        except Exception:
            pass
        
        # Save and encrypt config when stopping
        try:
            self.save_config(show_message=False)
        except:
            pass
        
        # Suppress HTTP logs during graceful stop
        if graceful_stop:
            try:
                import logging
                for logger_name in ['httpx', 'openai', 'google', 'google.api_core', 'google.generativeai', 'urllib3']:
                    logging.getLogger(logger_name).setLevel(logging.CRITICAL)
            except Exception:
                pass
        
        # Log message depends on stop mode
        if graceful_stop:
            try:
                wait_for_chunks = os.environ.get('WAIT_FOR_CHUNKS') == '1'
            except Exception:
                wait_for_chunks = False
            if wait_for_chunks:
                self.append_log("⏳ Graceful stop — waiting for in-flight API calls to complete...")
            else:
                self.append_log("⏳ Graceful stop — waiting for the current in-flight API call; queued work will not continue (WAIT_FOR_CHUNKS=0)")
        else:
            self.append_log("🛑 Force stop requested — aborting queued/in-flight API calls")

        # Do not schedule the glossary reset here.  Glossary and translation
        # share GRACEFUL_STOP, and the glossary-idle callback sees no glossary
        # worker during a translation, so it would clear the translation's
        # graceful-stop request after 500 ms while its API call was still live.
        # Don't call update_run_button() here - keep the "Stopping..." state until thread finishes.
        
        if current_file and hasattr(self, 'entry_epub'):
            QTimer.singleShot(100, lambda: self.preserve_file_path(current_file))

        # Schedule stop-flag reset once the worker has halted
        QTimer.singleShot(500, self._reset_stop_flags_if_idle)

    def preserve_file_path(self, file_path):
       """Helper to ensure file path stays in the entry field"""
       if hasattr(self, 'entry_epub') and file_path:
           try:
               selected = list(getattr(self, 'selected_files', []) or [])
               if len(selected) == 1 and selected[0] != file_path:
                   file_path = selected[0]
               elif len(selected) > 1 and file_path not in selected:
                   return
           except Exception:
               pass
           current = self.entry_epub.text()
           if not current or current != file_path:
               self.entry_epub.setText(file_path)

    @Slot(list)
    def _apply_selected_files_to_input_field(self, paths):
       """Refresh the visible input field after worker-side path changes."""
       try:
           files = [str(p) for p in (paths or []) if p]
           if not files or not hasattr(self, 'entry_epub'):
               return

           self.selected_files = files
           self.file_path = files[0]

           if len(files) == 1:
               self.entry_epub.setText(files[0])
           else:
               image_extensions = {'.png', '.jpg', '.jpeg', '.gif', '.bmp', '.webp'}
               images = [p for p in files if os.path.splitext(p)[1].lower() in image_extensions]
               epubs = [p for p in files if p.lower().endswith('.epub')]
               zips = [p for p in files if p.lower().endswith('.zip')]
               pdfs = [p for p in files if p.lower().endswith('.pdf')]
               txts = [p for p in files if p.lower().endswith('.txt')]
               jsons = [p for p in files if p.lower().endswith('.json')]
               csvs = [p for p in files if p.lower().endswith('.csv')]
               sdlxliffs = [p for p in files if p.lower().endswith('.sdlxliff')]

               summary_parts = []
               if epubs:
                   summary_parts.append(f"{len(epubs)} EPUB")
               if zips:
                   summary_parts.append(f"{len(zips)} ZIP")
               if pdfs:
                   summary_parts.append(f"{len(pdfs)} PDF")
               if txts:
                   summary_parts.append(f"{len(txts)} TXT")
               if jsons:
                   summary_parts.append(f"{len(jsons)} JSON")
               if csvs:
                   summary_parts.append(f"{len(csvs)} CSV")
               if sdlxliffs:
                   summary_parts.append(f"{len(sdlxliffs)} SDLXLIFF")
               if images:
                   summary_parts.append(f"{len(images)} images")

               summary = ', '.join(summary_parts) if summary_parts else 'mixed files'
               self.entry_epub.setText(f"{len(files)} files selected ({summary})")

           self._update_entry_epub_tooltip()
       except Exception:
           pass
    
    def _trigger_qa_scan_on_main_thread(self):
        """Handler called on main thread to trigger QA scan"""
        try:
            mode = self._get_scan_phase_mode()
            # Call run_qa_scan directly on the main thread with correct parameters
            self.run_qa_scan(mode_override=mode, non_interactive=True)
        except Exception as e:
            self.append_log(f"❌ Failed to start QA scan: {e}")
            import traceback
            self.append_log(traceback.format_exc())
    
    def _refresh_image_preview_on_main_thread(self):
        """Handler called on main thread to reload rendered image after parallel save"""
        try:
            print(f"[PARALLEL REFRESH] ✓ Handler called on main thread")
            
            # Find the manga translator instance
            if hasattr(self, 'manga_translator') and self.manga_translator:
                manga = self.manga_translator
                if hasattr(manga, 'image_preview_widget') and manga.image_preview_widget:
                    ipw = manga.image_preview_widget
                    if hasattr(ipw, 'current_image_path') and ipw.current_image_path:
                        print(f"[PARALLEL REFRESH] Reloading image: {ipw.current_image_path}")
                        ipw.load_image(
                            ipw.current_image_path,
                            preserve_rectangles=True,
                            preserve_text_overlays=True
                        )
                        print(f"[PARALLEL REFRESH] ✓ Image preview refreshed successfully")
                    else:
                        print(f"[PARALLEL REFRESH] No current_image_path available")
                else:
                    print(f"[PARALLEL REFRESH] No image_preview_widget found")
            else:
                print(f"[PARALLEL REFRESH] No manga_translator instance found")
        except Exception as e:
            print(f"[PARALLEL REFRESH] Failed: {e}")
            import traceback
            traceback.print_exc()

    def stop_glossary_extraction(self):
        """Stop glossary extraction specifically"""
        # Check if graceful stop is enabled
        graceful_stop = getattr(self, 'graceful_stop_var', False)
        
        # Double-click detection for force stop during graceful stop
        # Check if we're already in graceful stop mode by looking at button text
        already_in_graceful_stop = False
        if hasattr(self, 'glossary_text_label'):
            button_text = self.glossary_text_label.text()
            already_in_graceful_stop = (button_text == "Finishing...")
        
        import time
        current_time = time.time()
        if not hasattr(self, '_glossary_stop_click_times'):
            self._glossary_stop_click_times = []
        
        # Add current click
        self._glossary_stop_click_times.append(current_time)
        # Remove clicks older than 1 second
        self._glossary_stop_click_times = [t for t in self._glossary_stop_click_times if current_time - t < 1.0]
        
        # If 2+ clicks within 1 second AND we're in graceful stop mode, force immediate stop
        if len(self._glossary_stop_click_times) >= 2 and already_in_graceful_stop:
            self.append_log("⚡ Double-click detected — forcing immediate stop!")
            graceful_stop = False  # Override to force immediate stop
            self._glossary_stop_click_times = []  # Reset click counter
        
        # During graceful stop, keep button enabled to allow double-click force stop
        # Otherwise disable it immediately
        if hasattr(self, 'glossary_button'):
            if graceful_stop:
                # Graceful stop mode - keep enabled to allow double-click
                self.glossary_button.setEnabled(True)
            else:
                # Immediate stop or force stop - disable
                self.glossary_button.setEnabled(False)
            # Update text label instead of button text
            if hasattr(self, 'glossary_text_label'):
                if graceful_stop:
                    self.glossary_text_label.setText("Finishing...")
                else:
                    self.glossary_text_label.setText("Stopping...")
            self.glossary_button.setStyleSheet("""
                QPushButton {
                    background-color: #6c757d;
                    color: white;
                    border: 1px solid transparent;
                    border-radius: 0px;
                    padding: 6px;
                }
                QPushButton:hover {
                    border-color: #7bb3e0;
                    background-color: #6c757d;
                }
                QPushButton:disabled {
                    background-color: #555555;
                    color: #888888;
                    border-color: #555555;
                }
            """)
        
        # Set graceful stop mode in environment so API client knows to show logs
        os.environ['GRACEFUL_STOP'] = '1' if graceful_stop else '0'
        
        # Suppress HTTP logs during graceful stop
        if graceful_stop:
            try:
                import logging
                for logger_name in ['httpx', 'openai', 'google', 'google.api_core', 'google.generativeai', 'urllib3']:
                    logging.getLogger(logger_name).setLevel(logging.CRITICAL)
            except Exception:
                pass
        
        self.stop_requested = True
        
        # For graceful stop: DON'T abort in-flight API calls, let them finish
        # For immediate stop: abort everything aggressively
        if not graceful_stop:
            # Keep the extractor's hard-stop detection in sync with the other
            # translation stop path. Progress restoration uses this signal to
            # distinguish cancellation from an ordinary API failure.
            os.environ['TRANSLATION_CANCELLED'] = '1'
            os.environ['GRACEFUL_STOP_COMPLETED'] = '0'

            # ── FAST PATH (main thread): set all boolean flags instantly ──
            if glossary_stop_flag:
                glossary_stop_flag(True)
            
            try:
                import extract_glossary_from_epub
                if hasattr(extract_glossary_from_epub, 'set_stop_flag'):
                    extract_glossary_from_epub.set_stop_flag(True)
            except:
                pass
            
            # Set cancel flags immediately so _is_stop_requested() returns True
            try:
                import unified_api_client
                if hasattr(unified_api_client, 'set_stop_flag'):
                    unified_api_client.set_stop_flag(True)
                if hasattr(unified_api_client, 'UnifiedClient'):
                    unified_api_client.UnifiedClient._global_cancelled = True
            except Exception:
                pass
            
            # ── SLOW PATH (background thread): close connections, kill procs ──
            stop_run_id = getattr(self, '_glossary_run_id', None) or os.environ.get('GLOSSARION_RUN_ID')

            def _stop_heavy_work():
                # This cleanup is asynchronous. If another glossary run has
                # already started, its lifecycle reset owns the provider now;
                # an old cleanup must not cancel that new run's stream.
                current_run_id = getattr(self, '_glossary_run_id', None) or os.environ.get('GLOSSARION_RUN_ID')
                if stop_run_id and current_run_id != stop_run_id:
                    return
                # Hard cancel: close active HTTP sessions to abort in-flight requests
                try:
                    import unified_api_client as _uac
                    if hasattr(_uac, 'hard_cancel_all'):
                        _uac.hard_cancel_all()
                except Exception:
                    pass
                
                # Best-effort: terminate only known helper subprocesses we started.
                try:
                    import psutil
                    current_process = psutil.Process(os.getpid())
                    children = current_process.children(recursive=True)

                    _protected_pids = set()
                    try:
                        from manga_translator import MangaTranslator
                        if hasattr(MangaTranslator, '_inpaint_pool') and MangaTranslator._inpaint_pool:
                            for _key, _rec in MangaTranslator._inpaint_pool.items():
                                if _rec and 'spares' in _rec:
                                    for _inp in _rec['spares']:
                                        if _inp and getattr(_inp, '_mp_worker', None):
                                            try:
                                                _pid = _inp._mp_worker.pid
                                                if _pid:
                                                    _protected_pids.add(_pid)
                                            except Exception:
                                                pass
                    except Exception:
                        pass

                    def _cmdline_s(proc) -> str:
                        try:
                            cmd = proc.cmdline()
                            return " ".join(cmd) if isinstance(cmd, list) else str(cmd)
                        except Exception:
                            return ""

                    def _is_mp_internal(cmd_s: str) -> bool:
                        cs = (cmd_s or "")
                        return ("--multiprocessing-fork" in cs) or ("spawn_main" in cs) or ("multiprocessing.spawn" in cs)

                    processes_to_terminate = []
                    for child in children:
                        try:
                            if child.pid in _protected_pids:
                                continue
                            cmd_s = _cmdline_s(child)
                            if _is_mp_internal(cmd_s):
                                continue
                            if ("--run-chapter-extraction" in cmd_s or "chapter_extraction_worker" in cmd_s
                                    or "--run-pdf-extraction" in cmd_s or "_pdf_extraction_worker" in cmd_s
                                    or "pdf_extraction_manager" in cmd_s or "pdf_extractor" in cmd_s):
                                processes_to_terminate.append(child)
                        except (psutil.NoSuchProcess, psutil.AccessDenied):
                            continue

                    if processes_to_terminate:
                        for proc in processes_to_terminate:
                            try:
                                proc.terminate()
                            except (psutil.NoSuchProcess, psutil.AccessDenied):
                                pass

                        try:
                            gone, alive = psutil.wait_procs(processes_to_terminate, timeout=1)
                        except Exception:
                            alive = processes_to_terminate
                        for proc in alive:
                            try:
                                proc.kill()
                            except (psutil.NoSuchProcess, psutil.AccessDenied):
                                pass
                except Exception as e:
                    print(f"Error terminating helper child processes: {e}")

                # Touch stop file for GlossaryManager subprocesses
                try:
                    stop_file = os.environ.get('GLOSSARY_STOP_FILE')
                    if stop_file:
                        with open(stop_file, 'w', encoding='utf-8') as f:
                            f.write('stop')
                except Exception:
                    pass
            
            import threading
            threading.Thread(target=_stop_heavy_work, daemon=True, name="glossary-stop-cleanup").start()
        
        # Log message depends on stop mode
        if graceful_stop:
            try:
                wait_for_chunks = os.environ.get('WAIT_FOR_CHUNKS') == '1'
            except Exception:
                wait_for_chunks = False
            if wait_for_chunks:
                self.append_log("⏳ Graceful stop — waiting for in-flight API calls to complete...")
            else:
                self.append_log("🛑 Stop requested — cancelling glossary API calls (WAIT_FOR_CHUNKS=0)")
        else:
            self.append_log("❌ Glossary extraction stop requested.")
        # Keep polling until the worker has actually exited, then clear every
        # extractor/client/proxy stop source. A one-shot check while the worker
        # is still alive leaves cancellation state behind for the next run.
        QTimer.singleShot(500, self._reset_glossary_stop_flags_if_idle)
        # Don't call update_run_button() here - keep the "Stopping..." state until thread finishes


