                    ('GLOSSARY_LOGIT_BIAS_ENABLED', '1' if self.config.get('glossary_logit_bias_enabled', False) else '0'),
                    ('GLOSSARY_LOGIT_BIAS_STRENGTH', str(self.config.get('glossary_logit_bias_strength', -0.5))),
